def _sport_match(rec_sport, want):
    """[종목 분리] 레코드 sport 와 요청 sport 매칭. 레거시(None/'')는 horse 로 간주
    (triple_store 초기엔 일본경마만 존재). want 없으면 전부 통과.
    'horse' 요청은 경마(horse)만 — 경륜(cycle)·경정(boat)·바이크(bike)는 절대 매칭 안 됨."""
    if not want:
        return True
    return (rec_sport or "horse") == want


# 출마표2 전적 저장소 (raceKey → {horses:[{no,name,jockey,recent,weight}], t})
STARTERS_STORE = os.path.join(os.path.dirname(__file__), "starters_store.json")


def _starters_load():
    try:
        with open(STARTERS_STORE, encoding="utf-8") as f:
            return json.load(f)
    except Exception:
        return {}


def _starters_save(db):
    with open(STARTERS_STORE, "w", encoding="utf-8") as f:
        json.dump(db, f, ensure_ascii=False)


def _horse_has_form(h):
    """이 마필 항목이 실제 전적(착순/전적점수)을 담고 있는가."""
    if h.get("recent") or h.get("recentPlacings"):
        return True
    return (h.get("formScore") is not None) or (h.get("totalScore") is not None)


def _rec_form_count(rec):
    """레코드 안에서 전적이 채워진 마필 수."""
    return sum(1 for h in ((rec or {}).get("horses") or []) if _horse_has_form(h))


def _sanitize_starters(horses):
    """출마표2/DebaTable 파서 오탐(오즈표·전체목록 스크레이핑으로 수백 행이 딸려오는 경우) 방어.
    - 마번(no) 1~18 범위만 유효 · 마번 기준 중복 제거(전적 있는 항목 우선 보존)
    - 한 경주 출전마는 최대 18두이므로 334행 같은 쓰레기 입력을 정상 규모로 축소한다.
    반환: 정제된 리스트(마번 오름차순)."""
    by_no = {}
    for h in horses or []:
        try:
            no = int(h.get("no"))
        except (TypeError, ValueError):
            continue
        if no < 1 or no > 18:
            continue
        prev = by_no.get(no)
        if prev is None or (_horse_has_form(h) and not _horse_has_form(prev)):
            by_no[no] = h
    return [by_no[k] for k in sorted(by_no)]


def _form_from_starters(rk, drops, sport=None, valid_nos=None):
    """저장된 전적으로 마필 점수·등급 계산. 배당 급락마는 이상감지 상향 반영.
    - 일본(출마표2): recent 착순으로 점수 재계산
    - 한국(PDF): 프론트에서 이미 계산한 formScore/totalScore를 그대로 사용(마명·기수 한글 유지).
    - 경륜/경정/바이크(6명 종목): 한국경마(source=korea) 전적은 오매칭이므로 무시(전적없음이 정상).
      경륜 전적은 oddspark 출마표 분석(source=keirin)으로만 채운다.
    - valid_nos(현재 배당에 등장하는 마번 집합) 지정 시: 이전 경주 잔존마(배당 없는 마번)를 자동 제외."""
    rec = _starters_load().get(rk)
    if not rec or not rec.get("horses"):
        return None
    # [오매칭 차단] 6명 종목(경륜·경정·바이크)에 한국경마 전적이 raceKey 충돌로 들어간 경우 사용 금지.
    if sport in ("cycle", "boat", "bike") and rec.get("source") == "korea":
        return None
    anomaly_by_no = {}
    for d in drops or []:
        if d.get("pct", 0) < 0:  # 배당 하락(자금유입)
            for h in d["combo"]:
                anomaly_by_no.setdefault(int(h), {
                    "signalScore": min(100, 50 + int(abs(d["pct"]))),
                    "drop": abs(d["pct"]) / 100.0})
    raw = rec["horses"]
    # [잔존마 필터·1번] 현재 수집된 배당에 실제 등장하는 마번만 사용 → 이전 경주 잔존마(배당 없는 마번) 자동 제외.
    #   배당 매칭 말이 하나라도 있을 때만 적용(전무하면 마명 기반 종목 등 오검출 방지로 필터 보류).
    if valid_nos:
        def _hno(h):
            try:
                return int(h.get("no"))
            except (TypeError, ValueError):
                return None
        filtered = [h for h in raw if _hno(h) in valid_nos]
        if filtered:
            if len(filtered) != len(raw):
                dropped = sorted({_hno(h) for h in raw if _hno(h) is not None and _hno(h) not in valid_nos})
                print(f"[잔존마 필터] {rk}: 전적 {len(raw)}두 → 배당 출전마 {len(filtered)}두 (배당 없는 마번 제외: {dropped})")
            raw = filtered
    # [한국경마] 사전 계산된 전적점수가 있으면 그대로 통과(PDF Vision 한글 데이터)
    prescored = any(h.get("formScore") is not None or h.get("totalScore") is not None for h in raw)
    if rec.get("source") == "korea" or prescored:
        kra_hist = _kra_load_history()   # [전적→부진마 학습 연결] 마명으로 KRA 실전적 백필
        scored = []
        for h in raw:
            ts = h.get("totalScore")
            if ts is None:
                ts = h.get("formScore")
            no = h.get("no")
            an = anomaly_by_no.get(int(no)) if no is not None else None
            rp = (h.get("recent") or h.get("recentPlacings") or [])[:5]
            if not rp and h.get("name"):
                rp = _kra_recent_placings(h["name"], kra_hist)   # 저장 전적이 비면 KRA 실전적으로 채움
            # 전적점수가 없고(0/None) KRA 착순을 채웠으면 실전적 기반 점수로 보강(부진마·통합등급 반영)
            if (ts in (None, 0)) and rp:
                ts = base_form_score(rp)
            scored.append({
                "no": no, "name": h.get("name", ""), "jockey": h.get("jockey", ""),
                "recentPlacings": rp,
                "baseScore": round(ts or 0, 1), "courseBonus": 0, "jockeyBonus": 0,
                # [신규 근거 전달] 저장된 근거 문장(detail)·마체중·거리적성·기수복승률을 그대로 전달 → 패널 표시
                "totalScore": round(ts or 0, 1), "detail": h.get("detail") or [], "flags": [], "anomaly": an,
                "bodyWeight": h.get("bodyWeight"), "bodyWeightBonus": h.get("bodyWeightBonus"),
                "distAptitude": h.get("distAptitude"), "distAptitudeRate": h.get("distAptitudeRate"),
                "jockeyRate": h.get("jockeyRate"), "jockeyDistRate": h.get("jockeyDistRate"),
                # [보완1·경륜] 競走得点 절대등급 함께 전달(통합 사분위 grade와 별개)
                "competScore": h.get("competScore"), "absGrade": h.get("absGrade"),
                "styleType": h.get("styleType"),
                # [날씨·불량주로] 저장된 pastRaces(condition) 있으면 즉시 계산, 없으면 사전계산값 전달
                "badTrackRate": (bad_track_rate(h.get("pastRaces")) if h.get("pastRaces") else h.get("badTrackRate")),
                # [전적확장·신규] 기수교체·궁합·조교사·마번 표시용 필드 전달(패널 노출)
                "jockeyChangeBonus": h.get("jockeyChangeBonus"),
                "synergyGrade": h.get("synergyGrade"), "synergyRate": h.get("synergyRate"),
                "trainerName": h.get("trainerName"), "trainerRate": h.get("trainerRate"),
                "postPosDelta": h.get("postPosDelta"),
            })
        classify_grades(scored)
        scored.sort(key=lambda x: -x["totalScore"])
        return scored
    # [일본경마] 출마표2 착순으로 재계산 (착순이 비면 KRA 실전적으로 백필 — 한국 마명만 매칭)
    kra_hist = _kra_load_history()
    horses = []
    for h in raw:
        rp = h.get("recent") or []
        if not rp and h.get("name"):
            rp = _kra_recent_placings(h["name"], kra_hist)
        horses.append({"no": h.get("no"), "name": h.get("name", ""), "jockey": h.get("jockey", ""),
                       "recentPlacings": rp, "currentWeight": h.get("weight")})
    scored = compute_horse_scores({}, horses, None, anomaly_by_no)
    scored.sort(key=lambda x: -x["totalScore"])
    return scored


OPENING_ODDS = 100.0    # [배당판 미수집 방어] 복승/단승 이 값 이상 = opening/placeholder(실자금 거의 없음)


def _drop_placeholder_combos(combos, label=""):
    """[placeholder 배당 필터 (2026-07-19)] 발매 전 껍데기 배당(예 1054.4·9999.9)이 유력마·복병·
    크로스역배열·고배당 감지에 진짜 신호처럼 오인되던 문제(서울 2경주 복기) 차단.
    실배당은 소수 단위로 제각각 → '동일 값 100배+ 가 3조합 이상 반복'이면 껍데기로 판정,
    5000배+ 는 반복 무관 항상 껍데기. 원본은 건드리지 않고 걸러진 새 리스트 반환(무삭제·입력 필터만)."""
    try:
        vals = {}
        for c in (combos or []):
            o = c.get("odds")
            if o is not None:
                vals[o] = vals.get(o, 0) + 1
        bad = {o for o, n in vals.items() if (o >= 5000) or (o >= 100 and n >= 3)}
        if not bad:
            return combos
        out = [c for c in (combos or []) if c.get("odds") not in bad]
        if len(out) != len(combos or []):
            print(f"[placeholder 필터]{label} 껍데기 배당 {len(combos) - len(out)}조합 제외(값: "
                  f"{sorted(bad)[:3]}{'…' if len(bad) > 3 else ''})")
        return out
    except Exception:
        return combos
OPENING_DROP = -80.0    # opening 배당이 실배당으로 정착할 때의 기계적 급락(신호 아님)
STALE_ACTIVE_SEC = 1800  # [경주전환 잔존 방어] 활성 3종 배당이 이 시간(30분) 넘게 미갱신 → 끝난 경주로 간주(활성 캐시서 정리)
# [종목 오분석 근본수정] 한국 경마장명 → sport=horse·category=korea 강제 판정용(확장 KRA_TRACK_RE 와 동일 커버).
_KRA_TRACK_RE = re.compile(r"(서울|부산경남|부경|부산|제주|과천|렛츠런|한국마사회|경마공원|KRA)")
# [경륜 전용 지명] 경정장이 없는 '경륜 전용' 경마장명 → sport=cycle 강제(boat 오분석 차단).
#   ⚠ 경정장과 겹치는 지명(가와사키·다마노·구루메 등)은 제외 — 경륜 전용만 넣어 경정 오정정 방지.
#   세이부엔(西武園)이 KEIRIN_JO 미등록이라 boat 로 오분석되던 문제(2026-07-17 세이부엔 3경주).
_KEIRIN_ONLY_RE = re.compile(
    r"(세이부엔|西武園|야히코|弥彦|마에바시|前橋|우쓰노미야|宇都宮|케이오카쿠|京王閣|"
    r"이즈|伊豆|다치카와|立川|마쓰도|松戸|오다와라|小田原|기후|岐阜|시즈오카|静岡|경륜|競輪|keirin)")


def _is_opening_settle(po, pct):
    """opening/placeholder 배당(직전 100배+)이 실배당으로 정착하며 생기는 기계적 급락(≤-80%).
    배당판을 초반에 못 끌어와 캡처된 가짜 고배당 → 실배당 = 자금유입 신호가 아님(제외 대상)."""
    return po is not None and po >= OPENING_ODDS and pct is not None and pct <= OPENING_DROP


def _baseline_reset_needed(prev_q, cur_q, thresh=-90.0, min_ratio=0.6, min_combos=4):
    """[경주전환·초반미수집 방어] 직전 대비 공통 복승 조합의 다수(60%+)가:
    ①90%+ 급락(다른 경주 배당 잔존, 예: 147.4→5.7 시장 전반 붕괴), 또는
    ②opening 배당(100배+)에서 70%+ 정착(새 경주 배당판을 초반에 못 끌어와 생긴 가짜 고배당)
    → 기준값 재설정. 정상 경주는 일부만 급락(자금이 특정 말로 이동)하므로 시장 전반 동시 붕괴만 걸린다."""
    pm, cm = _odds_map_un(prev_q), _odds_map_un(cur_q)
    common = [k for k in cm if k in pm and pm[k] > 0 and cm[k] > 0]
    if len(common) < min_combos:
        return False
    big = sum(1 for k in common if (cm[k] - pm[k]) / pm[k] * 100 <= thresh)
    if (big / len(common)) >= min_ratio:
        return True
    # [초반 미수집] opening 배당(100배+)이 실배당으로 대거 정착(70%+) → 가짜 급락 방지
    opening = sum(1 for k in common
                  if pm[k] >= OPENING_ODDS and (cm[k] - pm[k]) / pm[k] * 100 <= -70.0)
    return (opening / len(common)) >= min_ratio


def _as_qmap(x):
    """복승 배당을 {정렬튜플: 최저배당} 맵으로 정규화 — 리스트([{combo,odds}])와
    저장 딕셔너리({'1+2': 배당}) 두 형식 모두 지원(스냅샷 저장형식 혼용 방어)."""
    if isinstance(x, dict):
        m = {}
        for k, v in x.items():
            try:
                kk = tuple(sorted(int(y) for y in str(k).split("+")))
                o = float(v)
            except (ValueError, TypeError):
                continue
            if o > 0 and (kk not in m or o < m[kk]):
                m[kk] = o
        return m
    return _odds_map_un(x)


def _next_race_surge(prev_q, cur_q, thresh=200.0, min_ratio=0.6, min_combos=4):
    """[2번 다음경주 혼입 방어] 직전 대비 공통 복승 조합의 다수(60%+)가 200%+ 급등하면
    현재 경주가 끝나고 다음 경주(초기 고배당) 배당이 섞인 것으로 판단 → 이후 데이터 차단.
    정상 경주는 배당이 내려가거나(자금유입) 소폭만 오르므로 대규모 동시 급등만 걸린다.
    (급락 방향은 _baseline_reset_needed 가 담당 — 이건 급등 방향 전용.)"""
    pm, cm = _as_qmap(prev_q), _as_qmap(cur_q)
    common = [k for k in cm if k in pm and pm[k] > 0 and cm[k] > 0]
    if len(common) < min_combos:
        return False
    big = sum(1 for k in common if (cm[k] - pm[k]) / pm[k] * 100 >= thresh)
    return (big / len(common)) >= min_ratio


def _triple_prune_stale(db, keep_rk=None, max_age=STALE_ACTIVE_SEC):
    """[경주전환 잔존 방어] 활성 3종 배당(triple_store)에서 max_age(기본 30분) 넘게
    갱신 안 된 경주를 제거한다. 경주별 히스토리 파일(data/odds_history)은 영구 보존되므로
    학습·복기·이상감지 누적에는 전혀 영향이 없다(활성 표시 캐시만 정리).
    keep_rk(방금 수집한 경주)는 나이와 무관하게 항상 유지. 반환: 제거된 raceKey 리스트.
    → max-t 폴백(triple_latest/current_race/analyze)이 '끝난 직전 경주'를 계속 끌어오던 문제 해소.
    한국·일본 동시 진행 등 최근(30분내) 갱신된 경주는 그대로 두어 병행 수집도 안전."""
    now = time.time()
    stale = [k for k, v in db.items()
             if k != keep_rk and (now - (v.get("t") or 0)) > max_age]
    for k in stale:
        db.pop(k, None)
    return stale


# [마번 범위 검증] 종목별 최대 마번(선수 번호). 이 값을 넘는 마번은 이전 경주 잔존·오검출로 간주해 제외.
#   경륜(cycle)=최대 9명 / 경정(boat)=6정 / 오토레이스(bike)=8차 / 경마(horse)=최대 18두(넉넉히 허용).
_SPORT_MAX_NO = {"cycle": 9, "boat": 6, "bike": 8, "horse": 18}


def _sport_max_no(sport):
    """종목별 유효 최대 마번 반환(모르는 종목은 경마 기준 18로 관대 처리)."""
    return _SPORT_MAX_NO.get((sport or "horse"), 18)


def _oddspark_covered_active(rk, within=200):
    """[자동전송 꼬임 방어] 이 raceKey를 서버가 oddspark로 방금(within초 내) 직접 수집 중인가?
    True면 확장(asyukk 사설 배당판·화면 수집)의 중복 전송은 불필요하고 오히려 유해 —
    ①탭 전환마다 다른 경주 배당이 서버를 덮어씀 ②사설≠공식 배당 혼입 ③유령 말번호 유입.
    → ingest 엔드포인트에서 확장 전송만 스킵(서버 oddspark 수집이 권위 소스). oddspark 미커버 경주는 False(확장 유지)."""
    now = time.time()
    try:
        m = _multi_store_load().get(rk)                  # multi_store = 항상 oddspark 서버 직접수집분
        if m and (now - (m.get("t") or 0)) <= within:
            return True
    except Exception:
        pass
    try:
        t = _triple_load().get(rk)                       # triple_store source에 oddspark 태그 + 최근 갱신
        if t and "oddspark" in (t.get("source") or "") and (now - (t.get("t") or 0)) <= within:
            return True
    except Exception:
        pass
    return False


# ══════════ [긴급수정 2026-07-18] 배당판 ↔ 분석 불일치 근본수정 ══════════
#   증상: 같은 경주가 "오비히로 2경주"(oddspark_bg)와 "2026-07-18 오비히로 2경주"(배당판) 등
#         2개 키로 갈려 저장 → 분석패널은 oddspark(말번호 밀림), 배당판은 정답을 표시해 서로 어긋남.
#   ① raceKey 통일  : 오늘 날짜 접두("YYYY-MM-DD ")를 제거해 무접두(=오늘) 규약으로 같은 경주를 한 키로 병합.
#   ② 사설 우선     : 최근 사설/배당판(비-oddspark) 수집이 있으면 oddspark 백업이 활성 배당을 덮어쓰지 않음.
#   ③ 말번호 매핑검증: 같은 배당값인데 조합(말번호)이 배당판과 다르면 '밀림'으로 판정·거부(로그 경고).
#   ⚠ 기존 기능 삭제 없음 — _oddspark_covered_active 등 기존 함수 보존, 판정 방향만 사설 우선으로 교정.
def _canon_rk(rk):
    """[① raceKey 통일] 오늘 날짜 접두("2026-07-18 오비히로 2경주")를 무접두("오비히로 2경주")로 통일.
    무접두 key = 오늘 규약(_analysis_log_path·_multi_key 등 기존 로직과 동일)이라 같은 경주가 한 키로 병합된다.
    과거 명시 날짜(어제 등)는 보존 → 지난 경주가 오늘로 섞이지 않음. 무접두/파싱실패는 원본 그대로."""
    s = (rk or "").strip()
    m = re.match(r"^(\d{4}-\d{2}-\d{2})\s+(.+)$", s)
    if m and m.group(1) == time.strftime("%Y-%m-%d"):
        return m.group(2).strip()
    return s


def _src_is_oddspark(src):
    """소스 문자열이 oddspark(백업 소스)인지. 사설(ks1)·keiba·kra_api·화면수집 등은 False(=배당판 권위)."""
    return "oddspark" in str(src or "")


def _combo_value_multiset(combos):
    """조합 목록 → 배당'값' 멀티셋(반올림). 말번호 무관하게 '같은 경주인지' 비교용."""
    from collections import Counter
    c = Counter()
    for it in (combos or []):
        if isinstance(it, dict):
            v = it.get("odds")
            if isinstance(v, (int, float)):
                c[round(float(v), 1)] += 1
    return c


def _combo_map(combos):
    """조합 목록 → {frozenset(말번호쌍): 배당값}. 말번호 매핑 비교용."""
    m = {}
    for it in (combos or []):
        if isinstance(it, dict):
            cc = it.get("combo"); v = it.get("odds")
            try:
                if cc and len(cc) == 2 and isinstance(v, (int, float)):
                    m[frozenset(int(x) for x in cc)] = round(float(v), 1)
            except (TypeError, ValueError):
                continue
    return m


def _oddspark_mapping_suspect(prev_q, new_q, min_pairs=6):
    """[③ 말번호 밀림 감지] 직전(배당판) 복승 조합 vs 새(oddspark) 복승 조합 비교.
    배당 '값'은 거의 같은데(=같은 경주) '말번호 매핑'이 절반 이상 다르면 밀림으로 판정.
    반환 True = oddspark 말번호가 배당판과 어긋남(밀림) → 덮어쓰기 거부 권장. 근거 부족(다른 경주·소량)=False."""
    pm, nm = _combo_map(prev_q), _combo_map(new_q)
    if len(pm) < min_pairs or len(nm) < min_pairs:
        return False
    pv, nv = _combo_value_multiset(prev_q), _combo_value_multiset(new_q)
    if sum((pv & nv).values()) < min_pairs:
        return False                               # 값 자체가 다름 = 다른 경주(밀림 아님)
    same = sum(1 for k, v in nm.items() if pm.get(k) == v)
    return (same / max(1, len(nm))) < 0.5          # 같은 말번호쌍 배당이 절반도 안 맞으면 밀림


@app.route("/api/odds/triple/ingest", methods=["POST"])
def triple_ingest():
    """확장 [전체 자동 수집]: {raceKey, quinella[], exacta[], trio[]} 저장 → {ok, counts}"""
    body = request.json or {}
    rk = _canon_rk((body.get("raceKey") or "").strip())   # [긴급수정 ①] 날짜접두 통일 → 같은 경주 병합
    if not rk:
        return jsonify({"error": "raceKey가 필요합니다."}), 400
    # [긴급수정 ② 사설 우선] 확장(사설 배당판·화면수집)은 사용자가 실제로 보고 베팅하는 화면 → 권위 소스.
    #   과거엔 oddspark 서버수집 중이면 확장을 스킵(oddspark 우선)했으나, oddspark 말번호 밀림으로 분석패널이
    #   배당판과 어긋나는 문제가 있어 '사설 우선'으로 전환한다. 확장 전송은 스킵하지 않고 그대로 저장하며,
    #   oddspark 는 _do_triple_ingest 의 소스우선 가드에서 '백업'으로만 반영(사설 데이터 신선하면 미덮어쓰기).
    #   ※ _oddspark_covered_active(기존 함수)는 삭제하지 않고 보존 — 판정 방향만 교정.
    _src = (body.get("source") or "")
    return jsonify(_do_triple_ingest(
        rk, body.get("quinella") or [], body.get("exacta") or [], body.get("trio") or [],
        _win_map_clean(body.get("win")), body.get("sport"), body.get("category"),
        body.get("source"), body.get("deadline"), scratched=body.get("scratched")))


_ARITY_MIN, _ARITY_MAX = 0.4, 1.5
# 서버가 직접 fetch 하는 신뢰 소스(탭 롤링과 무관 → 조합 수 검증 면제).
#   oddspark = 공식 HTML 직접 크롤링 · kra_api = 한국마사회 API. 이 경로엔 탭 오염이 원천적으로 없고,
#   수집 범위가 종류별로 달라(예: 한국 복승) 하한 검증을 걸면 정상 수집분까지 거부될 수 있다.
_ARITY_TRUSTED = ("oddspark", "kra_api")


def _combo_horse_count(combos):
    """조합 목록에 등장하는 서로 다른 마번 수(N)."""
    nos = set()
    for c in combos or []:
        if not isinstance(c, dict):
            continue
        for n in (c.get("combo") or []):
            try:
                nos.add(int(n))
            except (TypeError, ValueError):
                pass
    return len(nos)


def _arity_expect(kind, n):
    """N두 기준 기대 조합 수. 복승 nC2 · 쌍승 nP2 · 삼복승 nC3."""
    if n < 3:
        return 0
    if kind == "quinella":
        return n * (n - 1) // 2
    if kind == "exacta":
        return n * (n - 1)
    if kind == "trio":
        return n * (n - 1) * (n - 2) // 6
    return 0


def _arity_guard(kind, combos, label, source=None):
    """[오염방지 3·서버측 검증] 조합 수 정합성 검증 → 통과=원본 / 실패=[](그 종류만 저장 거부).

    확장 payload 에는 '이 배당이 복승인지 쌍승인지'를 나타내는 필드가 없다(어느 키에 담겼는가로만 종류를 표현).
    배당판 탭 전환이 실패하면 복승 매트릭스가 exacta 로 들어오는 등 종류가 뒤바뀐 채 저장될 수 있어,
    등장 마번 수 N 으로 기대 조합 수를 계산해 정상 범위(40%~150%) 밖이면 그 종류만 거부한다.
    ⚠ 삼복승(trio)은 하한을 적용하지 않는다 — 확장이 '유력마 축 클릭'으로 전체의 일부만 수집하는 설계라
       (축 1두면 전체의 ~25%) 하한을 걸면 정상 수집분까지 버려진다. 상한만 적용하고, trio 오염은
       확장측 [오염방지 1](축 클릭 실패 시 skip)이 원천 차단한다.
    """
    if not combos:
        return combos
    if source and any(t in str(source) for t in _ARITY_TRUSTED):
        return combos
    n = _combo_horse_count(combos)
    exp = _arity_expect(kind, n)
    if not exp:
        return combos
    ratio = len(combos) / exp
    too_many = ratio > _ARITY_MAX
    too_few = (kind != "trio") and (ratio < _ARITY_MIN)
    if too_many or too_few:
        print(f"⚠️ {label} 조합 수 이상 - 저장 거부 "
              f"({len(combos)}개 / 기대 {exp}개 · {n}두 · {ratio * 100:.0f}% · source={source or '확장'})")
        return []
    return combos


def _exacta_mirrors_quinella(q, x, source=None):
    """[오염방지 3-b·핵심] 쌍승이 사실상 복승 배당의 복사본인지 판정.

    조합 '수' 검증만으로는 최악의 오염(쌍승 탭 전환 실패 → 복승 매트릭스를 쌍승으로 전송)을 잡을 수 없다.
    복승 삼각 매트릭스(nC2=66)가 쌍승으로 들어오면 66/132 = 정확히 50% 라 40% 하한을 통과해 버린다.
    (복승 보드가 정사각이면 nP2=132 로 100% 가 되어 수량 검증은 아예 무의미해진다.)
    → 값으로 판정한다: 진짜 쌍승은 방향별로 배당이 다르고 복승보다 크지만, 복승을 긁어온 경우
      같은 말쌍의 쌍승 배당이 복승 배당과 동일해진다. 겹치는 말쌍의 90%+ 가 일치하면 오염으로 본다.
    """
    if not q or not x:
        return False
    if source and any(t in str(source) for t in _ARITY_TRUSTED):
        return False
    qmap = {}
    for c in q:
        if not isinstance(c, dict):
            continue
        cb = c.get("combo") or []
        if len(cb) == 2:
            try:
                qmap[(min(int(cb[0]), int(cb[1])), max(int(cb[0]), int(cb[1])))] = float(c.get("odds") or 0)
            except (TypeError, ValueError):
                pass
    if not qmap:
        return False
    total = same = 0
    for c in x:
        if not isinstance(c, dict):
            continue
        cb = c.get("combo") or []
        if len(cb) != 2:
            continue
        try:
            k = (min(int(cb[0]), int(cb[1])), max(int(cb[0]), int(cb[1])))
            xo = float(c.get("odds") or 0)
        except (TypeError, ValueError):
            continue
        qo = qmap.get(k)
        if qo is None or qo <= 0:
            continue
        total += 1
        if abs(xo - qo) <= max(0.05, qo * 0.01):   # 배당값이 실질 동일(반올림 오차 허용)
            same += 1
    if total < 5:
        return False
    return (same / total) >= 0.9


def _bettype_guard(kind, combos, label):
    """[보완2·서버측 대조] 조합이 스스로 밝힌 betType 과 담긴 키가 일치하는지 직접 대조.

    확장 v2.1.114+ 는 각 조합에 `betType`("quinella"|"exacta"|"trio")을 명시한다.
    탭 전환 실패로 종류가 뒤바뀌면 여기서 즉시 잡힌다(수량/미러 검증보다 확실·저렴).
    ⚠ 하위 호환: betType 이 없는 구버전 확장·oddspark·KRA 페이로드는 그대로 통과(무삭제).
    """
    if not combos:
        return combos
    tagged = [c for c in combos if isinstance(c, dict) and c.get("betType")]
    if not tagged:
        return combos          # 구버전/신뢰소스 → 대조 생략(기존 동작 유지)
    bad = [c for c in tagged if c.get("betType") != kind]
    if not bad:
        return combos
    got = sorted({str(c.get("betType")) for c in bad})
    print(f"⚠️ {label} betType 불일치 - 저장 거부 "
          f"(기대 '{kind}' · 수신 {got} · {len(bad)}/{len(tagged)}개)")
    return []


def _combo_max_no(*sources):
    """[종목 증거판정용] 배당 조합(복승·쌍승·삼복승)에 등장하는 최대 마번을 추출.
    입력 포맷 무관(리스트 [{combo,odds}]·딕셔너리 {'a+b':odds}·{'a-b':odds}·튜플키) 방어 —
    조합 표현을 문자열화해 정수 토큰만 스캔한다(마번 1~99만 유효로 간주)."""
    mx = 0
    for src in sources:
        if not src:
            continue
        try:
            if isinstance(src, dict):
                iterable = list(src.keys())
            elif isinstance(src, (list, tuple)):
                iterable = [(it.get("combo") if isinstance(it, dict) else it) for it in src]
            else:
                iterable = [src]
            for combo in iterable:
                for tok in re.findall(r"\d+", str(combo)):
                    n = int(tok)
                    if 1 <= n <= 99 and n > mx:
                        mx = n
        except Exception:
            continue
    return mx


def _do_triple_ingest(rk, q, x, tr, win, sport=None, category=None, source=None, deadline=None, scratched=None):
    """[코어] 3종 배당 스냅샷 저장 + 히스토리 누적 → 역배열·배당변화·이상감지 파이프라인 공용.
    확장(triple_ingest)과 oddspark 직접조회(keirin_odds)가 함께 사용."""
    rk = _canon_rk(rk)   # [긴급수정 ① raceKey 통일] 모든 수집 경로 공통 정규화(날짜접두 제거 → 같은 경주 1키 병합)
    # [종목 오분석 근본수정·서버측 강제] raceKey 에 한국 경마장(서울/부산/제주/부경/과천)이 있으면 무조건
    #   sport=horse·category=korea 로 정정. 확장이 경정/경륜으로 오분류해 보내도 서버가 최종 방어(부산 2경주 오분석 재발 차단).
    try:
        if _KRA_TRACK_RE.search(str(rk)):
            if (sport in (None, "boat", "cycle", "bike")) or (category in (None, "boat", "cycle", "bike")):
                if sport != "horse" or category != "korea":
                    print("[종목 정정] %s: 한국경마 raceKey → sport=horse·category=korea (기존 sport=%s·cat=%s)"
                          % (rk, sport, category))
                sport, category = "horse", "korea"
                # [수정3·한국 발주시각→타임스냅샷] 확장이 배당판에서 감지한 발주시각(deadline·ms)을 스케줄 postEpoch(초)로
                #   반영 → KRA API가 발주시각을 안 줘도 타임 스냅샷(T-7/T-5)이 한국경마에서도 작동(부산 2경주 스냅샷 부재 해결).
                try:
                    if deadline:
                        _korea_schedule_post_epoch(rk, float(deadline) / 1000.0)
                except Exception:
                    pass
    except Exception as _ke:
        print("[종목 정정] 실패(무시):", _ke)
    # [경륜 종목 강제·세이부엔 등] 경륜 전용 지명(경정장 없음) → sport=cycle 강제. 확장이 boat 로 오분류해 보내도 서버 최종 방어.
    #   한국경마 아니고(위에서 이미 처리), 종목이 미지정/boat/bike/horse 로 온 경우 정정(정상 cycle 은 그대로).
    #   [플립 원천 차단 (2026-07-19)] 조건에 "horse" 추가 — 새 ks1 배당판은 본문에 타 종목 메뉴·배너의
    #   경마장명이 섞여 확장이 경륜 경주(기후 2경주)를 sport=horse 로 전송 → oddspark 서버수집(cycle)과
    #   교대될 때마다 [종목 전환 완전 초기화]가 기준값 리셋+경륜 전적 삭제를 반복하고, 마감 직전 확장
    #   집중수집 시점부터 분석이 경마 스타일로 교체되던 문제. 경륜 전용 지명(기후·마쓰도·세이부엔 등)은
    #   horse 로 와도 무조건 cycle 로 정정(기존 조건 삭제 없음·확장만).
    try:
        if _KEIRIN_ONLY_RE.search(str(rk)) and not _KRA_TRACK_RE.search(str(rk)):
            if sport in (None, "horse", "boat", "bike") or category in (None, "japan_local", "boat", "bike"):
                if sport != "cycle":
                    print("[종목 정정] %s: 경륜 전용 지명 → sport=cycle (기존 sport=%s·cat=%s)" % (rk, sport, category))
                sport, category = "cycle", "cycle"
    except Exception as _ce:
        print("[종목 정정·경륜] 실패(무시):", _ce)
    # [종목 오분석·증거기반 근본수정] 배당 조합의 실제 마번으로 경정(boat) 오분류를 최종 차단.
    #   경정(競艇)은 정확히 6정(마번 1~6)만 존재 → 조합에 7번+ 마번이 있으면 경정이 물리적으로 불가능.
    #   확장이 asyukk 사설 배당판의 '경정' 네비 링크에 낚여 한국경마(부산 7~16두 등)를 boat 로 보내도,
    #   raceKey에 경마장명이 없어(위 이름기반 정정 미적용) 새던 케이스를 배당 실측으로 정정한다.
    #   ⚠ 조합에 7번+ 마번이 있을 때만 발동 → 정상 경정(1~6번만)은 절대 건드리지 않음(무회귀).
    try:
        if sport == "boat" or category == "boat":
            _mx = _combo_max_no(q, x, tr)
            if _mx > 6:                                          # 경정 불가 확정
                if _KRA_TRACK_RE.search(str(rk)):
                    _ns, _nc = "horse", "korea"                  # 한국 경마장명 → 한국경마
                elif _mx > 9:
                    _ns, _nc = "horse", (category if category not in (None, "boat") else "japan_local")  # 경륜(≤9)도 초과 → 경마
                elif _KEIRIN_ONLY_RE.search(str(rk)):
                    _ns, _nc = "cycle", "cycle"                  # 경륜 전용 지명 → 경륜
                else:
                    _ns, _nc = "cycle", "cycle"                  # 7~9두·근거부족: 경정만은 확실히 아님 → 경륜 추정
                print("[종목 정정·증거기반] %s: 조합 최대마번=%d → 경정(6정) 불가 → sport=%s·cat=%s (기존 boat)"
                      % (rk, _mx, _ns, _nc))
                sport, category = _ns, _nc
    except Exception as _be:
        print("[종목 정정·증거기반] 실패(무시):", _be)
    # [보완2] betType 직접 대조(가장 확실한 1차 관문) → 뒤바뀐 종류는 여기서 즉시 거부.
    q = _bettype_guard("quinella", q, "복승")
    x = _bettype_guard("exacta", x, "쌍승")
    tr = _bettype_guard("trio", tr, "삼복승")
    # [오염방지 3] 배당판 탭 롤링 실패로 종류가 뒤바뀐 데이터를 저장 전에 종류별로 거부(신뢰 소스는 면제).
    q = _arity_guard("quinella", q, "복승", source)
    x = _arity_guard("exacta", x, "쌍승", source)
    tr = _arity_guard("trio", tr, "삼복승", source)
    # [오염방지 3-b] 쌍승 = 복승 복사본이면 거부. 이 오염이 통과하면 쌍승역전 공식(_win_exacta_reversal)에
    #   가짜 역전 신호로 주입되므로, 수량 검증이 못 잡는 이 케이스를 값 비교로 확실히 차단한다.
    if _exacta_mirrors_quinella(q, x, source):
        print(f"⚠️ 쌍승 배당이 복승과 동일 - 저장 거부 (탭 전환 실패로 복승 화면을 쌍승으로 수집한 것으로 판단 · rk={rk})")
        x = []
    db = _triple_load()
    prev = db.get(rk) or {}
    now = time.time()
    # ══════════ [긴급수정 ②③ 사설 우선 + oddspark 말번호 밀림 방어] ══════════
    #   사설/배당판(비-oddspark)이 최근(≤200초) 이 경주를 수집했으면 oddspark 는 '백업' 위치 →
    #   활성 배당을 덮어쓰지 않는다(= 사용자가 실제 베팅하는 배당판과 분석패널을 항상 일치시킴).
    #   추가로 들어온 oddspark 조합이 배당판과 '같은 값·다른 말번호'(밀림)면 확실히 거부하고 경고를 남긴다.
    #   ⚠ 배당판이 오래됨(200초 초과·사용자 탭 종료)이면 가드가 풀려 oddspark 가 백업으로 정상 인계.
    if _src_is_oddspark(source) and prev:
        _prev_src = prev.get("source") or ""
        _prev_fresh = (now - (prev.get("t") or 0)) <= 200
        if _prev_src and (not _src_is_oddspark(_prev_src)) and _prev_fresh:
            _suspect = _oddspark_mapping_suspect(prev.get("quinella"), q)
            print("[사설 우선] %s: 최근 배당판(src=%s) 유지 → oddspark(%s) 백업 덮어쓰기 생략%s"
                  % (rk, _prev_src, source, " · ⚠️ 말번호 밀림 감지(oddspark 매핑 어긋남)" if _suspect else ""))
            return {"ok": True, "skipped": True, "raceKey": rk, "mappingSuspect": _suspect,
                    "reason": "사설/배당판 우선 — oddspark 백업 덮어쓰기 생략"}
    # 변동 추적용 히스토리(최근 12회) — 직전 대비 급락/순위/역전 계산에 사용
    prev_hist = prev.get("history") or []
    # [1·3번] 경주 전환 방어: 직전 배당 대비 다수 조합 95%+ 급락 = 다른 경주 잔존 → 기준값 재설정
    #   [실시간 분석 유지 버그수정] 확립된 baseline(4+스냅샷)은 배당 휴리스틱으로 초기화하지 않는다.
    #   초반(미확립·다른 경주 잔존 배당)만 즉시 초기화하고, 확립 후 경주 전환은 raceKey 변경으로 처리
    #   (확장이 경주 바뀌면 새 rk → 새 레코드로 자연히 fresh 시작). 변동성 큰 배당의 단발 블립으로
    #   분석이 '초반(기준값 재설정)'으로 되돌아가던 버그 제거.
    # [종목 전환 완전 초기화] 같은 raceKey에서 종목이 바뀌면(경마→경륜 등) 이전 종목 배당/전적은
    #   완전히 다른 경주이므로 확립 여부와 무관하게 강제 초기화(잔존 배당·잔존마 원천 차단).
    _prev_sport = prev.get("sport")
    _new_sport = sport or _prev_sport or "horse"
    sport_changed = bool(_prev_sport and _new_sport and _prev_sport != _new_sport)
    # [경주 전환 잔존 방어·시간 간격] 직전 수집 후 20분+ 경과 = 이전 경주 종료 → 새 경주(같은 rk 재사용·발주 지연)로
    #   간주해 확립 여부와 무관하게 강제 초기화(이전 급락/배당 완전 제거·이 수집 = 새 기준값). 오다와라 1R 발주지연 케이스 방어.
    _last_t = (prev_hist[-1].get("t") if prev_hist else None) or prev.get("t")
    stale_gap = bool(_last_t and (now - _last_t) > 1200)
    _established = len(prev_hist) >= 4
    baseline_reset = (sport_changed or stale_gap
                      or ((not _established) and bool(prev_hist and _baseline_reset_needed(prev_hist[-1].get("quinella"), q))))
    hist = [] if baseline_reset else list(prev_hist)   # 이전(다른 경주·다른 종목·오래된) 배당 완전 제거
    hist.append({"t": now, "quinella": q, "exacta": x, "trio": tr, "win": win})
    hist = hist[-12:]
    # [수정#3 경륜/경정] 종목 태그 저장(horse|cycle|boat|bike). 기본 horse(경마) → 기존 동작 불변.
    #   ⚠ 종목 전환 시엔 새 종목을 우선(이전 sport 상속 금지) → 경마→경륜 전환이 sport 상속으로 묻히지 않게.
    sport = _new_sport
    if sport_changed:
        # 이전 종목 전적(경마 11두 등)을 완전 제거 → 잔존마 추천 차단.
        #   같은 raceKey 아래 남은 '이전 종목' starters도 삭제(한국 PDF 사전분석분은 아침 일괄이라 보존).
        _sdb = _starters_load()
        _srec = _sdb.get(rk)
        if _srec and (_srec or {}).get("source") != "korea":
            _sdb.pop(rk, None)
            _starters_save(_sdb)
            print(f"[종목 전환] {rk}: 이전 종목 전적(source={_srec.get('source')}) 제거")
        _starters_prune(keep_rk=rk)   # 그 외 다른 경주 잔존 전적도 정리
    # [탭분리] 분석기 탭 라우팅용 카테고리(korea|japan_local|japan_central|boat|cycle|bike).
    category = (category or prev.get("category")
                or {"cycle": "cycle", "boat": "boat", "bike": "bike"}.get(sport, "japan_local"))
    db[rk] = {"quinella": q, "exacta": x, "trio": tr, "win": win, "history": hist,
              "source": source, "sport": sport, "category": category, "t": now,
              "scratched": sorted(set(int(s) for s in (scratched or []) if str(s).strip().lstrip("-").isdigit()))}
    # [경주전환 잔존 방어] 30분+ 미갱신된 '끝난 직전 경주'를 활성 캐시에서 정리(히스토리는 보존)
    #   → max-t 폴백이 직전 경주 배당을 계속 끌어오던 문제 차단.
    pruned = _triple_prune_stale(db, keep_rk=rk)
    _triple_save(db)
    # 배당 변동 히스토리 파일에 스냅샷 누적 (타임스탬프+발주전분+이상감지)
    try:
        _history_append(rk, q, x, deadline, win, baseline_reset=baseline_reset)
    except Exception as e:
        print("[히스토리] 기록 실패:", e)
    # [경륜 출마표 전적 자동 수집] 경륜 배당 수집(확장 asyukk 포함) 시 전적도 함께 → 통합등급 반영(raceKey에서 joCode 자동 감지·1회).
    if sport == "cycle":
        try:
            _kv, _kn = _area_num(rk)
            _kjo = _keirin_jo_from_venue(_kv)
            if _kjo and _kn:
                _keirin_autocollect_form(rk, _kjo, time.strftime("%Y%m%d"), _kn)
        except Exception as _ke:
            print("[경륜 전적·자동] ingest 훅 오류(무시):", _ke)
    counts = {"quinella": len(q), "exacta": len(x), "trio": len(tr), "win": len(win)}
    if sport_changed:
        print(f"[종목 전환] {rk}: {_prev_sport}→{_new_sport} → 배당·히스토리·전적 완전 초기화(잔존 데이터 제거)")
    elif stale_gap:
        print(f"[경주전환·시간간격] {rk}: 직전 수집 20분+ 경과 → 이전 경주 종료로 간주·기준값 재설정(급락 데이터 초기화)")
    elif baseline_reset:
        print(f"[경주전환 감지] {rk}: 비정상 변동폭(95%+ 다수) → 기준값 재설정(이전 배당 초기화)")
    if pruned:
        print(f"[활성정리] 끝난 경주 {len(pruned)}건 제거(히스토리 보존): {', '.join(pruned)}")
    print(f"[3종 수집] {rk}: {counts} (history {len(hist)}{' · 기준재설정' if baseline_reset else ''})")
    return {"ok": True, "counts": counts, "baselineReset": baseline_reset,
            "sportChanged": sport_changed, "pruned": pruned}


def _starters_prune(keep_rk=None):
    """[잔존마 방어·3번] starters_store(전적)에서 이전 경주 데이터 제거.
    keep_rk 주면 그 경주만 남기고 전부 삭제(새 경주 데이터만 유지), 없으면 전체 비움.
    한국 PDF 사전분석 전적(source=korea)은 아침 일괄 저장분이라 보존(경주별 재사용)."""
    sdb = _starters_load()
    if not sdb:
        return 0
    removed, kept = 0, {}
    for k, v in sdb.items():
        if k == keep_rk or (v or {}).get("source") == "korea":
            kept[k] = v            # 현재 경주 + 한국 PDF 사전분석분은 유지
        else:
            removed += 1
    _starters_save(kept)
    if removed:
        print(f"[잔존마 방어] starters 정리: {removed}건 제거(유지: {keep_rk or '없음'} + 한국PDF)")
    return removed


@app.route("/api/odds/triple/reset", methods=["POST"])
def triple_reset():
    """[🔄 새 경주 시작] 활성 3종 배당(triple_store)을 비워 새 경주로 전환.
    경주별 히스토리 파일(data/odds_history)은 그대로 보존(=[히스토리 보기]).
    body: {raceKey?, pruneStarters?} — raceKey 주면 그 경주만, 없으면 전체 활성 초기화.
    pruneStarters=true(기본): 이전 경주 전적(starters)도 함께 정리(잔존마 방지)."""
    body = request.json or {}
    rk = (body.get("raceKey") or "").strip()
    db = _triple_load()
    if rk:
        removed = 1 if db.pop(rk, None) is not None else 0
    else:
        removed = len(db)
        db = {}
    _triple_save(db)
    # [3번] 이전 경주 starters 정리(새 경주 raceKey만 유지 → 잔존마 원천 차단). 명시적으로 끄지 않는 한 수행.
    starters_removed = 0
    if body.get("pruneStarters", True):
        starters_removed = _starters_prune(keep_rk=rk or None)
    print(f"[새 경주] 활성 3종 초기화: {rk or '전체'} ({removed}건). 히스토리 파일은 보존.")
    return jsonify({"ok": True, "cleared": rk or "all", "removed": removed,
                    "startersRemoved": starters_removed})


@app.route("/api/starters/reset", methods=["POST"])
def starters_reset():
    """[잔존마 방어·3번] 경주 전환 시 이전 경주 전적(starters) 정리.
    body: {keepRaceKey?} — 주면 그 경주(+한국 PDF)만 유지, 없으면 한국 PDF 외 전부 삭제.
    triple_store(배당)는 건드리지 않음(전적만) → 방금 전환한 새 경주 배당은 보존."""
    keep = ((request.json or {}).get("keepRaceKey") or "").strip() or None
    removed = _starters_prune(keep_rk=keep)
    return jsonify({"ok": True, "startersRemoved": removed, "kept": keep or "korea만"})


# ══════════════ [경주 고정·서버측 raceKey 잠금] ══════════════
#   사용자가 경주를 고정하면 서버가 current_race/triple_latest에서 '항상 그 경주'를 반환한다.
#   → oddspark 자동수집이 다른 경주(오비히로)를 최신으로 저장해도 분석기는 고정 경주(사가)를 유지.
#   파일에 저장(서버 재시작에도 고정 유지) → "서버 재시작해도 반복" 문제 근본 차단.
RACE_PIN_FILE = os.path.join(os.path.dirname(__file__), "data", "race_pin.json")


def _race_pin_expire_stale():
    """[날짜 초기화] 고정 경주의 저장 날짜가 오늘이 아니면(어제 이전) 자동 해제 → None 반환.
    서버 시작 시 1회 + 매 조회(_race_pin_load)마다 호출 → 재시작·자정 넘김 모두에서
    '어제 고정 경주'가 오늘까지 잔존하는 것을 원천 차단. 날짜 기록 없는 레거시 고정은 유지(안전)."""
    try:
        d = json.load(open(RACE_PIN_FILE, encoding="utf-8"))
    except Exception:
        return None
    saved = (d.get("date") or "").strip()
    today = time.strftime("%Y-%m-%d")
    if saved and saved != today:
        _race_pin_clear()
        print(f"[경주 고정] 어제({saved}) 고정 경주 자동 해제 → 오늘({today})로 초기화(자동 전환 재개)")
        return None
    return (d.get("raceKey") or "").strip() or None


def _race_pin_load():
    """고정된 raceKey 반환(없으면 None). 파일 기반 → 서버 재시작에도 유지.
    단, 어제 이전 고정은 _race_pin_expire_stale 로 자동 해제(오늘 날짜만 유효)."""
    return _race_pin_expire_stale()


def _race_pin_save(rk):
    os.makedirs(os.path.dirname(RACE_PIN_FILE), exist_ok=True)
    json.dump({"raceKey": (rk or "").strip(), "pinnedAt": time.time(),
               "date": time.strftime("%Y-%m-%d")},   # [날짜 초기화] 고정 날짜 기록 → 어제 고정 자동 해제 판정
              open(RACE_PIN_FILE, "w", encoding="utf-8"), ensure_ascii=False)


def _race_pin_clear():
    try:
        os.remove(RACE_PIN_FILE)
    except OSError:
        pass


# ── [배당판 추종·board hint] 확장이 감지한 '현재 배당판 경주'를 분석기가 추종 ──────────────────
#   문제: oddspark bg 수집(나고야 등)이 30초마다 최신이라 current_race 의 max-t 폴백이 늘 그 경주를 반환 →
#         배당판은 몬베츠인데 분석기는 나고야/카나자와로 어긋남(특히 배당판 경주가 oddspark 미등록이면 데이터가
#         없어 max-t 가 다른 경주로 튐). 해결: content.js 가 배당판 raceKey 를 POST → 이 힌트를 max-t 보다 우선.
#   우선순위: pin(사용자 하드락) > board hint(신선) > max-t 폴백. TTL 지나면 자동 무시(배당판 닫히면 복귀).
BOARD_HINT_FILE = os.path.join(os.path.dirname(__file__), "data", "board_hint.json")
_BOARD_HINT_TTL = 90   # 초: 배당판 힌트 신선도(확장이 10초마다 재전송 → 넘으면 배당판 닫힌 것으로 보고 무시)


def _board_hint_save(rk, sport=None):
    try:
        os.makedirs(os.path.dirname(BOARD_HINT_FILE), exist_ok=True)
        json.dump({"raceKey": (rk or "").strip(), "sport": (sport or "").strip() or None, "t": time.time()},
                  open(BOARD_HINT_FILE, "w", encoding="utf-8"), ensure_ascii=False)
    except Exception as e:
        print("[배당판 힌트] 저장 실패(무시):", e)


def _board_hint_load():
    """신선한(TTL 내) 배당판 힌트 {raceKey, sport, t} 반환. 없거나 오래되면 None."""
    try:
        d = json.load(open(BOARD_HINT_FILE, encoding="utf-8"))
    except Exception:
        return None
    if not d or not d.get("raceKey"):
        return None
    if (time.time() - (d.get("t") or 0)) > _BOARD_HINT_TTL:
        return None
    return d


@app.route("/api/race/pin", methods=["GET", "POST"])
def race_pin():
    """[경주 고정] GET → 현재 고정 경주 조회. POST {raceKey} → 고정 / POST {clear:true} → 해제.
    고정 시 current_race·triple_latest가 명시 요청 없으면 항상 고정 경주를 반환(서버측 잠금)."""
    if request.method == "POST":
        body = request.json or {}
        if body.get("clear"):
            _race_pin_clear()
            print("[경주 고정] 해제 → 자동 전환 재개")
            return jsonify({"ok": True, "pinned": None})
        rk = (body.get("raceKey") or "").strip()
        if not rk:
            return jsonify({"error": "raceKey가 필요합니다."}), 400
        _race_pin_save(rk)
        print(f"[경주 고정] 서버측 잠금: {rk} (자동 전환 차단·재시작에도 유지)")
        return jsonify({"ok": True, "pinned": rk})
    return jsonify({"pinned": _race_pin_load()})


@app.route("/api/odds/triple/latest", methods=["GET", "POST"])
def triple_latest():
    """최근(또는 지정 raceKey) 3종 배당 조회 → {raceKey, quinella, exacta, trio, sport}.
    raceKey 명시 & 데이터 없으면 빈 결과(waiting) — 이전 경주로 폴백하지 않음.
    [종목 분리] sport 지정 시(query ?sport=horse 또는 body.sport) 그 종목의 최신만 반환
    → 일본경마 탭이 sport=horse 로 요청하면 경륜(cycle) 등 타종목이 절대 혼입되지 않는다.
    [경주 고정] 명시 요청이 없고 서버 고정이 걸려 있으면 항상 고정 경주를 반환(자동 전환 차단)."""
    rk, explicit, want_sport = None, False, None
    if request.method == "POST":
        body = request.json or {}
        rk = (body.get("raceKey") or "").strip() or None
        explicit = rk is not None
        want_sport = (body.get("sport") or "").strip() or None
    else:
        want_sport = (request.args.get("sport") or "").strip() or None
    db = _triple_load()
    if not db:
        return jsonify({})
    if rk not in db:
        if explicit:
            return jsonify({"raceKey": rk, "quinella": [], "exacta": [], "trio": [], "waiting": True})
        # [종목 분리] 종목 지정 시 그 종목 레코드만 후보(레거시 sport 없음=horse 로 간주 — 원래 일본경마만 존재).
        cand = list(db.keys())
        if want_sport == "korea":
            # [한국경마 탭 실시간 분석 (2026-07-19)] 한국경마는 sport=horse·category=korea 로 저장되므로
            #   sport 매칭으론 못 거른다 → category/경마장명으로 한국 경주만 후보(기존 horse 요청 동작 무변경·추가만).
            cand = [k for k in cand
                    if (db[k].get("category") == "korea") or _KRA_TRACK_RE.search(str(k))]
            if not cand:
                return jsonify({"raceKey": None, "quinella": [], "exacta": [], "trio": [],
                                "waiting": True, "noRace": True, "sport": "korea"})
        elif want_sport == "central":
            # [중앙경마 탭 실시간 분석 (2026-07-19)] JRA는 oddspark 미지원(서버 수집 불가) — 확장이 배당판에서
            #   잡아온 중앙 경주(category=japan_central·JRA 경마장명)를 이 탭에 실시간 표시(korea 와 동일 패턴·추가만).
            def _is_central_key(_k):
                if db[_k].get("category") == "japan_central":
                    return True
                _cv = _area_num(str(_k))[0] or ""
                return db[_k].get("category") not in ("korea", "cycle", "boat", "bike") and _cv in _JRA_TRACKS
            cand = [k for k in cand if _is_central_key(k)]
            if not cand:
                return jsonify({"raceKey": None, "quinella": [], "exacta": [], "trio": [],
                                "waiting": True, "noRace": True, "sport": "central"})
        elif want_sport:
            cand = [k for k in cand if _sport_match(db[k].get("sport"), want_sport)]
            if not cand:   # 해당 종목 경주 없음(예: 일본경마 오늘 개최 없음) → 타종목 혼입 없이 대기
                return jsonify({"raceKey": None, "quinella": [], "exacta": [], "trio": [],
                                "waiting": True, "noRace": True, "sport": want_sport})
        # [경주 고정] 명시 요청 없을 때: 서버 고정 경주가 있고(+종목 일치) 데이터가 있으면 우선(자동 전환 차단)
        _pin = _race_pin_load()
        if _pin and _pin in db and (not want_sport or _sport_match(db[_pin].get("sport"), want_sport)):
            rk = _pin
        else:
            rk = max(cand, key=lambda k: db[k].get("t", 0))
    rec = db.get(rk) or {}
    # [경주전환 잔존 방어] 30분+ 미갱신 최신 경주 = 끝난 경주 → stale 표기(프론트가 표시 억제)
    age = time.time() - (rec.get("t") or 0)
    return jsonify({"raceKey": rk, "quinella": rec.get("quinella", []),
                    "exacta": rec.get("exacta", []), "trio": rec.get("trio", []),
                    "sport": rec.get("sport") or "horse",
                    "ageSeconds": round(age), "stale": (not explicit) and age > STALE_ACTIVE_SEC})


def _anomaly_pretty(raw):
    """스냅샷 이상감지 원문 → {text, severity} 로 정규화(사람이 읽는 누적 피드용)."""
    m = re.search(r"(-?\d+)\s*%", raw or "")
    pct = int(m.group(1)) if m else None
    sev = "🔴" if ("역전" in raw or (pct is not None and pct <= -30)) else "🟡"
    if raw.startswith("급락감지:"):
        combo = raw.split(":", 1)[1].strip().split()[0]
        text = f"{combo} 복승 급락 {pct}%" if pct is not None else f"{combo} 복승 급락"
    elif raw.startswith("단승급락:"):
        mm = re.search(r"(\d+)번", raw)
        no = mm.group(1) if mm else "?"
        text = f"{no}번 단승 급락 {pct}%" if pct is not None else f"{no}번 단승 급락"
    elif raw.startswith("쌍승역전:"):
        pair = raw.split(":", 1)[1].strip()
        text = f"쌍승 역전 {pair}"
    else:
        text = raw
    return {"text": text, "severity": sev, "pct": pct}


def _anomaly_combo(raw):
    """스냅샷 이상감지 원문 → 조합 문자열(예 '2+3'·'4'·'5→10')."""
    raw = raw or ""
    if raw.startswith("급락감지:"):
        return raw.split(":", 1)[1].strip().split()[0]
    if raw.startswith("단승급락:"):
        m = re.search(r"(\d+)번", raw)
        return m.group(1) if m else ""
    if raw.startswith("쌍승역전:"):
        return raw.split(":", 1)[1].strip().split()[0]
    return ""


def _anomaly_events_from_doc(doc):
    """[이상감지 누적·공용] 스냅샷 doc → 시간순·중복제거 이상감지 이벤트 리스트.
    anomaly-feed 엔드포인트와 분석로그(anomaly_history)가 동일 규칙으로 공유(경주별 분리)."""
    events, seen = [], set()
    for s in (doc.get("snapshots") or []):
        for raw in (s.get("anomalies") or []):
            p = _anomaly_pretty(raw)
            # [초반미수집 방어] opening 배당 정착으로 이미 기록된 가짜 급락(-88%↓)은 숨김
            #   (복승/단승 급락만 · 쌍승역전은 유지). 물리적으로 정상 시장의 복승 -88%↓는 거의 없음.
            if p["pct"] is not None and p["pct"] <= -88 and ("복승 급락" in p["text"] or "단승 급락" in p["text"]):
                continue
            if p["text"] in seen:      # 최초 감지 시각만 유지(중복 누적 방지)
                continue
            seen.add(p["text"])
            events.append({"time": s.get("time"), "minutes_before": s.get("minutes_before"),
                           "text": p["text"], "severity": p["severity"], "pct": p["pct"],
                           "combo": _anomaly_combo(raw), "t": s.get("t")})
    events.sort(key=lambda e: e.get("t") or 0)   # 시간순
    return events


def _concentration_counts(doc):
    """[복병_집중급락] 경주 이상감지 이벤트에서 말별 등장 횟수(급락/역전 조합에 낀 횟수).
    마에바시 8R 복기: 8번이 낀 조합 다수가 동시 급락 → 15회 최다 = 자금 집중 복병 신호.
    반환 {말번호(int): 등장횟수}."""
    counts = {}
    for e in _anomaly_events_from_doc(doc):
        combo = e.get("combo")
        nos = combo if isinstance(combo, (list, tuple)) else re.split(r"[+\-↔→]", str(combo or ""))
        for h in nos:
            try:
                counts[int(str(h).strip())] = counts.get(int(str(h).strip()), 0) + 1
            except (TypeError, ValueError):
                pass
    return counts


@app.route("/api/odds/anomaly-feed", methods=["GET", "POST"])
def anomaly_feed():
    """[이상감지 누적] 경주별 스냅샷에서 감지된 이상을 시간순·중복제거로 누적 반환.
    스냅샷은 삭제되지 않으므로 마감 후에도, 새 수집 후에도 과거 감지가 유지된다.
    body/query: {raceKey}. → {raceKey, events:[{time,minutes_before,text,severity,pct,combo,t}]}"""
    if request.method == "POST":
        rk = ((request.json or {}).get("raceKey") or "").strip()
    else:
        rk = (request.args.get("raceKey") or "").strip()
    if not rk:
        return jsonify({"raceKey": rk, "events": []})
    path, _, _ = _hist_path(rk)
    try:
        doc = json.load(open(path, encoding="utf-8"))
    except Exception:
        return jsonify({"raceKey": rk, "events": []})
    return jsonify({"raceKey": rk, "events": _anomaly_events_from_doc(doc)})


@app.route("/api/learning/near-miss", methods=["GET"])
def learning_near_miss():
    """[2·3번] 4착 near-miss 케이스 + 4착 빈번(2회+) 말 목록(다음 경주 삼복승 보험픽 우선 고려)."""
    d = _near_miss_load()
    cases = sorted(d.get("cases", []), key=lambda c: -(c.get("t") or 0))
    cnt = {}
    for c in cases:
        nm = (c.get("name") or "").strip()
        if nm:
            cnt[nm] = cnt.get(nm, 0) + 1
    frequent = sorted([{"name": k, "count": v} for k, v in cnt.items() if v >= 2],
                      key=lambda x: -x["count"])
    return jsonify({"cases": cases, "count": len(cases), "frequent": frequent,
                    "note": "추천 말이 4착(아깝게 미적중)한 경주 — 4착 빈번 말은 삼복승 보험픽 우선 고려"})


