# ── [전날 경주 목록 + 스크린샷] 날짜별 결과기록 카드 + KPI ──
def _day_snapshot_for(rk, trigger="T-5"):
    """해당 경주의 지정 trigger 스냅샷 파일명 반환(없으면 T-10 등 폴백). 이미지 URL 조립용."""
    try:
        if not os.path.isdir(SNAPSHOT_DIR):
            return None
        cand = None
        for fn in os.listdir(SNAPSHOT_DIR):
            if not fn.endswith(".png"):
                continue
            mp = os.path.join(SNAPSHOT_DIR, fn.rsplit(".", 1)[0] + ".json")
            try:
                meta = json.load(open(mp, encoding="utf-8"))
            except Exception:
                continue
            if (meta.get("raceKey") or "").strip() != rk.strip():
                continue
            if meta.get("trigger") == trigger:
                return fn
            cand = cand or fn      # 폴백(아무 스냅샷)
        return cand
    except Exception:
        return None


@app.route("/api/day/races", methods=["GET"])
def day_races():
    """[전날 경주 목록] ?date=YYYYMMDD → 그 날짜 경주 카드(결과·예상vs결과·적중·복병적중·T-5 스크린샷) + KPI 요약."""
    date = re.sub(r"[^\d]", "", request.args.get("date") or "")
    if len(date) != 8:
        date = time.strftime("%Y%m%d")
    date_dash = "%s-%s-%s" % (date[:4], date[4:6], date[6:8])
    cards = []
    q_hit = q_tot = dark_hit = 0
    sig_stat = {}
    # dark_horse_log 인덱싱(경주명→분석)
    dark_by_race = {}
    if os.path.isdir(DARK_LOG_DIR):
        for fn in os.listdir(DARK_LOG_DIR):
            if not fn.endswith(".json"):
                continue
            try:
                d = json.load(open(os.path.join(DARK_LOG_DIR, fn), encoding="utf-8"))
            except Exception:
                continue
            if d.get("date") == date_dash:
                dark_by_race[d.get("race")] = d
    if os.path.isdir(RACE_RESULTS_DIR):
        for fn in sorted(os.listdir(RACE_RESULTS_DIR)):
            if not fn.endswith(".json"):
                continue
            try:
                d = json.load(open(os.path.join(RACE_RESULTS_DIR, fn), encoding="utf-8"))
            except Exception:
                continue
            if d.get("date") != date_dash:
                continue
            rk = d.get("raceKey") or ""
            res = d.get("result") or {}
            top3 = [res.get("1st"), res.get("2nd"), res.get("3rd")]
            top3 = [int(x) for x in top3 if x not in (None, "")]
            pred = d.get("prediction") or {}
            ra = d.get("result_analysis") or {}
            # 복승 예상 조합(recommend_main "3+5") vs 결과
            main = pred.get("recommend_main")
            main_hit = bool(ra.get("main_hit"))
            if main:
                q_tot += 1
                if main_hit:
                    q_hit += 1
            # 복병 적중
            dh = dark_by_race.get(rk) or {}
            dha = dh.get("dark_horse_analysis") or {}
            dark_ok = bool(dha.get("rank1_hit") or dha.get("rank2_hit"))
            if dark_ok:
                dark_hit += 1
            # 신호별(간이): pattern_tags
            for tg in (ra.get("pattern_tags") or []):
                s = sig_stat.setdefault(tg, [0, 0])
                s[1] += 1; s[0] += 1 if main_hit else 0
            cards.append({
                "race": rk, "horses": d.get("horse_count"),
                "result": {"top3": top3},
                "prediction": {"main": main, "sub": pred.get("recommend_sub")},
                "hit": main_hit, "dark_hit": dark_ok,
                "dark_ranks": dh.get("dark_horses"),
                "snapshot": _day_snapshot_for(rk, "T-5"),
            })
    kpi = {
        "quinellaRate": round(q_hit / q_tot * 100, 1) if q_tot else 0,
        "quinellaHit": q_hit, "quinellaTotal": q_tot,
        "darkHitCount": dark_hit,
        "bySignal": {k: {"hit": v[0], "total": v[1], "rate": round(v[0] / v[1] * 100, 1) if v[1] else 0}
                     for k, v in sig_stat.items()},
    }
    cards.sort(key=lambda c: c.get("race") or "")
    return jsonify({"date": date_dash, "count": len(cards), "kpi": kpi, "cards": cards})


# ── [카카오 알림] 큐 조회(사업자 등록 전 감사·수동발송용) ──
@app.route("/api/kakao/queue", methods=["GET"])
def kakao_queue():
    """카카오 알림 큐(발송 대기/이력) 최신순. ?limit=N."""
    limit = int(request.args.get("limit") or 50)
    out = []
    try:
        if os.path.exists(KAKAO_QUEUE_FILE):
            with open(KAKAO_QUEUE_FILE, encoding="utf-8") as f:
                for line in f:
                    line = line.strip()
                    if line:
                        try:
                            out.append(json.loads(line))
                        except Exception:
                            pass
    except Exception as e:
        return jsonify({"error": str(e)}), 500
    out = out[-limit:][::-1]
    return jsonify({"count": len(out), "messages": out,
                    "webhookConfigured": bool(os.environ.get("KAKAO_NOTIFY_URL"))})


def _high_odds_case_save(case):
    """[수동 케이스 학습] 사용자가 짚어준 놓친 케이스(카와사키 11R 등)를 data/high_odds_review/에 저장.
      자동 생성 복기(_high_odds_review_one)와 파일명 충돌 안 나게 '_case' 접미사 사용. manual_case=True 태깅.
      반환 저장 경로."""
    os.makedirs(HIGH_ODDS_REVIEW_DIR, exist_ok=True)
    c = dict(case or {})
    c["manual_case"] = True
    c.setdefault("saved_at", time.strftime("%Y-%m-%d %H:%M:%S", time.localtime()))
    safe = re.sub(r"[^0-9A-Za-z가-힣]", "_", str(c.get("race") or "case"))
    p = os.path.join(HIGH_ODDS_REVIEW_DIR, (c.get("date") or "nodate") + "_" + safe + "_case.json")
    tmp = p + ".tmp"
    with open(tmp, "w", encoding="utf-8") as f:
        json.dump(c, f, ensure_ascii=False, indent=1)
    os.replace(tmp, p)
    return p


def _high_odds_cases_load():
    """저장된 수동 케이스(manual_case=True) 목록(최신순)."""
    out = []
    if os.path.isdir(HIGH_ODDS_REVIEW_DIR):
        for fn in sorted(os.listdir(HIGH_ODDS_REVIEW_DIR), reverse=True):
            if not fn.endswith("_case.json"):
                continue
            try:
                out.append(json.load(open(os.path.join(HIGH_ODDS_REVIEW_DIR, fn), encoding="utf-8")))
            except Exception:
                continue
    return out


@app.route("/api/high-odds-review", methods=["GET", "POST"])
def high_odds_review():
    """[고배당 심층분석] 복승30배+/삼복승100배+ 경주 복기.
      GET ?raceKey=      → 해당 경주 심층 분석(고배당 아니면 is_high_odds:False)
      GET ?list=1        → 저장된 고배당 복기 목록(최신순 경량)
      GET ?cases=1       → 수동 학습 케이스(카와사키 11R 등) 목록
      GET ?stats=1       → [7번] 누적 통계(총/적중/미적중·A/B/C·개선 후 예상)
      POST body{case}    → 수동 케이스 저장 / body{date?} → [1번] 스캔·저장"""
    if request.args.get("cases"):
        return jsonify({"cases": _high_odds_cases_load()})
    if request.args.get("stats"):
        return jsonify(_high_odds_stats())
    if request.args.get("list"):
        out = []
        if os.path.isdir(HIGH_ODDS_REVIEW_DIR):
            for fn in sorted(os.listdir(HIGH_ODDS_REVIEW_DIR), reverse=True):
                if not fn.endswith(".json"):
                    continue
                try:
                    r = json.load(open(os.path.join(HIGH_ODDS_REVIEW_DIR, fn), encoding="utf-8"))
                except Exception:
                    continue
                out.append({"race": r.get("race"), "date": r.get("date"), "result": r.get("result"),
                            "hit": r.get("hit"), "abc_type": r.get("abc_type"),
                            "fail_label": r.get("fail_label"), "result_odds": r.get("result_odds")})
        return jsonify({"reviews": out, "count": len(out)})
    if request.method == "POST":
        body = request.get_json(silent=True) or {}
        if body.get("case"):                       # [수동 케이스 저장]
            try:
                p = _high_odds_case_save(body["case"])
                return jsonify({"ok": True, "saved": os.path.basename(p)})
            except Exception as e:
                return jsonify({"ok": False, "error": str(e)}), 500
        date = body.get("date") or None
        found = _high_odds_scan(date)
        return jsonify({"scanned_high_odds": len(found),
                        "hits": sum(1 for r in found if r.get("hit")),
                        "misses": sum(1 for r in found if not r.get("hit")),
                        "races": [r.get("race") for r in found]})
    rk = (request.args.get("raceKey") or "").strip()
    if not rk:
        return jsonify({"ok": False, "error": "raceKey 또는 ?list/stats/POST scan 이 필요합니다."}), 400
    rk = _resolve_race_key(rk) or rk
    return jsonify(_high_odds_review_one(rk))


@app.route("/api/hall-of-fame", methods=["GET"])
def hall_of_fame():
    """[5번] 고배당 적중 명예의 전당(복승 30배+/삼복승 100배+) — 최신순 + 스토리·타임라인."""
    try:
        arr = json.load(open(HIGHLIGHT_FILE, encoding="utf-8"))
    except Exception:
        arr = []
    arr = sorted(arr, key=lambda x: x.get("t", 0), reverse=True)
    return jsonify({"wins": arr[:100], "count": len(arr)})


@app.route("/api/races/list", methods=["GET"])
def races_list():
    """[2번] 결과 입력용 경주 목록(시간순). ?date=YYYY-MM-DD &pending=1(미입력만).
    → {races:[{raceKey,area,num,hasResult,top3,lastT,snaps}]} — 자동완성·순서대로 빠른입력용."""
    date = (request.args.get("date") or "").strip()
    pending = request.args.get("pending") in ("1", "true", "yes")
    out = []
    if os.path.isdir(ODDS_HISTORY_DIR):
        for fn in os.listdir(ODDS_HISTORY_DIR):
            if not fn.endswith(".json"):
                continue
            try:
                d = json.load(open(os.path.join(ODDS_HISTORY_DIR, fn), encoding="utf-8"))
            except Exception:
                continue
            rk = d.get("raceKey") or d.get("race")
            if not rk:
                continue
            if date and date not in (rk or "") and date != (d.get("date") or ""):
                continue
            has_result = bool(d.get("result"))
            if pending and has_result:
                continue
            area, num = _area_num(rk)
            res = d.get("result") or {}
            top3 = [res.get("1st"), res.get("2nd"), res.get("3rd")]
            snaps = d.get("snapshots") or []
            out.append({"raceKey": rk, "area": area, "num": num, "hasResult": has_result,
                        "top3": [x for x in top3 if x not in (None, "")],
                        "lastT": (snaps[-1].get("t") if snaps else 0), "snaps": len(snaps)})
    out.sort(key=lambda x: (x.get("lastT") or 0))   # 수집 시각순 → 결과 목록 시간순 매칭
    return jsonify({"races": out, "count": len(out)})


# ══════════════ [경쟁 AI 벤치마킹] 저쪽 추천 수집·패턴 역추산·비교 학습 ══════════════
#   목적: 경쟁 AI 추천 조합을 매 경주 수집→축·연결마·조합패턴 자동분석→우리 추천과 비교→
#         누적통계로 '저쪽이 잘 맞히는 패턴(고배당 등)'을 역추산해 우리 시스템 개선에 반영.
#   ⚠ 완전 추가(기존 분석/학습/판정 무관). data/competitor_analysis/ 경주별 저장 + competitor_stats.json 누적.
COMPETITOR_DIR = os.path.join(os.path.dirname(__file__), "data", "competitor_analysis")
COMPETITOR_STATS_FILE = os.path.join(os.path.dirname(__file__), "data", "competitor_stats.json")


def _combo_norm(picks):
    """[[4,10],[7,10],...] → 정렬 2두+ 조합 리스트(정수·중복제거)."""
    out, seen = [], set()
    for c in (picks or []):
        try:
            nums = sorted(int(x) for x in c)
        except (TypeError, ValueError):
            continue
        if len(nums) >= 2 and tuple(nums) not in seen:
            seen.add(tuple(nums))
            out.append(nums)
    return out


def _analyze_competitor_pattern(picks, odds=None):
    """추천 조합 → 축(최다등장 번호)·연결마·조합수·고배당포함 패턴 분석. odds(조합별 배당) 있으면 고배당 판정."""
    combos = _combo_norm(picks)
    if not combos:
        return {"combos": [], "axis": [], "connections": [], "others": [], "combo_count": 0,
                "horses": [], "high_odds": None, "label": "조합 없음"}
    cnt = {}
    for c in combos:
        for n in set(c):
            cnt[n] = cnt.get(n, 0) + 1
    maxc = max(cnt.values())
    axis = sorted([n for n, v in cnt.items() if v == maxc and v >= 2])   # 2조합+ 최다등장 = 축
    conn = sorted({n for c in combos if set(c) & set(axis) for n in c if n not in axis})
    others = [c for c in combos if not (set(c) & set(axis))]
    high_odds = None
    try:
        ov = [float(o) for o in (odds or []) if o is not None]
        if ov:
            high_odds = bool(max(ov) >= 15)   # 조합 중 15배+ 있으면 고배당 포함
    except (TypeError, ValueError):
        pass
    label = ("%s번 축 %d조합" % ("·".join(map(str, axis)), len(combos))) if axis else ("축 불명 %d조합" % len(combos))
    if high_odds:
        label += " · 고배당포함"
    return {"combos": combos, "axis": axis, "connections": conn, "others": others,
            "combo_count": len(combos), "horses": sorted(cnt.keys()), "high_odds": high_odds, "label": label}


def _our_picks_for_race(rk):
    """우리 시스템 복승 추천 + 축 → analysis_log corePicks/최종추천에서 복원(_rec_combos 재사용)."""
    combos = []
    for c in _rec_combos_from_analysis_log(rk):
        if c.get("kind") == "복승" and len(c.get("combo") or []) == 2:
            combos.append(sorted(int(x) for x in c["combo"]))
    pat = _analyze_competitor_pattern(combos)
    return {"picks": pat["combos"], "axis": pat["axis"], "connections": pat["connections"],
            "main_horse": (pat["axis"] or [None])[0], "pattern": pat}


def _competitor_result_for_race(rk):
    """경주 결과(1·2·3착) → analysis_log(canonical) 우선, 없으면 race_results."""
    try:
        path, _, _ = _analysis_log_path(_canonical_log_key(rk))
        d = json.load(open(path, encoding="utf-8"))
        r = d.get("result")
        if r and r.get("1st") not in (None, ""):
            return {k: r.get(k) for k in ("1st", "2nd", "3rd") if r.get(k) not in (None, "")}
    except Exception:
        pass
    try:
        rp, _, _ = _race_result_path(rk)
        d = json.load(open(rp, encoding="utf-8"))
        r = d.get("result") or {}
        if r.get("1st") not in (None, ""):
            return {k: r.get(k) for k in ("1st", "2nd", "3rd") if r.get(k) not in (None, "")}
    except Exception:
        pass
    return None


def _quinella_hits(combos, result):
    """복승 조합 중 실제 1·2착(순서무관)과 일치하는 게 있으면 True. 결과 없으면 None."""
    if not result or result.get("1st") in (None, "") or result.get("2nd") in (None, ""):
        return None
    try:
        top2 = sorted([int(result["1st"]), int(result["2nd"])])
    except (TypeError, ValueError):
        return None
    return any(sorted(c) == top2 for c in (combos or []))


def _competitor_compare(comp_pat, our, result):
    """저쪽 vs 우리 비교: 적중·축 일치·연결마 차이."""
    ca, oa = set(comp_pat.get("axis") or []), set(our.get("axis") or [])
    comp_hit = _quinella_hits(comp_pat.get("combos") or [], result)
    our_hit = _quinella_hits(our.get("picks") or [], result)
    axis_match = bool(ca and oa and (ca & oa))
    cc, oc = set(comp_pat.get("connections") or []), set(our.get("connections") or [])
    diff = []
    if ca or oa:
        diff.append(("축 일치(%s)" % "·".join(map(str, sorted(ca & oa)))) if axis_match
                    else ("축 다름(저쪽 %s / 우리 %s)" % ("·".join(map(str, sorted(ca))) or "-", "·".join(map(str, sorted(oa))) or "-")))
    only_c, only_o = sorted(cc - oc), sorted(oc - cc)
    if only_c:
        diff.append("저쪽만 연결: %s" % "·".join(map(str, only_c)))
    if only_o:
        diff.append("우리만 연결: %s" % "·".join(map(str, only_o)))
    return {"competitor_hit": comp_hit, "our_hit": our_hit,
            "competitor_axis": sorted(ca), "our_axis": sorted(oa),
            "axis_match": axis_match, "diff": " · ".join(diff) or "-"}


def _competitor_path(rk, date):
    rid = re.sub(r"[^\w가-힣]+", "_", "%s_%s" % (date, re.sub(r"\d{4}-\d{2}-\d{2}", "", rk or "").strip())).strip("_")
    os.makedirs(COMPETITOR_DIR, exist_ok=True)
    return os.path.join(COMPETITOR_DIR, rid + ".json")


def _competitor_record(rk, comp_picks, comp_odds=None, comp_note=None):
    """저쪽 추천 저장 + 우리 추천/결과 비교 분석 → data/competitor_analysis/ + 통계 갱신."""
    m = re.search(r"\d{4}-\d{2}-\d{2}", rk or "")
    date = m.group(0) if m else time.strftime("%Y-%m-%d", time.localtime())
    comp_pat = _analyze_competitor_pattern(comp_picks, comp_odds)
    our = _our_picks_for_race(rk)
    result = _competitor_result_for_race(rk)
    analysis = _competitor_compare(comp_pat, our, result)
    rec = {
        "date": date, "race": rk,
        "competitor": {"picks": comp_pat["combos"], "axis": comp_pat["axis"],
                       "connections": comp_pat["connections"], "high_odds": comp_pat["high_odds"],
                       "pattern": comp_pat["label"], "note": comp_note},
        "ours": {"picks": our["picks"], "axis": our["axis"], "main_horse": our["main_horse"]},
        "result": result, "analysis": analysis, "savedAt": int(time.time()),
    }
    try:
        json.dump(rec, open(_competitor_path(rk, date), "w", encoding="utf-8"), ensure_ascii=False, indent=1)
    except Exception as e:
        print("[경쟁분석] 저장 실패:", e)
    _competitor_recompute_stats()
    return rec


def _competitor_recompute_stats():
    """data/competitor_analysis/ 전체 스캔 → 적중률·축정확도·고배당 비교 통계 누적."""
    st = {"races": 0, "with_result": 0,
          "competitor_hit": 0, "our_hit": 0, "both_hit": 0, "only_competitor": 0, "only_ours": 0, "both_miss": 0,
          "axis_match": 0, "competitor_high_odds": 0, "competitor_high_odds_hit": 0,
          "missed_by_us_axis": {}, "updatedAt": int(time.time())}
    try:
        if not os.path.isdir(COMPETITOR_DIR):
            return st
        for fn in os.listdir(COMPETITOR_DIR):
            if not fn.endswith(".json"):
                continue
            try:
                d = json.load(open(os.path.join(COMPETITOR_DIR, fn), encoding="utf-8"))
            except Exception:
                continue
            st["races"] += 1
            an = d.get("analysis") or {}
            if an.get("axis_match"):
                st["axis_match"] += 1
            if (d.get("competitor") or {}).get("high_odds"):
                st["competitor_high_odds"] += 1
            ch, oh = an.get("competitor_hit"), an.get("our_hit")
            if ch is None and oh is None:
                continue
            st["with_result"] += 1
            if ch:
                st["competitor_hit"] += 1
                if (d.get("competitor") or {}).get("high_odds"):
                    st["competitor_high_odds_hit"] += 1
            if oh:
                st["our_hit"] += 1
            if ch and oh:
                st["both_hit"] += 1
            elif ch and not oh:
                st["only_competitor"] += 1
                for a in (d.get("competitor") or {}).get("axis") or []:   # 저쪽만 맞힌 경주의 축 = 우리가 놓친 패턴
                    st["missed_by_us_axis"][str(a)] = st["missed_by_us_axis"].get(str(a), 0) + 1
            elif oh and not ch:
                st["only_ours"] += 1
            else:
                st["both_miss"] += 1
        n = st["with_result"] or 1
        st["competitor_hit_rate"] = round(100 * st["competitor_hit"] / n)
        st["our_hit_rate"] = round(100 * st["our_hit"] / n)
        st["axis_match_rate"] = round(100 * st["axis_match"] / (st["races"] or 1))
        json.dump(st, open(COMPETITOR_STATS_FILE, "w", encoding="utf-8"), ensure_ascii=False, indent=1)
    except Exception as e:
        print("[경쟁분석] 통계 갱신 실패:", e)
    return st


@app.route("/api/competitor/record", methods=["POST"])
def competitor_record():
    """[경쟁분석] 저쪽 추천 저장·비교. body:{raceKey, picks:[[4,10],[7,10]], odds?:[..], note?}."""
    b = request.json or {}
    rk_in = (b.get("raceKey") or "").strip()
    if not rk_in or not b.get("picks"):
        return jsonify({"error": "raceKey 와 picks 가 필요합니다."}), 400
    rk = _resolve_race_key(rk_in) or rk_in
    rec = _competitor_record(rk, b.get("picks"), b.get("odds"), b.get("note"))
    try:
        _data_git_backup("경쟁분석 저장: %s" % rk)
    except Exception:
        pass
    return jsonify({"ok": True, "raceKey": rk, "record": rec,
                    "matchedFrom": rk_in if rk != rk_in else None})


@app.route("/api/competitor/list", methods=["GET"])
def competitor_list():
    """[경쟁분석] 저장된 경주 목록(?date=YYYY-MM-DD 필터, 기본 전체)."""
    date = request.args.get("date")
    out = []
    if os.path.isdir(COMPETITOR_DIR):
        for fn in sorted(os.listdir(COMPETITOR_DIR)):
            if not fn.endswith(".json"):
                continue
            try:
                d = json.load(open(os.path.join(COMPETITOR_DIR, fn), encoding="utf-8"))
            except Exception:
                continue
            if date and d.get("date") != date:
                continue
            an = d.get("analysis") or {}
            out.append({"race": d.get("race"), "date": d.get("date"),
                        "competitor_axis": an.get("competitor_axis"), "our_axis": an.get("our_axis"),
                        "competitor_hit": an.get("competitor_hit"), "our_hit": an.get("our_hit"),
                        "diff": an.get("diff")})
    out.sort(key=lambda x: (x.get("date") or "", x.get("race") or ""), reverse=True)
    return jsonify({"races": out, "count": len(out)})


@app.route("/api/competitor/get", methods=["GET"])
def competitor_get():
    """[경쟁분석] 한 경주 상세(?raceKey=)."""
    rk_in = (request.args.get("raceKey") or "").strip()
    if not rk_in:
        return jsonify({"error": "raceKey 필요"}), 400
    rk = _resolve_race_key(rk_in) or rk_in
    m = re.search(r"\d{4}-\d{2}-\d{2}", rk or "")
    date = m.group(0) if m else time.strftime("%Y-%m-%d", time.localtime())
    try:
        d = json.load(open(_competitor_path(rk, date), encoding="utf-8"))
        return jsonify({"ok": True, "record": d})
    except Exception:
        return jsonify({"ok": False, "error": "저장된 경쟁분석 없음", "raceKey": rk})


@app.route("/api/competitor/stats", methods=["GET"])
def competitor_stats():
    """[경쟁분석] 누적 비교 통계(적중률·축정확도·고배당·우리가 놓친 축 패턴)."""
    try:
        st = json.load(open(COMPETITOR_STATS_FILE, encoding="utf-8"))
    except Exception:
        st = _competitor_recompute_stats()
    return jsonify(st)


@app.route("/api/history/record-result", methods=["POST"])
def history_record_result():
    """경주 결과 입력 → 히스토리에 결과 기록 + 자동학습 + 완전 저장(race_results).
    body: {raceKey, result:{'1st':7,'2nd':1,'3rd':9,'4th':2}, stake?, payout?, finalOdds?,
           memo?, budget?, quinellaOdds?, trifectaOdds?, distance?, trackCondition?, weather?, horseCount?}"""
    body = request.json or {}
    rk_in = (body.get("raceKey") or "").strip()
    result = body.get("result") or {}
    top3 = [result.get("1st"), result.get("2nd"), result.get("3rd")]
    top3 = [int(x) for x in top3 if x not in (None, "")]
    if not rk_in or len(top3) < 1:
        return jsonify({"error": "raceKey와 결과(1~3착)가 필요합니다."}), 400
    # [매칭 유연화] '서울 5' ↔ '2026-07-05 서울 5경주' 형식 불일치 방어 → 실제 분석 key로 해석
    rk = _resolve_race_key(rk_in) or rk_in
    # [2번] 결과 입력 부가정보(메모·확정배당·예산·경주조건) → 완전 저장 파일에 반영
    inputs = {
        "memo": body.get("memo"), "budget": body.get("budget"),
        "main_bet": body.get("mainBet"), "sub_bet": body.get("subBet"),
        "quinella_odds": body.get("quinellaOdds"), "trifecta_odds": body.get("trifectaOdds"),
        "distance": body.get("distance"), "track_condition": body.get("trackCondition"),
        "weather": body.get("weather"), "horse_count": body.get("horseCount"),
    }
    record, stats = _apply_result_learning(rk, result, top3, body.get("finalOdds"),
                                           stake=body.get("stake"), payout=body.get("payout"), inputs=inputs)
    return jsonify({"ok": True, "record": record, "stats": stats, "raceKey": rk,
                    "matchedFrom": rk_in if rk != rk_in else None,
                    "raceResultSaved": record.get("race_result_saved"),
                    "dataErrors": record.get("race_result_errors") or []})


# ─────────────────────────────────────────────────────────────────────
# [복기 저장] 확장 팝업 🧠 복기 저장 — 중요 신호(분석 스냅샷) + 결과를 묶어 저장.
#   결과가 있으면 record-result 와 동일한 학습(_apply_result_learning)까지 수행.
#   저장본은 결과기록 탭 재현 리포트와 별개로 data/review_log/ 에 누적(복기용).
# ─────────────────────────────────────────────────────────────────────
REVIEW_LOG_DIR = os.path.join(os.path.dirname(__file__), "data", "review_log")

# [자유 코멘트 키워드 태깅] 사용자가 쓴 코멘트에서 참고용 키워드만 자연스럽게 추출.
#   ⚠ 강제 분류·분석 없음 — 코멘트는 원문 그대로 저장하고, 태그는 부가 참고용.
COMMENT_TAG_RULES = [
    (["아쉽", "아쉬", "惜"], "near_miss"),
    (["놓쳤", "놓침", "못잡", "못 잡", "놓친"], "missed"),
    (["주목", "기억", "다음에"], "watch_next"),
    (["스마트머니", "스마트 머니"], "smart_money"),
    (["역배열", "역배"], "reversal"),
    (["복병"], "dark_horse"),
    (["고배당"], "high_odds"),
]
COMMENT_TAG_LABEL = {
    "near_miss": "아쉬움", "missed": "놓침", "watch_next": "다음 주목",
    "smart_money": "스마트머니", "reversal": "역배열", "dark_horse": "복병", "high_odds": "고배당",
}


def _comment_tags(comment):
    """자유 코멘트 → 참고용 키워드 태그 리스트(강제 분류 아님·중복 제거)."""
    c = comment or ""
    tags = []
    for kws, tag in COMMENT_TAG_RULES:
        if tag not in tags and any(k in c for k in kws):
            tags.append(tag)
    return tags


def _review_extract_signals(sig):
    """확장 analyzeStatus.data 에서 중요 신호만 압축 요약(급락·역배열·스마트머니·경고·확신도)."""
    sig = sig or {}
    out = {"drops": [], "reversals": [], "smartMoney": [], "keyHorses": [],
           "alerts": [], "confidence": [], "recommend": [],
           "minutesBefore": sig.get("minutesBefore"), "afterClose": bool(sig.get("afterClose"))}
    for d in (sig.get("drops") or [])[:8]:
        try:
            out["drops"].append({"combo": d.get("combo"), "prev": d.get("prev"),
                                 "cur": d.get("cur"), "pct": d.get("pct")})
        except Exception:
            pass
    for r in (sig.get("reversals") or []):
        if r.get("flipped"):
            out["reversals"].append({"favored": r.get("favored"), "ratio": r.get("ratio")})
    for h in (sig.get("darkHorses") or []):
        if h.get("smartMoney"):
            out["smartMoney"].append({"no": h.get("no"), "stars": h.get("stars"),
                                      "oddsRepr": h.get("oddsRepr"), "tierLabel": h.get("tierLabel")})
    out["keyHorses"] = sig.get("keyHorses") or []
    al = sig.get("alertSignal") or {}
    for x in (al.get("alerts") or [])[:6]:
        out["alerts"].append({"combo": x.get("combo"), "before": x.get("before"), "after": x.get("after")})
    conf = ((sig.get("signalQuality") or {}).get("signalConfidence") or {})
    horses = conf.get("horses") or {}
    scored = []
    for no, v in horses.items():
        c = (v or {}).get("confidence")
        if c is not None:
            scored.append({"no": no, "confidence": c})
    scored.sort(key=lambda x: -x["confidence"])
    out["confidence"] = scored[:6]
    for r in (sig.get("betRecommend") or [])[:6]:
        out["recommend"].append({"label": r.get("label"), "combo": r.get("combo")})
    out["count"] = len(out["drops"]) + len(out["reversals"]) + len(out["smartMoney"]) + len(out["alerts"])
    return out


@app.route("/api/review/save", methods=["POST"])
def review_save():
    """[복기 저장·자유 코멘트] body: {raceKey, signals?, result:{1st,2nd,3rd}?, comment?, importance?(1~3),
       finalOdds?, stake?, payout?}. 코멘트는 원문 그대로 저장·키워드는 참고용 태깅(강제분류 없음)."""
    body = request.json or {}
    rk_in = (body.get("raceKey") or "").strip()
    if not rk_in:
        return jsonify({"error": "raceKey가 필요합니다."}), 400
    rk = _resolve_race_key(rk_in) or rk_in
    sig = _review_extract_signals(body.get("signals"))
    result = body.get("result") or {}
    top3 = [result.get("1st"), result.get("2nd"), result.get("3rd")]
    top3 = [int(x) for x in top3 if x not in (None, "")]
    has_result = len(top3) >= 1
    # [자유 코멘트·중요도] 원문 보존 + 참고용 키워드 태깅. 중요도(1일반/2중요/3최고)=학습 가중.
    comment = (body.get("comment") or "").strip()
    try:
        importance = int(body.get("importance") or 1)
    except (TypeError, ValueError):
        importance = 1
    importance = max(1, min(3, importance))
    tags = _comment_tags(comment)
    hit = None
    if has_result:
        # 결과가 있으면 기존 학습 파이프라인 재사용(record-result 와 동일 — 재호출 시 깨끗이 덮어씀)
        try:
            record, _stats = _apply_result_learning(rk, result, top3, body.get("finalOdds"),
                                                     stake=body.get("stake"), payout=body.get("payout"))
            hit = record.get("hit")
        except Exception as e:
            print("[복기저장] 학습 실패:", e)
    os.makedirs(REVIEW_LOG_DIR, exist_ok=True)
    rid, date = _race_result_id(rk)
    rec = {"raceKey": rk, "race_id": rid, "date": date,
           "savedAt": int(time.time() * 1000), "signals": sig,
           "result": {"top3": top3} if has_result else None, "hit": hit,
           # [자유 코멘트 저장 구조] comment(정리본)·raw_comment(원문)·importance·tags·weight
           "comment": comment, "raw_comment": comment,
           "importance": importance, "weight": importance, "tags": tags}
    try:
        with open(os.path.join(REVIEW_LOG_DIR, rid + ".json"), "w", encoding="utf-8") as f:
            json.dump(rec, f, ensure_ascii=False, indent=2)
    except Exception as e:
        return jsonify({"error": f"저장 실패: {e}"}), 500
    # [중요도 학습 반영] ⭐최고(3)는 즉시 규칙 검토 큐에 기록(참고용·비침습)
    if importance >= 3:
        try:
            _review_flag_top_importance(rec)
        except Exception as e:
            print("[복기저장] 최고중요 플래그 실패:", e)
    return jsonify({"ok": True, "raceKey": rk, "race_id": rid,
                    "signalCount": sig.get("count", 0), "hasResult": has_result, "hit": hit,
                    "importance": importance, "tags": tags,
                    "tagLabels": [COMMENT_TAG_LABEL.get(t, t) for t in tags]})


REVIEW_TOP_FILE = os.path.join(os.path.dirname(__file__), "data", "review_top_importance.json")


def _review_flag_top_importance(rec):
    """⭐⭐⭐ 최고 중요 경주 → 즉시 규칙 검토 큐(참고용)에 누적(최근 200건)."""
    try:
        cur = json.load(open(REVIEW_TOP_FILE, encoding="utf-8")) if os.path.exists(REVIEW_TOP_FILE) else []
    except Exception:
        cur = []
    if not isinstance(cur, list):
        cur = []
    cur = [x for x in cur if x.get("race_id") != rec.get("race_id")]   # 같은 경주 중복 제거(최신 유지)
    cur.insert(0, {"race_id": rec.get("race_id"), "raceKey": rec.get("raceKey"),
                   "savedAt": rec.get("savedAt"), "comment": rec.get("comment"),
                   "tags": rec.get("tags") or [], "result": rec.get("result")})
    cur = cur[:200]
    try:
        with open(REVIEW_TOP_FILE, "w", encoding="utf-8") as f:
            json.dump(cur, f, ensure_ascii=False, indent=2)
    except Exception:
        pass


