@app.route("/api/learning/upset", methods=["GET"])
def learning_upset():
    """[2번] 부진마 역전 학습 조회 → {patterns, condition_stats, summary}.
    조건별 적중률(rate=hit/count)을 계산해 통계 탭에서 바로 표시한다."""
    d = _upset_load()
    cs = d.get("condition_stats") or {}
