# ─────────────────────────────────────────
# 전적 분석 엔진 (Phase 3) — 마필 점수 자동 계산
# ─────────────────────────────────────────
# 3-1 기본 점수: 최근 5경주 착순 가중 평균
#   착순→점수: 1착=100, 2착=75, 3착=50, 4착=25, 5착 이하=0
#   가중치(직전 경주부터): 40% / 30% / 20% / 5% / 5%
FORM_WEIGHTS = [0.40, 0.30, 0.20, 0.05, 0.05]


def place_points(p):
    """착순(int) → 점수. 1=100, 2=75, 3=50, 4=25, 5착 이하=0. 무효(기권/미출주 등)는 None."""
    try:
        p = int(p)
    except (TypeError, ValueError):
        return None
    if p <= 0:
        return None
    return {1: 100, 2: 75, 3: 50, 4: 25}.get(p, 0)


def base_form_score(placings):
    """placings: 최근 경주부터 [직전, -2, -3, -4, -5] 착순 리스트.
    유효 착순만 가중평균하되, 실제 사용된 가중치 합으로 재정규화(전적 <5경주 대응). 0~100."""
    used = []
    for w, p in zip(FORM_WEIGHTS, (placings or [])[:5]):
        pts = place_points(p)
        if pts is not None:
            used.append((w, pts))
    if not used:
        return 0.0
    wsum = sum(w for w, _ in used)
    return round(sum(w * pts for w, pts in used) / wsum, 1)


def _to_int(v):
    """'1200', '1200M', '1,200m' → 1200. 숫자 없으면 None."""
    if v is None:
        return None
    m = re.search(r"\d+", str(v).replace(",", ""))
    return int(m.group()) if m else None


def _placings_of(horse):
    """horse 에서 최근 착순 배열을 얻는다. recentPlacings 우선, 없으면 pastRaces[].placing."""
    if horse.get("recentPlacings"):
        return horse["recentPlacings"]
    return [pr.get("placing") for pr in (horse.get("pastRaces") or [])]


# ── 3-2 코스 적성 보너스 ──────────────────
def course_aptitude_bonus(past_races, race):
    """현재 거리 ±100m 경험 +10 / 현재 코스(내·외) 경험 +10 / 현재 조건(급) 경험 +5."""
    bonus, detail = 0, []
    rdist = _to_int(race.get("distance"))
    rcourse = (race.get("course") or "").strip()
    rgrade = (race.get("grade") or "").strip()
    dists, courses, grades = [], [], []
    for pr in past_races or []:
        d = _to_int(pr.get("distance"))
        if d is not None:
            dists.append(d)
        if pr.get("course"):
            courses.append(str(pr["course"]).strip())
        if pr.get("grade"):
            grades.append(str(pr["grade"]).strip())
    if rdist is not None and any(abs(d - rdist) <= 100 for d in dists):
        bonus += 10
        detail.append("거리적성(±100m)+10")
    if rcourse and rcourse in courses:
        bonus += 10
        detail.append(f"코스일치({rcourse})+10")
    if rgrade and rgrade in grades:
        bonus += 5
        detail.append(f"조건일치({rgrade})+5")
    return bonus, detail


# ── 3-3 기수 보너스 ──────────────────────
def top20_threshold(rates):
    """복승률 리스트의 상위 20% 경계값(80번째 백분위). 유효값 없으면 None."""
    vals = sorted(v for v in rates if isinstance(v, (int, float)) and v > 0)
    if not vals:
        return None
    # 80번째 백분위(선형 보간)
    idx = 0.8 * (len(vals) - 1)
    lo = int(idx)
    frac = idx - lo
    return vals[lo] + (vals[min(lo + 1, len(vals) - 1)] - vals[lo]) * frac


def jockey_bonus(horse, threshold):
    """기수 3개월 복승률 상위 20% +15 / 기수-마필 직전 경주 적중(같은 기수·3착 이내) +10."""
    bonus, detail = 0, []
    rate = horse.get("jockey3mPlaceRate")
    if threshold is not None and isinstance(rate, (int, float)) and rate >= threshold and rate > 0:
        bonus += 15
        detail.append(f"기수복승률상위20%({rate}%)+15")
    placings = _placings_of(horse)
    last = placings[0] if placings else None
    last_jockey = horse.get("lastJockey")
    same = (last_jockey is None) or (str(last_jockey).strip() == str(horse.get("jockey", "")).strip())
    lp = _to_int(last)
    if same and lp is not None and 1 <= lp <= 3:
        bonus += 10
        detail.append(f"기수-마필 직전적중({lp}착)+10")
    return bonus, detail


# ── 3-2b 각질(레이스 스타일) 추정 [2] ──────────
def _running_style(horse):
    """직전 3경주의 초반 포지션(선행/중단/후방)으로 각질 추정.
    선행 우세 → '선행형', 후방 우세 → '추격형', 혼재 → '평지형'.
    포지션 정보가 전혀 없으면 '' (레이팅/착순만으로는 초반위치 추정 불가 → 미상)."""
    prs = (horse.get("pastRaces") or [])[:3]
    lead = mid = back = 0
    for pr in prs:
        pos = (pr.get("position") or "").strip()
        if any(k in pos for k in ("선행", "선두", "도주")):
            lead += 1
        elif any(k in pos for k in ("후방", "후미", "추입", "추격")):
            back += 1
        elif any(k in pos for k in ("중단", "중위", "중")):
            mid += 1
    if not (lead or mid or back):
        return ""
    if lead > back and lead >= mid:
        return "선행형"
    if back > lead and back >= mid:
        return "추격형"
    return "평지형"


# ══════════════ [각질 편성 분석·신규] 4분류 정규화 + 페이스 예측 + 각질별 유불리 ══════════════
#   고배당 적중 핵심: 편성(각질 분포)으로 페이스 예측 → 각질별 유불리 보정 → 추입 고배당 기회 포착.
_GAIT_STYLE_MAP = {"선행형": "선행", "도주": "선행", "추격형": "추입", "추입형": "추입",
                   "마크": "추입", "평지형": "선입"}


def _gait_of(horse):
    """[1] 각질 4분류 정규화 → 선행/선입/추입/자유. 명시 gait/styleType > runningStyle > pastRaces position."""
    for key in ("gait", "styleType", "runningStyle"):
        v = str(horse.get(key) or "").strip()
        if v:
            # [수정1·경륜 각질 전체 매핑] 자재(양각)=상황가변 → 자유
            if "자유" in v or "자재" in v or "양각" in v or "両" in v or "自在" in v:
                return "자유"
            # 선행 계열: 선행·도주(逃)·젖히기(捲·まくり·마쿠리)·선두 — 젖히기는 앞에서 치고나가는 선행 계열
            if any(k in v for k in ("선행", "도주", "선두", "젖히기", "捲", "まくり", "마쿠리", "先行", "逃")):
                return "선행"
            # 추입 계열: 추입·추격·마크(マ)·차입(差·差し·사시)·追
            if any(k in v for k in ("추입", "추격", "마크", "マ", "차입", "差", "사시", "追")):
                return "추입"
            if "선입" in v or "중간" in v or "중단" in v or "中団" in v:
                return "선입"
            if v in _GAIT_STYLE_MAP:
                return _GAIT_STYLE_MAP[v]
            if "평지" in v or "중" in v:
                return "선입"
    rs = _running_style(horse)                            # pastRaces position 집계 폴백
    if rs:
        return _GAIT_STYLE_MAP.get(rs, "자유")
    # [수정2·한국 각질추론] styleType/position 없으면 KRA 이력 stOrd 패턴으로 추론(말 이름 기준·신뢰도 60%+만)
    _inf = _infer_gait_from_history(horse.get("name") or horse.get("hrName"))
    if _inf and _inf.get("conf", 0) >= 60:
        return _inf["gait"]
    return "자유"


def _pace_scenario(pace, counts, form, nH):
    """[6] 경주 전개 시나리오 텍스트(리스트)."""
    lines = ["선행 %d · 선입 %d · 추입 %d%s" % (counts["선행"], counts["선입"], counts["추입"],
             (" · 자유 %d" % counts["자유"]) if counts["자유"] else "")]
    if pace == "빠른":
        lines.append("선행 %d두 경합 → 빠른 페이스" % counts["선행"])
        lines.append("3코너 선행 탈진 → 추입 기회")
    elif pace == "느린":
        lines.append("선행 %d두 → 느린 페이스" % counts["선행"])
        lines.append("선행 독주 가능 → 앞선 말 유리")
    else:
        lines.append("선행 %d두 → 보통 페이스(뚜렷한 유불리 없음)" % counts["선행"])
    return lines


def _apply_pace_analysis(form, horse_count=None):
    """[2~7] form 각질 편성 분석 → 페이스 예측 + 각질별 유불리 보정(paceBonus 가산·무삭제).
    각 말에 gait·paceBonus·paceDetail 추가. 반환 {counts, pace, paceLabel, focus, scenario, advice}."""
    if not form:
        return None
    nH = horse_count or len(form)
    counts = {"선행": 0, "선입": 0, "추입": 0, "자유": 0}
    for h in form:
        g = _gait_of(h)
        h["gait"] = g
        counts[g] = counts.get(g, 0) + 1
    lead = counts["선행"]
    pace = "빠른" if lead >= 3 else ("느린" if lead <= 1 else "보통")           # [2] 페이스 예측
    _base = {
        "빠른": {"선행": -10, "선입": 5, "추입": 15, "자유": 0},                  # [3] 빠른→추입 유리
        "느린": {"선행": 10, "선입": 5, "추입": -10, "자유": 0},                  # [3] 느린→선행 유리
        "보통": {"선행": 0, "선입": 0, "추입": 0, "자유": 0},
    }[pace]
    focus = []
    for h in form:
        g = h["gait"]
        b, det = _base.get(g, 0), []
        if b:
            det.append("%s페이스·%s %s%d" % (pace, g, "+" if b > 0 else "", b))
        is_a = str(h.get("grade") or "").upper() == "A"
        if is_a and g == "추입" and pace == "빠른":                              # [4] A급 추입·빠른페이스
            b += 10; det.append("💡 A급 추입마 빠른페이스 유리 +10")
        elif is_a and g == "선행" and pace == "빠른":                            # [4] A급 선행·경합위험
            b -= 5; det.append("⚠️ A급 선행마 경합 위험 -5")
        no = _to_int(h.get("no"))
        if no is not None:                                                       # [5] 마번+각질
            inner, outer = no <= 3, no >= max(8, nH - 2)
            if g == "추입" and inner:
                b -= 5; det.append("추입·안쪽마번 포위 위험 -5")
            elif g == "추입" and outer:
                b += 5; det.append("추입·바깥마번 자유추입 +5")
            elif g == "선행" and inner:
                b += 5; det.append("선행·안쪽마번 인코스 유리 +5")
        h["paceBonus"] = b
        h["paceDetail"] = det
        h["totalScore"] = round((h.get("totalScore") or 0) + b, 1)               # 편성 보정 점수 반영
        if det:
            h["detail"] = (h.get("detail") or []) + det
        if b >= 15:
            focus.append({"no": no, "gait": g, "bonus": b, "grade": h.get("grade")})
    _label = {"빠른": "⚡ 빠른 페이스", "느린": "🐌 느린 페이스", "보통": "보통 페이스"}[pace]
    _advice = {"빠른": "추입마 유리 · 선행마 주의", "느린": "선행마 유리 · 추입마 주의", "보통": "뚜렷한 유불리 없음"}[pace]
    gait_lists = {"선행": [], "선입": [], "추입": [], "자유": []}       # [시나리오B] 각질별 마번 목록
    for h in form:
        _n = _to_int(h.get("no"))
        if _n is not None:
            gait_lists.setdefault(h.get("gait"), []).append(_n)
    return {"counts": counts, "pace": pace, "paceLabel": _label, "advice": _advice,
            "focus": sorted(focus, key=lambda x: -x["bonus"])[:3], "gaitLists": gait_lists,
            "scenario": _pace_scenario(pace, counts, form, nH)}


# ══════════ [작업1·일본경마 전개 시뮬레이션 2026-07-18] ══════════
#   한국경마(_simulate_race_flow_kra: KRA 구간지수)에 대응하는 일본경마판.
#   입력: oddspark 전적(form) — 각질(styleType→_gait_of)·상3F(last3f)·뒷심(backPower)·단승배당(winOdds).
#   ⚠ 기존 각질편성(_apply_pace_analysis)·form 점수 반영은 그대로 유지. 이 함수는 '패널 표시용 전개 예측(jpFlowSim)'만 추가 산출.
def _simulate_race_flow_keirin(horses, line=None, tendency=None, valid_nos=None, win_odds=None):
    """[경륜 특화①②·전개 시뮬레이션 (2026-07-19)] oddspark 출마표 전적(styleType·득점·결정수비율)과
    라인(並び)·경륜장 결정수 경향으로 경륜 전용 전개 예측 — 한국(_simulate_race_flow_kra)·
    일본경마(_simulate_race_flow_jp)와 동형 구조.
      ▸ 라인 그룹: 출마표 라인 순서에서 자력형(선행형/젖히기형) 선수마다 새 그룹 시작(선두=자력·뒤=마크) 휴리스틱.
      ▸ 페이스: 선행형 3명+ = 주도권 경합(소모전→젖히기·추입 유리) / 1명 = 단독 선행(그 라인 절대 유리).
      ▸ 라인 페어: 각 라인 (선두, 2번수) 복승 페어 — 경륜 동반 입상의 핵심(linePairs로 추천 반영).
      ▸ 경륜장 경향: 직근 1년 결정수 비율(도주/젖히기/차입) 최다 유형과 부합하는 각질 강조.
    반환 {pace, leadCount, lineGroups, linePairs, favoredHorses, darkHorses, note, text} 또는 None."""
    try:
        hs = [h for h in (horses or []) if h.get("no") is not None]
        if valid_nos:
            hs = [h for h in hs if int(h["no"]) in valid_nos] or hs
        if len(hs) < 3:
            return None
        by_no = {int(h["no"]): h for h in hs}
        style_of = {int(h["no"]): str(h.get("styleType") or "") for h in hs}
        leaders = [n for n, s in style_of.items() if "선행" in s]
        makuri = [n for n, s in style_of.items() if "젖히기" in s]
        chasers = [n for n, s in style_of.items() if ("추입" in s or "마크" in s)]
        lead_n = len(leaders)
        # ── 라인 그룹(휴리스틱: 라인 순서에서 자력형마다 새 그룹) ──
        groups = []
        seq = [int(x) for x in (line or []) if int(x) in by_no]
        if seq:
            cur = []
            for n in seq:
                if ("선행" in style_of.get(n, "") or "젖히기" in style_of.get(n, "")) and cur:
                    groups.append(cur)
                    cur = [n]
                else:
                    cur.append(n)
            if cur:
                groups.append(cur)
            in_line = set(seq)
            for n in by_no:
                if n not in in_line:
                    groups.append([n])                     # 라인 밖 = 단기(단독)
        else:
            groups = [[n] for n in by_no]                  # 라인 정보 없음 → 전원 단기 취급
        # 그룹 정렬: 선두 선수 총점 높은 라인부터
        def _gscore(g):
            return by_no.get(g[0], {}).get("totalScore") or 0
        groups.sort(key=_gscore, reverse=True)
        # ── 페이스 판단 ──
        if lead_n >= 3:
            pace, pace_note = "하이(주도권 경합)", "선행형 %d명 주도권 소모전 → 젖히기·추입 유리" % lead_n
            favored = sorted(makuri + chasers, key=lambda n: by_no[n].get("totalScore") or 0, reverse=True)[:3]
        elif lead_n == 1:
            _ld = leaders[0]
            _grp = next((g for g in groups if _ld in g), [_ld])
            pace, pace_note = "슬로우(단독 선행)", "%d번 단독 선행 — 그 라인 절대 유리" % _ld
            favored = ([_ld] + [n for n in _grp if n != _ld])[:3]
        else:
            pace, pace_note = "보통", "선행형 %d명 — 라인·득점 우위가 관건" % lead_n
            favored = sorted(by_no, key=lambda n: by_no[n].get("totalScore") or 0, reverse=True)[:3]
        # ── 경륜장 경향 결합 ──
        tend_note = ""
        td = tendency or {}
        if td:
            _fav_style = max(td, key=td.get)
            tend_note = "이 경륜장 직근 1년 '%s' 결정 %.0f%%" % (_fav_style, td[_fav_style])
            _match = {"도주": leaders, "젖히기": makuri, "차입": chasers}.get(_fav_style) or []
            for n in sorted(_match, key=lambda n: by_no[n].get("totalScore") or 0, reverse=True):
                if n not in favored:
                    favored = (favored + [n])[:4]
                    break
        # ── 라인 페어(선두+2번수 복승) ──
        line_pairs = []
        for g in groups:
            if len(g) >= 2:
                line_pairs.append({"combo": [g[0], g[1]],
                                   "label": "라인 페어(%d번 %s + %d번 마크)"
                                            % (g[0], style_of.get(g[0], "자력"), g[1])})
        # ── 복병: 하위 랭크지만 연대율/결정수 우수 + 페이스 부합 ──
        ranked = sorted(by_no, key=lambda n: by_no[n].get("totalScore") or 0, reverse=True)
        darks = []
        for n in ranked[3:]:
            h = by_no[n]
            kr = h.get("kimariteRatio") or {}
            if (h.get("rentai") or 0) >= 50 or (lead_n >= 3 and (kr.get("차입", 0) + kr.get("젖히기", 0)) >= 50):
                darks.append(n)
        text = " · ".join(x for x in [pace_note, tend_note] if x)
        return {"pace": pace, "leadCount": lead_n, "lineGroups": groups, "linePairs": line_pairs,
                "favoredHorses": favored, "darkHorses": darks[:2], "note": pace_note,
                "tendencyNote": tend_note, "text": text}
    except Exception as _ke:
        print("[경륜 전개시뮬] 실패(무시):", _ke)
        return None


def _simulate_race_flow_jp(form, valid_nos=None, win_odds=None):
    """[일본경마 전개 시뮬레이션] 각질·상3F로 선행경합→페이스→유리한 말→고배당 복병 예측.
    _simulate_race_flow_kra 와 동일 출력 구조(jpFlowSim). form 없으면 None(조용히 스킵)."""
    if not form:
        return None
    vs = set()
    for n in (valid_nos or []):
        try: vs.add(int(n))
        except (TypeError, ValueError): pass
    rows = [h for h in form if isinstance(h, dict) and h.get("no") is not None
            and (not vs or int(h.get("no")) in vs)]
    if not rows:
        return None

    def _g(h):
        try: return h.get("gait") or _gait_of(h)
        except Exception: return h.get("gait") or "자유"
    # 선행 경합 후보(각질=선행)
    lead = sorted(int(h["no"]) for h in rows if _g(h) == "선행")
    lead_count = len(lead)
    if lead_count >= 3:
        pace, pace_reason, favor = "하이페이스", "선행 %d두 경합 → 초반 빠름 → 추입 유리" % lead_count, "추입"
    elif lead_count <= 1:
        pace, pace_reason, favor = "슬로우페이스", "선행 %d두 → 초반 느림 → 선행·선입 유지 유리" % lead_count, "선행"
    else:
        pace, pace_reason, favor = "미들페이스", "선행 2두 → 표준 전개", None
    favored, dark = [], []
    for h in rows:
        no = int(h["no"]); g = _g(h)
        bp = h.get("backPower")                       # 상3F 상대 뒷심(강/보통/약)
        odds = h.get("winOdds")
        reasons, score = [], 0
        if favor == "추입" and g in ("추입", "선입"):
            score += 15; reasons.append("추입력(빠른페이스 유리)")
        if favor == "추입" and bp == "강":
            score += 10; reasons.append("상3F 상위(막판 스피드)")
        if favor == "선행" and g == "선행":
            score += 15; reasons.append("선행력(느린페이스 유리)")
        if bp == "강" and pace == "하이페이스" and "상3F 상위(막판 스피드)" not in reasons:
            score += 5; reasons.append("뒷심 강")
        if score <= 0:
            continue
        it = {"no": no, "gait": g, "backPower": bp, "odds": odds, "score": score, "reasons": reasons}
        # 단승 15배+ = 복병(dark), 그 미만 = 유력마(favored). 단승 미수집이면 favored 로.
        if isinstance(odds, (int, float)) and odds >= 15:
            dark.append(it)
        else:
            favored.append(it)
    favored.sort(key=lambda x: -x["score"])
    dark.sort(key=lambda x: -x["score"])
    if not favored and not dark:
        return None
    text = [pace_reason]
    if favored:
        text.append("유력: " + ", ".join("%d번(%s)" % (f["no"], "·".join(f["reasons"])) for f in favored[:3]))
    if dark:
        text.append("복병: " + ", ".join("%d번(%s%s)" % (d["no"], "·".join(d["reasons"]),
                    ("·%s배" % d["odds"]) if isinstance(d["odds"], (int, float)) else "") for d in dark[:2]))
    return {"pace": pace, "paceReason": pace_reason, "leadCount": lead_count, "leadContenders": lead,
            "favoredHorses": favored[:5], "darkHorses": dark[:5],
            "note": "%s · %s" % (pace, pace_reason), "text": text, "source": "oddspark전적(각질·상3F)"}


# ── 3-2c 거리 변화 보너스 [3] ──────────────────
def distance_change_bonus(horse, race, style=None):
    """이번 거리 vs 직전 경주 거리. 단축=스피드 유리 +5, 연장=추격형 +3·선행형 -3·미상 적성체크."""
    rdist = _to_int(race.get("distance"))
    prs = horse.get("pastRaces") or []
    last_d = _to_int(prs[0].get("distance")) if prs else None
    if rdist is None or last_d is None or rdist == last_d:
        return 0, []
    if rdist < last_d:
        return 5, [f"거리단축({last_d}→{rdist}m·스피드유리)+5"]
    if style == "추격형":
        return 3, [f"거리연장({last_d}→{rdist}m·추격형적성)+3"]
    if style == "선행형":
        return -3, [f"거리연장({last_d}→{rdist}m·선행형스태미너주의)-3"]
    return 0, [f"거리연장({last_d}→{rdist}m·적성체크)"]


# ── 3-3b 기수 교체 보너스 [4] ──────────────────
def _leader_jockeys(jstats, top_frac=0.2):
    """jockeyStats(이름→통계)에서 복승권율(placeRate) 상위 top_frac 기수명 set."""
    rated = [(n, s.get("placeRate")) for n, s in (jstats or {}).items()
             if isinstance(s, dict) and isinstance(s.get("placeRate"), (int, float)) and s.get("rides", 0)]
    if not rated:
        return set()
    rates = sorted((r for _, r in rated), reverse=True)
    k = max(1, int(len(rates) * top_frac))
    thresh = rates[k - 1]
    return {n for n, r in rated if r >= thresh}


def jockey_change_bonus(horse, leader_names, rate_fn=None):
    """[1] 기수 교체 감지. 직전 기수 vs 이번 기수.
    ▸ rate_fn(기수명→복승률) 제공 시 복승률 기반 판정 우선: 일반→상위(30%+) +15 / 상위→일반(10%↓) -10.
    ▸ rate_fn 없거나 판정 불가 시 기존 리딩기수 set 방식(무삭제) — 리딩 상향 +15 / 하향 -10.
    ▸ 첫 기승(직전 기수 미상=이 말 첫 조합) → 중립 '첫 기승 주목'. 동일 기수 → 0."""
    cur = str(horse.get("jockey", "")).strip()
    prs = horse.get("pastRaces") or []
    last_j = str((prs[0].get("jockey") or "")).strip() if prs else str(horse.get("lastJockey") or "").strip()
    if not cur:
        return 0, []
    if not last_j:                                       # 직전 기수 미상 = 이 말+기수 첫 조합
        return 0, ["첫 기승 주목"]
    if cur == last_j:
        return 0, []
    # [확장·복승률 기반] rate_fn 으로 상위(30%+)/하위(10%↓) 판정
    if rate_fn is not None:
        cr, lr = rate_fn(cur), rate_fn(last_j)
        if isinstance(cr, (int, float)) and isinstance(lr, (int, float)) and (cr > 0 or lr > 0):
            if cr >= 30 and lr < 30:
                return 15, [f"⚡ 기수 교체! {last_j}→{cur} (승부의지 상향·복승률 {cr:.0f}%) +15"]
            if lr >= 30 and cr <= 10:
                return -10, [f"⚠️ 기수 하향 교체 {last_j}→{cur} (복승률 {lr:.0f}%→{cr:.0f}%) -10"]
    # [기존·리딩기수 set] rate_fn 없거나 판정 불가 시(무삭제)
    ln = leader_names or set()
    if cur in ln and last_j not in ln:
        return 15, [f"⚡ 기수 교체! {last_j}→{cur} (리딩기수 상향) +15"]
    if last_j in ln and cur not in ln:
        return -10, [f"⚠️ 기수 하향 교체({last_j}→{cur}) -10"]
    return 0, [f"기수 교체({last_j}→{cur})"]


# ── 3-4b 부담중량 변화 보너스 [5] ──────────────
def weight_change_bonus(horse):
    """이번 부담중량 vs 직전. 증가 -5, 감소 +5, 동일/미상 0. (부담중량=핸디캡, 마체중과 별개)"""
    cur = _to_int(horse.get("weight"))
    prs = horse.get("pastRaces") or []
    last_w = _to_int(prs[0].get("weight")) if prs else _to_int(horse.get("lastWeight"))
    if cur is None or last_w is None or cur == last_w:
        return 0, []
    if cur > last_w:
        return -5, [f"부담중량 증가({last_w}→{cur}kg)-5"]
    return 5, [f"부담중량 감소({last_w}→{cur}kg)+5"]


def _parse_body_weight(bw):
    """마체중 표기('486(-4)'·'486kg'·486) → 정수 kg. 괄호 안 증감은 무시(절대값만). 실패 None."""
    if bw is None:
        return None
    m = re.search(r"(\d{3})", str(bw))       # 지방경마 마체중은 통상 3자리(300~600kg)
    return int(m.group(1)) if m else None


def body_weight_change_bonus(cur_bw, past):
    """[마체중 변화·신규] 이번 마체중(cur_bw) vs 직전 경주 마체중.
    감소 2kg+ → +5(조정 호조·군살 빠짐) · 증가 4kg+ → -5(과체중·컨디션 난조) · 그 외 0.
    ⚠ 부담중량(핸디캡)과 별개인 '말 체중'. cur_bw 없으면 전적 최근 마체중으로 추세만 참고.
    반환 (bonus, detail[list], curKg)."""
    cur = _parse_body_weight(cur_bw)
    last = None
    for pr in (past or []):
        v = _parse_body_weight(pr.get("bodyWeight"))
        if v is not None:
            last = v
            break
    if cur is None or last is None:
        return 0, [], cur
    diff = cur - last
    if diff <= -2:
        return 5, [f"마체중 {diff}kg({last}→{cur}) 조정 호조 +5"], cur
    if diff >= 4:
        return -5, [f"마체중 +{diff}kg({last}→{cur}) 과체중 -5"], cur
    return 0, ([f"마체중 {diff:+d}kg({last}→{cur})"] if diff else [f"마체중 유지({cur}kg)"]), cur


# ── 3-3c 경마 등급 체계 보정 [2번] ──────────────
def _norm_grade(g):
    """등급명 정규화: 로마숫자→아라비아, 공백 제거, 대문자. 'GⅢ'/'G III'→'G3'."""
    s = str(g or "").upper().replace(" ", "").replace("　", "")
    s = s.replace("GⅢ", "G3").replace("GⅡ", "G2").replace("GⅠ", "G1")
    s = s.replace("GIII", "G3").replace("GII", "G2").replace("GI", "G1")
    s = s.replace("ＧⅢ", "G3").replace("ＧⅡ", "G2").replace("ＧⅠ", "G1")
    return s


# 등급 경험 보너스: 문자열에 토큰 포함 시 해당 보너스(최상위 하나만 적용). 상위→하위 순.
_GRADE_EXP_TIERS = [
    (("G1", "G2", "G3"), 20, "그레이드(G1~G3) 경험"),   # JRA 중상금 / KRA 그레이드 대상경주
    (("A1",), 20, "A1 경험"),                             # NAR A1
    (("A2",), 15, "A2 경험"),                             # NAR A2
    (("오픈", "OP", "オープン", "リステッド", "LISTED", "L"), 10, "오픈/리스티드 경험"),
    (("B1", "B2"), 10, "B급 경험"),                       # NAR B
    (("C1",), 5, "C1 경험"),                              # NAR C1
]
# 등급 랭크(작을수록 상위·강함) — 하락/상승 판정용. 상위 토큰 먼저.
_GRADE_RANK_TIERS = [
    ("G1", 1), ("G2", 2), ("G3", 3),
    ("A1", 2), ("A2", 3),
    ("오픈", 4), ("OP", 4), ("オープン", 4), ("リステッド", 4), ("LISTED", 4), ("L", 4),
    ("B1", 5), ("B2", 6),
    ("국1군", 5), ("1군", 5), ("국2군", 6), ("2군", 6), ("국3군", 7), ("3군", 7),
    ("국4군", 8), ("4군", 8), ("국5군", 9), ("5군", 9), ("국6군", 9), ("6군", 9),
    ("3勝", 5), ("2勝", 6), ("1勝", 7), ("未勝", 9), ("新馬", 9),
    ("C1", 7), ("C2", 8), ("C3", 8),
]


def _grade_exp_bonus_of(g):
    s = _norm_grade(g)
    if not s:
        return 0, ""
    for toks, bonus, label in _GRADE_EXP_TIERS:
        if any(_norm_grade(t) in s for t in toks):
            return bonus, label
    return 0, ""


def _grade_rank(g):
    s = _norm_grade(g)
    if not s:
        return None
    for tok, rk in _GRADE_RANK_TIERS:
        if _norm_grade(tok) in s:
            return rk
    return None


def grade_bonus(cur_grade, past_grades):
    """[2번] 등급 경험(최상위 하나) + 하락(상위→하위·강자 +15)/상승(하위→상위·적응중 -5).
    한국경마 G1~G3 +20·오픈 +10 / 지방 A1 +20·A2 +15·B +10·C1 +5. 반환 (bonus, detail)."""
    past = [g for g in (past_grades or []) if g]
    bonus, detail = 0, []
    exps = [_grade_exp_bonus_of(g) for g in past]
    best = max(exps, key=lambda x: x[0]) if exps else (0, "")
    if best[0] > 0:
        bonus += best[0]
        detail.append(f"{best[1]} +{best[0]}")
    cr = _grade_rank(cur_grade)
    lr = _grade_rank(past[0]) if past else None
    if cr is not None and lr is not None and cr != lr:
        if cr > lr:                      # rank 커짐 = 하위 등급으로 하락 = 상위에서 내려온 강자
            bonus += 15
            detail.append("✅ 강급 출전(상위→하위·강자) +15")   # [5] 승급전 감지·표시
        else:                            # 상위 등급으로 상승 = 적응 중
            bonus -= 5
            detail.append("⚠️ 승급전 첫 도전(하위→상위·적응중) -5")   # [5] 승급전 감지·표시
    return bonus, detail


# ── 3-3d 당거리 경험 [3번] ──────────────────
def dist_exp_bonus(past_races, cur_dist):
    """[3번] 당거리(정확히 같은 거리) 출전 경험. 있음 +10, 없음 0. 반환 (bonus, detail, experienced)."""
    cd = _to_int(cur_dist)
    if cd is None:
        return 0, [], None
    dists = [_to_int(pr.get("distance")) for pr in (past_races or [])]
    cnt = sum(1 for d in dists if d == cd)
    if cnt > 0:
        return 10, [f"당거리({cd}m) 경험 {cnt}회 +10"], True
    if any(d is not None for d in dists):
        return 0, [f"당거리({cd}m) 미경험"], False
    return 0, [], None


def dist_aptitude_bonus(past_races, cur_dist, tol=200):
    """[거리 적성·신규] 이번 경주 거리(±tol m 유사거리) 전적의 복승권율(1~3착 비율)로 적성 등급.
    적성 A(복승률 40%+) → +10 · 적성 C(복승률 10% 이하) → -5 · 그 외 0. 표본 3경주 미만이면 판단 보류(0).
    ⚠ dist_exp_bonus(경험 유무)와 별개 — 이건 '그 거리에서 실제로 잘 뛰었나'(성적). 반환 (bonus, detail, grade, rate)."""
    cd = _to_int(cur_dist)
    if cd is None:
        return 0, [], None, None
    hits = [pr for pr in (past_races or []) if _to_int(pr.get("distance")) is not None
            and abs(_to_int(pr.get("distance")) - cd) <= tol]
    placings = [pr.get("placing") for pr in hits if isinstance(pr.get("placing"), (int, float)) and pr["placing"] > 0]
    if len(placings) < 3:
        return 0, [], None, None
    rate = round(sum(1 for p in placings if p <= 3) / len(placings) * 100, 1)
    if rate >= 40:
        return 10, [f"{cd}m 적성 A급(복승률 {rate}%·{len(placings)}전) +10"], "A", rate
    if rate <= 10:
        return -5, [f"{cd}m 적성 C급(복승률 {rate}%·{len(placings)}전) -5"], "C", rate
    return 0, [f"{cd}m 적성 B급(복승률 {rate}%·{len(placings)}전)"], "B", rate


def bad_track_rate(past_races):
    """[불량주로 성적·신규] pastRaces 의 condition(주로: 무거움/불량) 경주 복승권율(1·2착 %) 계산.
    한국 PDF 전적의 condition 필드(양호/무거움/불량)에서 도출 → _weather_adjust_form 의 badTrackRate 입력.
    표본 2경주 미만이면 None(판단 보류·날씨 불량주로 보정 미적용). 양호 주로만 있으면 None."""
    placings = []
    for pr in past_races or []:
        cond = str(pr.get("condition") or "")
        if ("불량" in cond) or ("무거" in cond) or ("다습" in cond):
            p = pr.get("placing")
            if isinstance(p, (int, float)) and p > 0:
                placings.append(int(p))
    if len(placings) < 2:
        return None
    return round(sum(1 for p in placings if p <= 2) / len(placings) * 100, 1)


# ══════════════ [전적 확장 통계·신규] 기수-말 궁합·조교사 전략·마번 유불리 ══════════════
#   KRA 이력(kra_history.json·647경주+)을 한 번 스캔해 3종 통계 집계 → 분석 시 조회(mtime 캐시).
#   ⚠ 착순=rcTime 오름차순(KRA stOrd 는 게이트/출발위치라 착순 아님). 복승권=1·2착.
_FORM_EXT_STATS = None
_FORM_EXT_SRC_MTIME = None


def _kra_race_placings(race):
    """KRA 경주 1건 → rcTime 오름차순 착순 맵 {마번:착순}. rcTime 없는 말 제외."""
    rows = []
    for h in (race.get("horses") or []):
        sec = _kra_rctime_sec(h.get("rcTime"))
        no = h.get("no")
        if sec and no is not None:
            try:
                rows.append((int(no), float(sec)))
            except (TypeError, ValueError):
                pass
    rows.sort(key=lambda x: x[1])
    return {no: i + 1 for i, (no, _s) in enumerate(rows)}


def _date_diff_days(d1, d2):
    """'20260620' 형식 두 날짜의 일수 차(d2-d1). 파싱 실패 시 None."""
    try:
        import datetime as _dt
        a = _dt.date(int(d1[:4]), int(d1[4:6]), int(d1[6:8]))
        b = _dt.date(int(d2[:4]), int(d2[4:6]), int(d2[6:8]))
        return (b - a).days
    except Exception:
        return None


def _form_ext_build():
    """KRA 이력 스캔 → {synergy, trainer, postPos} 통계. 표본 하한 적용(궁합2·조교사5·마번5)."""
    hist = _kra_load_history() or {}
    races = hist.get("races") or {}
    synergy, trainer, postpos, gait_rel = {}, {}, {}, {}
    horse_last_date, horse_trainer = {}, {}
    ordered = sorted(races.values(), key=lambda r: str(r.get("date") or ""))
    for r in ordered:
        meet = r.get("meet")
        date = str(r.get("date") or "")
        pl = _kra_race_placings(r)
        _nfield = len(r.get("horses") or [])                     # [각질추론] 두수(상대위치 계산용)
        if not pl:
            continue
        for h in (r.get("horses") or []):
            no = h.get("no")
            if no is None:
                continue
            try:
                no = int(no)
            except (TypeError, ValueError):
                continue
            rank = pl.get(no)
            if rank is None:
                continue
            jk = str(h.get("jkName") or "").strip()
            hr = str(h.get("hrName") or "").strip()
            tr = str(h.get("trName") or "").strip()
            # [각질추론] stOrd(초반 통과순위)/두수 = 상대위치(0~1). 낮으면 앞(선행)·높으면 뒤(추입)
            if hr and h.get("stOrd") is not None and _nfield > 1:
                try:
                    gait_rel.setdefault(hr, []).append(float(h["stOrd"]) / _nfield)
                except (TypeError, ValueError):
                    pass
            if jk and hr:                                        # [2] 기수-말 궁합
                synergy.setdefault(jk + "|" + hr, []).append(rank)
            if tr:                                               # [3] 조교사 전체 + 출전간격버킷
                t = trainer.setdefault(tr, {"pl": [], "gap": {}})
                t["pl"].append(rank)
                if hr:
                    gap = _date_diff_days(horse_last_date.get(hr, ""), date) if horse_last_date.get(hr) and date else None
                    if gap is not None and gap >= 0:
                        bk = "le7" if gap <= 7 else ("le14" if gap <= 14 else ("le21" if gap <= 21 else "gt21"))
                        t["gap"].setdefault(bk, []).append(rank)
            if meet is not None:                                 # [4] 마번(경주장별)
                postpos.setdefault(str(meet) + "|" + str(no), []).append(rank)
            if hr and tr:                                         # 말→최근 조교사(날짜순 마지막=최근)
                horse_trainer[hr] = tr
            if hr and date:
                horse_last_date[hr] = date

    def _rate(pls):
        n = len(pls)
        return {"rate": round(sum(1 for p in pls if p <= 2) / n * 100, 1), "n": n} if n else None
    out = {"synergy": {}, "trainer": {}, "postPos": {}, "postPosBase": {}, "horseTrainer": horse_trainer}
    for k, v in synergy.items():
        if len(v) >= 2:
            out["synergy"][k] = _rate(v)
    for k, v in trainer.items():
        if len(v["pl"]) >= 5:
            rec = _rate(v["pl"])
            rec["byGap"] = {bk: _rate(pls) for bk, pls in v["gap"].items() if len(pls) >= 3}
            out["trainer"][k] = rec
    # 마번: 경주장별 마번 복승률 + 경주장 평균(기준선) → 유불리는 편차로 판단
    meet_all = {}
    for k, v in postpos.items():
        if len(v) >= 5:
            out["postPos"][k] = _rate(v)
        m = k.split("|")[0]
        meet_all.setdefault(m, []).extend(v)
    for m, v in meet_all.items():
        if v:
            out["postPosBase"][m] = round(sum(1 for p in v if p <= 2) / len(v) * 100, 1)
    # [각질추론] 말별 stOrd 상대위치 평균 → 각질(선행≤0.35·추입≥0.60·선입) + 일관성 신뢰도. kra_horse_gait.json 저장.
    out["gait"] = {}
    for hr, rels in gait_rel.items():
        if len(rels) < 3:
            continue
        avg = sum(rels) / len(rels)
        var = sum((x - avg) ** 2 for x in rels) / len(rels)
        conf = max(40, min(95, int(90 - var * 200)))            # 일관성 클수록(분산 작을수록) 신뢰도↑
        g = "선행" if avg <= 0.35 else ("추입" if avg >= 0.60 else "선입")
        out["gait"][hr] = {"gait": g, "conf": conf, "n": len(rels)}
    try:
        json.dump(out["gait"], open(KRA_GAIT_FILE, "w", encoding="utf-8"), ensure_ascii=False)
    except Exception as e:
        print("[한국각질추론] 저장 실패:", e)
    return out


def _infer_gait_from_history(horse_name):
    """[한국 각질 추론] KRA 이력 stOrd(초반위치) 패턴 → 각질+신뢰도. 반환 {gait, conf, n} 또는 None."""
    return (_form_ext_stats().get("gait") or {}).get(str(horse_name or "").strip())


def _form_ext_stats():
    """캐시된 전적 확장 통계 반환(kra_history mtime 변경 시 자동 재빌드)."""
    global _FORM_EXT_STATS, _FORM_EXT_SRC_MTIME
    try:
        mt = os.path.getmtime(KRA_HISTORY_FILE) if os.path.exists(KRA_HISTORY_FILE) else 0
    except Exception:
        mt = 0
    if _FORM_EXT_STATS is None or _FORM_EXT_SRC_MTIME != mt:
        try:
            _FORM_EXT_STATS = _form_ext_build()
            _FORM_EXT_SRC_MTIME = mt
        except Exception as e:
            print("[전적확장통계] 빌드 실패:", e)
            _FORM_EXT_STATS = _FORM_EXT_STATS or {"synergy": {}, "trainer": {}, "postPos": {}, "postPosBase": {}, "gait": {}}
    return _FORM_EXT_STATS


def jockey_horse_synergy_bonus(jockey, horse_name):
    """[2] 기수-말 궁합 — KRA 이력 조합 복승권율. A(40%+)+15 / B(20~40%)+5 / C(20%↓)-5 / 첫기승 표시.
    반환 (bonus, detail, grade, rate). 표본 없으면 첫 기승(중립)."""
    jk = str(jockey or "").strip()
    hr = str(horse_name or "").strip()
    if not jk or not hr:
        return 0, [], None, None
    rec = (_form_ext_stats().get("synergy") or {}).get(jk + "|" + hr)
    if not rec:
        return 0, ["첫 기승 주목(궁합 데이터 없음)"], "첫기승", None
    rt, n = rec["rate"], rec["n"]
    if rt >= 40:
        return 15, [f"기수·말 궁합 A급(복승률 {rt}%·{n}회) +15"], "A", rt
    if rt >= 20:
        return 5, [f"기수·말 궁합 B급(복승률 {rt}%·{n}회) +5"], "B", rt
    return -5, [f"기수·말 궁합 C급(복승률 {rt}%·{n}회) -5"], "C", rt


def trainer_strategy_ctx(trainer, gap_days=None):
    """[3] 조교사 전략 — 조교사 전체 복승률 + (있으면) 출전간격버킷 복승률. 표시용 컨텍스트 반환.
    반환 {rate, n, gapRate, gapLabel} 또는 None(데이터 없음)."""
    tr = str(trainer or "").strip()
    if not tr:
        return None
    rec = (_form_ext_stats().get("trainer") or {}).get(tr)
    if not rec:
        return None
    ctx = {"rate": rec["rate"], "n": rec["n"], "gapRate": None, "gapLabel": None}
    if gap_days is not None:
        bk = "le7" if gap_days <= 7 else ("le14" if gap_days <= 14 else ("le21" if gap_days <= 21 else "gt21"))
        g = (rec.get("byGap") or {}).get(bk)
        if g:
            _lab = {"le7": "7일 이내", "le14": "14일", "le21": "21일", "gt21": "21일+"}[bk]
            ctx["gapRate"], ctx["gapLabel"] = g["rate"], _lab
    return ctx


def post_position_ctx(meet, no):
    """[4] 마번 유불리 — 경주장별 마번 복승률 vs 경주장 평균 편차. 반환 {rate, base, delta, n} 또는 None."""
    if meet is None or no is None:
        return None
    st = _form_ext_stats()
    rec = (st.get("postPos") or {}).get(str(meet) + "|" + str(no))
    base = (st.get("postPosBase") or {}).get(str(meet))
    if not rec or base is None:
        return None
    return {"rate": rec["rate"], "base": base, "delta": round(rec["rate"] - base, 1), "n": rec["n"]}


# ── 3-3e 뒷힘(상승3F) [3번] ──────────────────
def back_power_bonus(my_last3f, all_last3f):
    """[3번] 상승3F(막판 뒷힘). 경주 내 상대: 상위30%(빠름) +15, 하위30%(느림) -5, 보통 0.
    상3F는 작을수록 빠름(강함). 반환 (bonus, detail, level: 강/보통/약/None)."""
    if not isinstance(my_last3f, (int, float)) or my_last3f <= 0:
        return 0, [], None
    vals = sorted(v for v in (all_last3f or []) if isinstance(v, (int, float)) and v > 0)
    if len(vals) < 3:
        return 0, [], None
    p30 = vals[max(0, int(0.3 * (len(vals) - 1)))]        # 빠른 쪽 30% 경계
    p70 = vals[min(len(vals) - 1, int(0.7 * (len(vals) - 1)))]
    if my_last3f <= p30:
        return 15, [f"뒷힘 강점(상3F {my_last3f}초·상위30%) +15"], "강"
    if my_last3f >= p70:
        return -5, [f"막판 둔화(상3F {my_last3f}초·하위30%) -5"], "약"
    return 0, [f"상3F {my_last3f}초(보통)"], "보통"


# ── 2-1 고배당 말 자동 제거 [1·5번] ──────────────
def _high_odds_verdict(win_odds, has_signal):
    """[1·5번] 단승 배당 기준 고배당 제거. 999=무조건 / 100배+=확실 / 50~99=권장 / 30~49=신호없으면 제거.
    반환 (force_cut, reason). 이변 신호(급락·쌍승상위) 있으면 30~99배 구간은 제거 보류(999·100+는 무조건)."""
    if not isinstance(win_odds, (int, float)) or win_odds <= 0:
        return False, ""
    if win_odds >= 999:
        return True, "단승 999배 → 무조건 제거(전적 무관)"
    if win_odds >= 100:
        return True, "단승 100배+ → 확실 제거"
    if win_odds >= 50:
        return (not has_signal), "단승 50~99배 → 제거 권장"
    if win_odds >= 30:
        return (not has_signal), "단승 30~49배 → 관찰(신호 없으면 제거)"
    return False, ""


# ── 3-4 특수 플래그 ──────────────────────
def special_flags(horse, race):
    """동일거리 2착 2회↑ → 삼복승필수 / 마체중 ±10kg↑ 경고 / 출전간격 3주↑ 주의 / 연속출전 피로도."""
    flags = []
    rdist = _to_int(race.get("distance"))
    if rdist is not None:
        cnt = sum(1 for pr in (horse.get("pastRaces") or [])
                  if _to_int(pr.get("distance")) == rdist and _to_int(pr.get("placing")) == 2)
        if cnt >= 2:
            flags.append({"type": "삼복승필수", "level": "must",
                          "msg": f"동일거리({rdist}m) 2착 {cnt}회 → 삼복승 필수 포함"})
    cw, lw = _to_int(horse.get("currentWeight")), _to_int(horse.get("lastWeight"))
    if cw is not None and lw is not None and abs(cw - lw) >= 10:
        flags.append({"type": "마체중급변", "level": "warn",
                      "msg": f"마체중 전경주 대비 {cw - lw:+d}kg (±10kg↑) 경고"})
    days = _to_int(horse.get("daysSinceLast"))
    if days is not None and days >= 21:
        flags.append({"type": "장기간격", "level": "caution",
                      "msg": f"출전 간격 {days}일(3주↑) 주의"})
    consec = _to_int(horse.get("consecutiveRuns"))
    if consec is not None and consec >= 2:
        flags.append({"type": "피로도", "level": "warn",
                      "msg": f"{consec}연전 연속 출전 → 피로도 경고"})
    return flags


# ── 3-5 등급 분류 + Phase 2 이상감지 보정 ──
GRADES = ["A", "B", "C", "D"]


def _upgrade(grade):
    i = GRADES.index(grade)
    return GRADES[max(0, i - 1)]


def classify_grades(scored):
    """totalScore 사분위로 A/B/C/D(상위25/50/75%) 부여 후, 이상감지로 보정.
    🔴(signalScore≥75) → 1단계 상향 / 급락 50%↑ → 삼복승 보험 강제 플래그."""
    order = sorted(scored, key=lambda h: h["totalScore"], reverse=True)
    n = len(order)
    for rank, h in enumerate(order):
        frac = rank / n if n else 0
        h["grade"] = "A" if frac < 0.25 else "B" if frac < 0.50 else "C" if frac < 0.75 else "D"
        h["gradeBase"] = h["grade"]
        an = h.get("anomaly") or {}
        sig = an.get("signalScore")
        drop = an.get("drop")
        if isinstance(sig, (int, float)) and sig >= 75:
            h["grade"] = _upgrade(h["grade"])
            if h["grade"] != h["gradeBase"]:
                h.setdefault("flags", []).append(
                    {"type": "이상감지상향", "level": "info",
                     "msg": f"🔴 이상감지(신호 {sig}) → {h['gradeBase']}→{h['grade']} 상향"})
        if isinstance(drop, (int, float)) and drop >= 0.50:
            h.setdefault("flags", []).append(
                {"type": "삼복승보험강제", "level": "must",
                 "msg": f"🔴 배당 급락 {round(drop * 100)}% → 삼복승 보험 강제 추가"})
    return scored


def score_horses_raw(race, horses, jockey_threshold=None, leader_names=None):
    """3-1~3-4: 마필별 baseScore/courseBonus/jockeyBonus/distanceBonus/jockeyChangeBonus/
    weightBonus/runningStyle/totalScore + flags (등급 전 단계).
    거리·기수교체·부담중량 보너스는 pastRaces 가 있을 때만 값이 생기고, 없으면 0 → 기존 동작 그대로."""
    if jockey_threshold is None:
        jockey_threshold = top20_threshold([h.get("jockey3mPlaceRate") for h in horses])
    # [전적확장·신규] 경주장(meet) 도출(마번 유불리용) + KRA 이력 통계(궁합·조교사·마번)
    _meet = race.get("meet")
    if _meet is None:
        _mt = _area_num(str(race.get("track") or race.get("venue") or race.get("raceKey") or ""))
        _meet = {"서울": 1, "제주": 2, "부산": 3, "부경": 3}.get(_mt[0] if _mt else "", None)
    _ext = _form_ext_stats()
    _htr = _ext.get("horseTrainer") or {}
    scored = []
    for h in horses:
        placings = _placings_of(h)
        base = base_form_score(placings)
        cb, cd = course_aptitude_bonus(h.get("pastRaces"), race)
        jb, jd = jockey_bonus(h, jockey_threshold)
        style = _running_style(h)                              # [2] 각질 추정
        db_, dd = distance_change_bonus(h, race, style)        # [3] 거리 변화
        kb, kd = jockey_change_bonus(h, leader_names, rate_fn=_jockey_place_rate)   # [1] 기수 교체(복승률 기반)
        wb, wd = weight_change_bonus(h)                        # [5] 부담중량 변화
        # [등급/당거리 보정] 등급 경험·하락강자 + 당거리 정확경험(뒷힘은 상3F 있는 지방/중앙 build_form 에서)
        past_grades = [pr.get("grade") for pr in (h.get("pastRaces") or [])]
        gb, gd = grade_bonus(h.get("grade") or race.get("grade"), past_grades)   # [2·5] 등급 체계+승급전
        deb, ded, dexp = dist_exp_bonus(h.get("pastRaces"), race.get("distance"))  # [3] 당거리 경험
        # [2·신규] 기수-말 궁합 / [3] 조교사 전략 / [4] 마번 유불리 (KRA 이력 기반·한국경마)
        _nm = h.get("name", "")
        syn_b, syn_d, syn_g, syn_r = jockey_horse_synergy_bonus(h.get("jockey"), _nm)
        _trn = h.get("trainer") or _htr.get(_nm)
        _trctx = trainer_strategy_ctx(_trn)
        tr_b, tr_d = 0, []
        if _trctx:
            if _trctx["rate"] >= 40:
                tr_b = 5; tr_d = [f"조교사 {_trn}: 복승률 {_trctx['rate']:.0f}% (우수) +5"]
            elif _trctx["rate"] <= 12:
                tr_b = -3; tr_d = [f"조교사 {_trn}: 복승률 {_trctx['rate']:.0f}% (저조) -3"]
        _ppctx = post_position_ctx(_meet, h.get("no"))
        pp_b, pp_d = 0, []
        if _ppctx and _ppctx["n"] >= 8:
            if _ppctx["delta"] >= 6:
                pp_b = 4; pp_d = [f"이 경주장 {h.get('no')}번 마번 유리 (+{_ppctx['delta']:.0f}%p)"]
            elif _ppctx["delta"] <= -6:
                pp_b = -4; pp_d = [f"이 경주장 {h.get('no')}번 마번 불리 ({_ppctx['delta']:.0f}%p)"]
        flags = special_flags(h, race)
        scored.append({
            "no": h.get("no"), "name": _nm, "jockey": h.get("jockey", ""),
            "recentPlacings": placings[:5],
            "baseScore": base, "courseBonus": cb, "jockeyBonus": jb,
            "distanceBonus": db_, "jockeyChangeBonus": kb, "weightBonus": wb,
            "gradeBonus": gb, "distExpBonus": deb, "distExperienced": dexp,
            "runningStyle": style,
            # [신규 전적확장] 궁합·조교사·마번 보정 + 표시용 컨텍스트
            "synergyBonus": syn_b, "synergyGrade": syn_g, "synergyRate": syn_r,
            "trainerBonus": tr_b, "trainerName": _trn, "trainerRate": (_trctx or {}).get("rate") if _trctx else None,
            "postPosBonus": pp_b, "postPosDelta": (_ppctx or {}).get("delta") if _ppctx else None,
            "totalScore": round(base + cb + jb + db_ + kb + wb + gb + deb + syn_b + tr_b + pp_b, 1),
            "detail": cd + jd + dd + kd + wd + gd + ded + syn_d + tr_d + pp_d, "flags": flags,
            "anomaly": h.get("anomaly"),
            "badTrackRate": bad_track_rate(h.get("pastRaces")),   # [날씨] 과거 불량주로 복승권율(pastRaces condition)
        })
    return scored, jockey_threshold


def compute_horse_scores(race, horses, jockey_threshold=None, anomaly_by_no=None, leader_names=None):
    """3-1~3-5 통합. anomaly_by_no(마번→이상감지) 주면 등급 보정에 반영."""
    scored, _ = score_horses_raw(race, horses, jockey_threshold, leader_names)
    if anomaly_by_no:
        for h in scored:
            if anomaly_by_no.get(h["no"]) is not None:
                h["anomaly"] = anomaly_by_no[h["no"]]
    classify_grades(scored)
    return scored


