@app.errorhandler(Exception)
def on_error(e):
    # HTTP 예외(404/405 등)는 원래 상태코드를 보존 — 405가 500으로 둔갑하던 버그 수정
    if isinstance(e, HTTPException):
        return jsonify({"error": f"{e.code} {e.name}: {e.description}"}), e.code
    # [공개 서비스·item5] 프로덕션에서는 내부 경로/디버그정보 노출 방지 — 일반 메시지로 응답.
    #   로컬(debug 또는 FLASK_ENV!=production)에서는 기존대로 str(e) 노출해 디버깅 유지(무삭제).
    if app.debug or os.environ.get("FLASK_ENV") != "production":
        return jsonify({"error": str(e)}), 500
    try:
        app.logger.exception("internal error")  # 상세 원인은 서버 로그에만 기록
    except Exception:
        pass
    return jsonify({"error": "internal_error", "message": "서버 내부 오류가 발생했습니다."}), 500


# ═══════════════════════════════════════════════════════════════════════════
# [다중 경주 동시 배당판] — 별도 추가 기능(기존 단일 경주 분석 완전 유지·무영향)
#   ⚠ 핵심 원칙: triple_store.json 절대 미접근. multi_race_store.json / today_schedule.json 전용 저장소.
#   실패 격리(6번): fetch 실패 경주만 건너뜀 · 스케줄 실패 시 단일 모드 유지 · 저장소 손상 시 자동 초기화.
# ═══════════════════════════════════════════════════════════════════════════
MULTI_STORE_FILE = os.path.join(os.path.dirname(__file__), "data", "multi_race_store.json")
SCHEDULE_FILE = os.path.join(os.path.dirname(__file__), "data", "today_schedule.json")
_multi_lock = threading.Lock()
MULTI_COLLECT_LEAD_SEC = 600      # [2번] 발주 10분전부터 수집 시작
MULTI_URGENT_SEC = 180            # [3·5번] T-3분 이내 = 긴급(빨강)
MULTI_WARN_SEC = 600             # [3번] T-10분 이내 = 주의(주황)


def _multi_store_load():
    """multi_race_store.json 로드. 손상 시 자동 초기화(6번·기존 기능 영향 없음)."""
    try:
        with open(MULTI_STORE_FILE, encoding="utf-8") as f:
            d = json.load(f)
        return d if isinstance(d, dict) else {}
    except FileNotFoundError:
        return {}
    except Exception as e:
        print("[다중경주] 저장소 손상 → 자동 초기화:", e)
        try:
            os.remove(MULTI_STORE_FILE)
        except OSError:
            pass
        return {}


def _multi_store_save(db):
    """원자적 쓰기(tmp→replace)로 저장소 손상 방지."""
    try:
        os.makedirs(os.path.dirname(MULTI_STORE_FILE), exist_ok=True)
        tmp = MULTI_STORE_FILE + ".tmp"
        with open(tmp, "w", encoding="utf-8") as f:
            json.dump(db, f, ensure_ascii=False)
        os.replace(tmp, MULTI_STORE_FILE)
    except Exception as e:
        print("[다중경주] 저장 실패:", e)


def _schedule_load():
    try:
        with open(SCHEDULE_FILE, encoding="utf-8") as f:
            return json.load(f)
    except Exception:
        return {}


def _schedule_save(sched):
    try:
        os.makedirs(os.path.dirname(SCHEDULE_FILE), exist_ok=True)
        tmp = SCHEDULE_FILE + ".tmp"
        with open(tmp, "w", encoding="utf-8") as f:
            json.dump(sched, f, ensure_ascii=False)
        os.replace(tmp, SCHEDULE_FILE)
    except Exception as e:
        print("[스케줄] 저장 실패:", e)


def _korea_schedule_post_epoch(rk, post_epoch):
    """[수정3] 한국경마 경주의 발주 epoch(초)를 today_schedule 에 반영 → 타임 스냅샷(T-7/T-5) 작동.
    확장이 배당판에서 감지한 발주시각을 KRA 스케줄(발주시각 미제공)에 채운다. 트랙 없으면 생성."""
    try:
        if not rk or not post_epoch or post_epoch <= 0:
            return
        venue, rno = _area_num(rk)
        if not (venue and rno):
            return
        sched = _schedule_load() or {"ymd": time.strftime("%Y%m%d"), "updated": time.time(), "tracks": []}
        tracks = sched.setdefault("tracks", [])
        tr = next((t for t in tracks if t.get("venue") == venue and t.get("sport") == "korea"), None)
        if not tr:
            tr = {"venue": venue, "sport": "korea", "category": "korea", "races": []}
            tracks.append(tr)
        races = tr.setdefault("races", [])
        rc = next((r for r in races if r.get("raceNo") == rno), None)
        if not rc:
            rc = {"raceNo": rno}
            races.append(rc)
        # 이미 postEpoch 가 있고 5분 이내 근접하면 갱신 생략(중복쓰기 방지)
        if rc.get("postEpoch") and abs(rc["postEpoch"] - post_epoch) < 300:
            return
        rc["postEpoch"] = post_epoch
        rc["postTime"] = time.strftime("%H:%M", time.localtime(post_epoch))
        _schedule_save(sched)
    except Exception as e:
        print("[한국 발주시각] 스케줄 반영 실패(무시):", e)


def _post_time_epoch(hhmm, ymd):
    """'HH:MM' + ymd(YYYYMMDD) → 발주 epoch(서버 로컬). 실패 시 None."""
    try:
        m = re.match(r"(\d{1,2}):(\d{2})", (hhmm or "").strip())
        if not m or len(ymd or "") != 8:
            return None
        st = time.struct_time((int(ymd[:4]), int(ymd[4:6]), int(ymd[6:8]),
                               int(m.group(1)), int(m.group(2)), 0, 0, 0, -1))
        return time.mktime(st)
    except (ValueError, TypeError):
        return None


_MULTI_POST_CACHE = {}   # {(ymd,op,sp,rno): "HH:MM"} 발주시각 당일 캐시(시각은 하루 불변 → 재fetch 방지)


def _multi_post_time(op, sp, ymd, rno):
    """[1번] 특정 경주 RaceList.do?raceNb=N 페이지에서 発走時間(HH:MM) 추출. 당일 캐시·실패 시 None(격리)."""
    ck = (ymd, op, sp, rno)
    if ck in _MULTI_POST_CACHE:
        return _MULTI_POST_CACHE[ck]
    try:
        url = ("https://www.oddspark.com/keiba/RaceList.do?raceDy=%s&opTrackCd=%s&sponsorCd=%s&raceNb=%s"
               % (ymd, op, sp, rno))
        html = _keirin_fetch(url)
        # oddspark 실제 라벨: '発走時間 14:30'(時間) — 発走時刻/締切 아님. 방어적으로 발走 계열 다 허용.
        m = (re.search(r"発走時間\s*(\d{1,2}:\d{2})", html)
             or re.search(r"(?:発走時刻|発走|締切)\s*(\d{1,2}:\d{2})", html))
        pt = m.group(1) if m else None
        if pt:
            _MULTI_POST_CACHE[ck] = pt        # 성공만 캐시(실패는 다음 갱신 때 재시도)
        return pt
    except Exception:
        return None


def _multi_race_list(op, sp, ymd):
    """[1번] oddspark RaceList.do → [{raceNo, postTime, postEpoch}]. 경주번호는 목록 페이지에서, 発走時間은 경주별 페이지에서 병렬 취득.
      ⚠ KaisaiRaceList.do·목록 페이지엔 発走時間이 없어(각 경주 페이지에만 '発走時間 HH:MM' 존재) 경주별 fetch 필요."""
    url = ("https://www.oddspark.com/keiba/RaceList.do?raceDy=%s&opTrackCd=%s&sponsorCd=%s" % (ymd, op, sp))
    html = _keirin_fetch(url)
    # 경주번호 집합(raceNb 링크)
    nums = sorted({int(x) for x in re.findall(r"raceNb=(\d{1,2})", html) if 1 <= int(x) <= 12})
    if not nums:
        nums = list(range(1, 13))          # 링크 못 찾으면 1~12 시도(발주시각 없으면 자동 제외됨)
    # 発走時間 경주별 병렬 취득(부하·차단 방지 위해 소량 동시성)
    times = {}
    try:
        with ThreadPoolExecutor(max_workers=4) as ex:
            fut = {ex.submit(_multi_post_time, op, sp, ymd, n): n for n in nums}
            for f in as_completed(fut):
                times[fut[f]] = f.result()
    except Exception as e:
        print("[스케줄] 発走時間 병렬취득 오류(무시):", e)
    out = []
    for n in nums:
        pt = times.get(n)
        out.append({"raceNo": n, "postTime": pt, "postEpoch": _post_time_epoch(pt, ymd)})
    return out


_KEIRIN_SCHED_CACHE = {}   # {ymd: {"t":.., "tracks":[...]}} 경륜 개최 스케줄 당일 캐시(6시간)


def _keirin_post_time(jo, ymd, rno):
    """[경륜 서버수집] 경주별 RaceList.do 페이지에서 発走時間(HH:MM) 추출. 당일 캐시·실패 None(격리).
      ⚠ 締切予定(발매마감·23:45 류)은 발주시각이 아니므로 発走時間 계열만 사용."""
    ck = ("keirin", ymd, str(jo), rno)
    if ck in _MULTI_POST_CACHE:
        return _MULTI_POST_CACHE[ck]
    try:
        html = _keirin_fetch(_keirin_url(jo, ymd, rno))
        # 경륜 페이지는 라벨과 시각 사이에 태그가 있어(경마와 구조 차이) 태그 제거 후 매칭
        body = re.sub(r"\s+", " ", re.sub(r"<[^>]+>", " ", html))
        m = (re.search(r"発走時間\s*(\d{1,2}:\d{2})", body)
             or re.search(r"(?:発走予定|発走時刻|発走)\s*(\d{1,2}:\d{2})", body))
        pt = m.group(1) if m else None
        if pt:
            _MULTI_POST_CACHE[ck] = pt        # 성공만 캐시(실패는 다음 갱신 때 재시도)
        return pt
    except Exception:
        return None


def _keirin_venue_races(jo, ymd):
    """[경륜 서버수집] joCode의 경륜장명 + 경주번호 목록. raceNo=1 공개 출주표 title에서 경륜장명,
      raceNo 링크에서 경주 수(보통 12). 실패 시 (None, [])."""
    try:
        html = _keirin_fetch(_keirin_url(jo, ymd, 1))
    except Exception:
        return None, []
    mt = re.search(r"<title>(.*?)</title>", html, re.S)
    title = _kstrip(mt.group(1)) if mt else ""
    mv = re.search(r"([一-龯ぁ-んァ-ヶー]{2,6})競輪", title)
    venue_ja = mv.group(1).strip() if mv else ""
    nums = sorted({int(x) for x in re.findall(r"raceNo=(\d{1,2})", html) if 1 <= int(x) <= 12})
    if not nums:
        nums = list(range(1, 13))          # 링크 못 읽으면 1~12 시도(발주시각 없으면 자동 제외됨)
    return venue_ja, nums


def _keirin_schedule(ymd, force=False):
    """[경륜 서버 직접 수집] oddspark 경륜 홈(로그인 불필요·공개)에서 오늘 개최 경륜장(joCode) 추출 →
      경주별 발주시각까지 수집해 today_schedule 병합용 트랙 리스트 반환.
      반환: [{venue, joCode, sport:'cycle', races:[{raceNo, postTime, postEpoch}]}]. 실패해도 예외 전파 안 함.
      ⚠ KaisaiRaceList.do 는 로그인 벽 → 홈페이지의 RaceList.do?joCode&kaisaiBi 링크로 개최 감지(공개 경로)."""
    ck = _KEIRIN_SCHED_CACHE.get(ymd)
    if ck and not force and (time.time() - ck.get("t", 0) < 21600):
        return ck["tracks"]
    tracks = []
    jos = []
    try:
        home = _keirin_fetch("https://www.oddspark.com/keirin/").replace("&amp;", "&")
        jos = sorted({m.group(1) for m in re.finditer(r"joCode=(\d+)&kaisaiBi=%s" % ymd, home)})
    except Exception as e:
        print("[경륜 스케줄] 홈 조회 실패(경륜 생략):", e)
    for jo in jos:
        try:
            venue_ja, nums = _keirin_venue_races(jo, ymd)
            venue = KEIRIN_JO.get(str(jo)) or venue_ja or ("경륜%s" % jo)
            times = {}
            try:
                with ThreadPoolExecutor(max_workers=4) as ex:
                    fut = {ex.submit(_keirin_post_time, jo, ymd, n): n for n in nums}
                    for f in as_completed(fut):
                        times[fut[f]] = f.result()
            except Exception as e:
                print("[경륜 스케줄] 発走시각 병렬취득 오류(무시):", e)
            races = [{"raceNo": n, "postTime": times.get(n), "postEpoch": _post_time_epoch(times.get(n), ymd)}
                     for n in nums]
            tracks.append({"venue": venue, "joCode": str(jo), "sport": "cycle", "races": races})
        except Exception as e:
            print("[경륜 스케줄]", jo, "경주목록 실패(건너뜀):", e)
            continue
    _KEIRIN_SCHED_CACHE[ymd] = {"t": time.time(), "tracks": tracks}
    print("[경륜 스케줄] %s: 경륜장 %d곳 · 경주 %d개(서버 직접수집·로그인 불필요)"
          % (ymd, len(tracks), sum(len(t["races"]) for t in tracks)))
    return tracks


# [한국경마 스케줄] KRA 배당 API로 오늘 개최 경주 감지 → 전체 경주 탭 병합용 트랙 리스트.
#   KRA 는 스케줄 전용 API가 없어 배당 API(_kra_fetch)로 각 경주 존재를 확인한다(발매 시작 후 감지).
#   ⚠ 발주시각 필드는 KRA API에 없음 → postTime 은 None(카운트다운 대신 목록만). 두수는 단승 개수로 산출.
#   ⚠ 한국경마 개최일(보통 금 부경·토일 서울/부산/제주)에만 경주가 잡힘. 비개최일엔 빈 리스트(정상).
_KRA_SCHED_CACHE = {}
KRA_MEET_FOR_SCHED = [("1", "서울"), ("2", "제주"), ("3", "부산")]


def _kra_schedule(ymd, force=False):
    """[한국경마 서버 감지] 오늘 개최 KRA 경주 → [{venue, meet, sport:'korea', races:[{raceNo, horses, postTime:None}]}].
      경주 존재는 배당 API 응답 유무로 판단(발매 전이면 빈 값 → 아직 안 뜸). 캐시 30분(개최 진행 중 갱신 반영).
      ⚠ 배당 API를 경주별로 조회하므로 비개최일엔 12R×3장 헛조회가 되지만, 첫 빈 응답 연속 시 조기 중단."""
    ck = _KRA_SCHED_CACHE.get(ymd)
    if ck and not force and (time.time() - ck.get("t", 0) < 1800):
        return ck["tracks"]
    tracks = []
    for meet, venue in KRA_MEET_FOR_SCHED:
        races = []
        miss_streak = 0
        for rc in range(1, 16):        # 최대 15경주(한국은 보통 ~11R)
            try:
                items, _meta, err = _kra_fetch(meet, ymd, str(rc), num_rows=200)
            except Exception:
                items, err = [], "fetch 오류"
            if err or not items:
                miss_streak += 1
                if miss_streak >= 3 and not races:
                    break              # 1~3R 연속 없음 + 아직 한 경주도 못 찾음 = 비개최 → 조기 중단
                if miss_streak >= 3 and races:
                    break              # 마지막 경주 이후 3연속 없음 = 개최 종료
                continue
            miss_streak = 0
            win, _q, _x, _tr = _kra_parse_items(items)
            races.append({"raceNo": rc, "horses": len(win), "postTime": None, "postEpoch": None})
        if races:
            tracks.append({"venue": venue, "meet": meet, "sport": "korea",
                           "category": "korea", "races": races})
    _KRA_SCHED_CACHE[ymd] = {"t": time.time(), "tracks": tracks}
    print("[한국경마 스케줄] %s: 경마장 %d곳 · 경주 %d개(KRA API 감지·발주시각 미제공)"
          % (ymd, len(tracks), sum(len(t["races"]) for t in tracks)))
    return tracks


def _multi_schedule_fetch():
    """[1번] 오늘 개최 경주 스케줄(경마장+경주번호+발주시각) → today_schedule.json. 실패해도 예외 전파 안 함.
      [경륜 통합] 지방경마 + 경륜을 서버가 함께 수집(경륜도 oddspark 홈 공개경로 → Chrome 확장 불필요)."""
    ymd = time.strftime("%Y%m%d")
    sched = {"ymd": ymd, "updated": time.time(), "tracks": []}
    try:
        tracks = _keiba_schedule(ymd)         # {한자경마장명: (opTrackCd, sponsorCd)}
    except Exception as e:
        print("[스케줄] 개최 목록 실패(단일 모드 유지):", e)
        tracks = {}
    for kanji, codes in (tracks or {}).items():
        try:
            op, sp = codes
            races = _multi_race_list(op, sp, ymd)
            sched["tracks"].append({"venue": _track_norm(kanji), "kanji": kanji,
                                    "opTrackCd": op, "sponsorCd": sp, "races": races})
        except Exception as e:
            print("[스케줄]", kanji, "경주목록 실패(건너뜀):", e)
            continue
    # [경륜 서버 직접 수집] 지방경마와 동시에 경륜 스케줄도 병합(sport=cycle) → 확장 없이 경륜 자동 수집·표시
    try:
        for kt in _keirin_schedule(ymd):
            sched["tracks"].append(kt)
    except Exception as e:
        print("[스케줄] 경륜 병합 실패(무시·경마는 유지):", e)
    # [한국경마 병합] KRA API로 오늘 개최 한국경마(서울·부산·제주)를 감지해 병합(sport=korea) → 전체 경주 탭에 🇰🇷 표시.
    #   ⚠ 비개최일엔 빈 리스트(정상). 발주시각은 KRA 미제공이라 목록만(카운트다운 없음).
    try:
        for kt in _kra_schedule(ymd):
            sched["tracks"].append(kt)
    except Exception as e:
        print("[스케줄] 한국경마 병합 실패(무시·일본경주는 유지):", e)
    _schedule_save(sched)
    _n_cycle = sum(1 for t in sched["tracks"] if (t.get("sport") == "cycle"))
    _n_korea = sum(1 for t in sched["tracks"] if (t.get("sport") == "korea"))
    print("[다중경주 스케줄] %s: 트랙 %d곳(경륜 %d·한국 %d 포함) · 경주 %d개"
          % (ymd, len(sched["tracks"]), _n_cycle, _n_korea, sum(len(t["races"]) for t in sched["tracks"])))
    return sched


def _multi_key(venue, race_no):
    # [岐阜·기후 중복 통합] 저장키의 경마장명을 표준(한글)으로 정규화 → 岐阜/기후가 한 키로 병합(중복 저장 방지).
    return "%s %d경주" % (_track_norm(venue), int(race_no))


def _multi_collect_one(track, race, ymd):
    """[2번] 한 경주 배당 수집 → multi_race_store 저장(실패 격리·triple_store 미접근). 반환 raceKey 또는 None.
      종목 라우팅: opTrackCd=경마(keiba) · joCode=경륜(keirin·배당은 공개라 서버 수집 가능·스케줄만 로그인 필요)."""
    try:
        rno = race["raceNo"]
        is_cycle = bool(track.get("joCode")) and (track.get("sport") == "cycle" or not track.get("opTrackCd"))
        if is_cycle:
            jo = track["joCode"]
            # 경륜: betType 5=복승(2車複)·6=쌍승(2車単) (경마와 반대)
            q = _keirin_parse_quinella(_keirin_fetch(_keirin_odds_url(jo, ymd, rno, 5)))
            x = _keirin_parse_exacta(_keirin_fetch(_keirin_odds_url(jo, ymd, rno, 6)))
            sport, category = "cycle", "cycle"
        else:
            op, sp = track["opTrackCd"], track["sponsorCd"]
            q = _keiba_parse_quinella(_keirin_fetch(_keiba_odds_url(op, sp, ymd, rno, _KEIBA_BET["quinella"])))
            x = _keiba_parse_exacta(_keirin_fetch(_keiba_odds_url(op, sp, ymd, rno, _KEIBA_BET["exacta"])))
            sport, category = "horse", "japan_local"
        if not _keiba_odds_live(q, x):
            return None                        # 발매 전·마감 후(가짜값) → 저장 안 함
        key = _multi_key(track["venue"], rno)
        with _multi_lock:
            db = _multi_store_load()
            prev = db.get(key) or {}
            hist = list(prev.get("history") or [])
            hist.append({"t": time.time(), "quinella": q, "exacta": x, "trio": [], "win": {}})
            hist = hist[-12:]
            db[key] = {"quinella": q, "exacta": x, "trio": [], "win": {}, "history": hist,
                       "sport": sport, "category": category,
                       "venue": track["venue"], "raceNo": rno,
                       "postTime": race.get("postTime"), "postEpoch": race.get("postEpoch"),
                       "t": time.time()}
            _multi_store_save(db)
        # [단일 탭 배당 공급·근본수정] 백그라운드 수집분을 triple_store 에도 주입 →
        #   일본경마/경륜/경정 '단일 탭'(/api/odds/triple/latest·analyze)이 Chrome 확장·프론트 토글 없이
        #   서버만으로 실시간 표시. 기존엔 background→multi_store 만 채우고 triple_store 는 확장/토글에만
        #   의존해, 둘 다 꺼지면 '배당 수집 안 됨'으로 보이던 문제 해결. 확장 ingest 와 동일 파이프라인(같은
        #   raceKey 병합·중복 아님)이고 sport 분리 필터가 탭 혼재를 막는다(무삭제·multi_store 경로 유지).
        try:
            # [자동전환·마감판정] 발주시각(postEpoch) 전달 → analyze 의 minutesBefore/afterClose 가 채워져
            #   프론트 '경주 종료' 판정(_raceFinished)·자동예상 T-5분 타이밍이 정확해짐(기존엔 deadline 미전달로 None).
            _do_triple_ingest(key, q, x, [], {}, sport=sport, category=category,
                              source="oddspark_bg", deadline=race.get("postEpoch"))
        except Exception as _be:
            print("[다중경주] triple_store 브리지 실패(무시·multi_store 는 정상):", _be)
        # [경륜 전적 자동 수집] 다중 경주 경륜 배당 수집 시 전적도 함께(1회·통합등급 반영)
        if is_cycle:
            try:
                _keirin_autocollect_form(key, track.get("joCode"), ymd, rno)
            except Exception:
                pass
        else:
            # [지방경마(NAR) 전적 자동 수집] 확장 자동전송 차단(NAR 서버 전담) 상황에서 '전적 데이터 없음'
            #   해소 — 배당과 동시에 oddspark 出走表+전적을 수집·저장(경주당 1회·통합등급 반영). keirin 대칭.
            try:
                _keiba_autocollect_form(key, track.get("opTrackCd"), track.get("sponsorCd"), ymd, rno)
            except Exception:
                pass
        return key
    except Exception as e:
        print("[다중경주] 수집 실패 %s %s: %s" % (track.get("venue"), race.get("raceNo"), e))
        return None


_JRA_TRACKS = ("삿포로", "하코다테", "후쿠시마", "니가타", "도쿄", "나카야마", "주쿄", "쿄토", "교토", "한신", "고쿠라", "코쿠라")


def _multi_sport_of(rec):
    """[통합·4번] rec의 sport/category → 대시보드 종목 그룹(horse|central|cycle|boat|korea).
      중앙경마(JRA)는 category=japan_central 또는 JRA 경마장명으로 'central' 분류(지방경마 horse와 구분)."""
    cat = (rec.get("category") or "").lower()
    sp = (rec.get("sport") or "").lower()
    if sp == "cycle" or cat == "cycle":
        return "cycle"
    if sp == "boat" or cat == "boat":
        return "boat"
    _venue = rec.get("venue") or ""
    _area = _area_num(_venue)[0] or _area_num(rec.get("raceKey") or "")[0] or ""
    if cat == "korea" or _area in ("서울", "부산", "부경", "제주", "과천"):
        return "korea"
    if cat == "japan_central" or _area in _JRA_TRACKS or _venue in _JRA_TRACKS:
        return "central"                        # [중앙경마·JRA] 지방경마와 별도 그룹
    return "horse"


def _card_conf_value(conf):
    """[확신도 표시 수정] 카드에 표시할 확신도 스칼라 추출.
    _confidence_engine 의 overall 은 {best,band,bestHorse} 객체이므로 best(대표 점수)를 꺼낸다.
    레거시(overall 이 숫자)·level 폴백은 그대로 유지. 값 없으면 None."""
    conf = conf or {}
    ov = conf.get("overall")
    if isinstance(ov, dict):
        ov = ov.get("best")
    if ov is not None:
        return ov
    lv = conf.get("level")
    if isinstance(lv, dict):
        lv = lv.get("best") or lv.get("band")
    return lv


def _live_exact_hit(key, top3, horse_count=None):
    """[적중 표시 정직화 (2026-07-19)] '라이브에서 실제 화면에 표시된 추천'(analysis_log의 corePicks·
    recommendation_history·final_recommendation)만으로 정확 적중 재판정.
      복승 = 추천 조합 == 1·2착(순서무관) · 삼복승 = 추천 조합 == 1·2·3착(순서무관) — 적중판정 기준 그대로.
    배경: 저장된 main_hit 는 결과입력 시점 '재분석' betRecommend(마감 후 확정배당 기반 = 정답이 최저배당인
    상태에서 재생성 → 사용자가 본 적 없는 유령 추천)까지 판정 대상에 넣어 적중이 부풀려짐(오늘 19건 중 16건 ✅).
    → 표시는 라이브 추천만으로 재판정(기존 파일·학습데이터는 무수정 — 표시 계층만 정직화).
    반환 {hit, trioHit, matched, matchedTrio, liveQuinellas} 또는 None(로그 없음 → 저장 판정 폴백)."""
    # [마감 후 기록 제외 (2026-07-19·모리오카 3R)] 마감 13:22 인데 로그의 유일한 추천(4+9)이
    #   13:26 기록(마감 후 재계산 잔재) → 그걸로 ✅ 판정되던 문제. 마감 시각(odds_history 첫
    #   after_close 스냅샷) 이후 기록된 추천은 판정 제외. 마감 전 추천이 하나도 없고 분석 자체
    #   (analyzed_at)도 마감 후면 "추천 미형성"(noRec) — 적중/미적중 어느 쪽도 아님(집계 제외).
    try:
        _close_t = None
        try:
            _hp0, _, _ = _hist_path(key)
            _hd0 = json.load(open(_hp0, encoding="utf-8"))
            for _sx in (_hd0.get("snapshots") or []):
                if _sx.get("after_close") and _sx.get("time"):
                    _close_t = _sx["time"]
                    break
        except Exception:
            pass
        _log_doc = None
        try:
            _lp0, _, _ = _analysis_log_path(_canonical_log_key(key))
            _log_doc = json.load(open(_lp0, encoding="utf-8"))
        except Exception:
            _log_doc = None
        if _close_t and _log_doc:
            _rh0 = _log_doc.get("recommendation_history") or []
            _pre = [e for e in _rh0 if not e.get("time") or str(e.get("time")) < _close_t]
            _an_at = str(_log_doc.get("analyzed_at") or "")
            if _rh0 and not _pre and _an_at and _an_at >= _close_t:
                return {"hit": False, "trioHit": False, "matched": None, "matchedTrio": None,
                        "liveQuinellas": [], "noRec": True}
        _lc = _rec_combos_from_analysis_log(key)
        # [마감 후 기록 개별 제외] 마감 후에만 등장한 조합은 판정 대상에서 뺀다(마감 전 기록에도
        #   있던 조합은 유지 — 같은 추천이 마감 후 재기록된 경우는 정당).
        if _close_t and _log_doc:
            def _combset(pred):
                _out = set()
                for e in (_log_doc.get("recommendation_history") or []):
                    if pred(e):
                        for _k2 in ("quinella_main", "quinella_sub", "trifecta_main"):
                            _v2 = e.get(_k2)
                            if _v2:
                                try:
                                    _out.add(tuple(sorted(int(x) for x in re.split(r"[+\-]", str(_v2)) if str(x).strip().isdigit())))
                                except Exception:
                                    pass
                return _out
            _only_post = (_combset(lambda e: e.get("time") and str(e["time"]) >= _close_t)
                          - _combset(lambda e: not e.get("time") or str(e["time"]) < _close_t))
            if _only_post:
                _lc = [c for c in _lc if tuple(sorted(int(x) for x in (c.get("combo") or []))) not in _only_post]
        if not _lc:
            return None
        _t2 = sorted(int(x) for x in (top3 or [])[:2] if x is not None)
        _t3s = sorted(int(x) for x in (top3 or [])[:3] if x is not None)

        def _valid(c):
            # [로그 오염 방어] 출주 두수 초과 마번 조합(타 경주 혼입 — 경륜 7명에 1+10 등)은 판정 제외
            try:
                return not (horse_count and any(int(x) > int(horse_count) for x in c))
            except Exception:
                return True
        hit = trio_hit = False
        matched = matched_t = None
        live_q = []
        for c in _lc:
            combo = c.get("combo") or []
            if not _valid(combo):
                continue
            if c.get("kind") == "복승" and len(combo) == 2:
                live_q.append("+".join(map(str, sorted(combo))))
                if len(_t2) == 2 and sorted(combo) == _t2:
                    hit = True
                    matched = "+".join(map(str, sorted(combo)))
            elif c.get("kind") == "삼복승" and len(combo) == 3:
                if len(_t3s) == 3 and sorted(combo) == _t3s:
                    trio_hit = True
                    matched_t = "+".join(map(str, sorted(combo)))
        return {"hit": hit, "trioHit": trio_hit, "matched": matched,
                "matchedTrio": matched_t, "liveQuinellas": live_q[:4], "noRec": False}
    except Exception:
        return None


def _race_result_summary(key):
    """[카드 적중 표시 (2026-07-19)] 결과 파일 → {top3, hit(복승 정확), trioHit(삼복승 정확), subHit,
    recommend, quinellaOdds} 또는 None. 적중 표시는 라이브 추천 정확 재판정(_live_exact_hit) 우선,
    analysis_log 없는 구데이터만 저장된 result_analysis.main_hit 폴백(적중판정 기준 불변)."""
    try:
        _rid, _ = _race_result_id(key)
        _rp = os.path.join(RACE_RESULTS_DIR, _rid + ".json")
        if not os.path.exists(_rp):
            _rp = _race_result_path(key) if callable(globals().get("_race_result_path")) else None
            if not _rp or not os.path.exists(_rp):
                return None
        _doc = json.load(open(_rp, encoding="utf-8"))
        _r = _doc.get("result") or {}
        _t3 = [_r.get("1st"), _r.get("2nd"), _r.get("3rd")]
        if _t3[0] is None:
            return None
        _ra = _doc.get("result_analysis") or {}
        # [적중 표시 안 됨 버그 수정 2026-07-19] prediction.recommend_main 은 문자열("1+7")로 저장됨(dict 아님).
        #   기존 _pm.get("combo") 는 문자열에 AttributeError → except 로 None 반환 → 추천이 있던 경주일수록
        #   ✅/❌ 배지가 전부 사라지던 원인(추천 없던 경주만 배지 표시 = "오늘 적중 1건" 증상). 타입별 안전 처리.
        _pm = (_doc.get("prediction") or {}).get("recommend_main")
        if isinstance(_pm, dict):
            _rec = _pm.get("combo")
        elif isinstance(_pm, (list, tuple)):
            _rec = "+".join(str(x) for x in _pm) if _pm else None
        else:
            _rec = _pm or None
        _po = _r.get("payouts") or _doc.get("payouts") or {}
        # [확정배당 폴백] 결과 doc 의 확정 복승배당은 investment.quinella_odds 에 저장됨(result.payouts 비어 있음)
        _qo = (_po.get("quinella") if isinstance(_po, dict) else None)
        if _qo is None:
            _qo = (_doc.get("investment") or {}).get("quinella_odds")
        # [적중 표시 정직화] 라이브 추천 정확 재판정 우선 · 로그 없는 구데이터만 저장 main_hit 폴백
        #   경륜(최대 9명)은 horse_count 미저장이어도 9 상한으로 오염 조합(1+10 등) 차단
        _hc = _doc.get("horse_count") or (9 if (_doc.get("sport") == "cycle" or _KEIRIN_ONLY_RE.search(str(key))) else None)
        _lx = _live_exact_hit(key, _t3, _hc)
        if _lx is not None:
            _hit, _trio = _lx["hit"], _lx["trioHit"]
            _matched, _matched_t, _live_q = _lx["matched"], _lx["matchedTrio"], _lx["liveQuinellas"]
            _judged = "live"
            _norec = bool(_lx.get("noRec"))
        else:
            _hit, _trio = bool(_ra.get("main_hit")), False
            _matched, _matched_t, _live_q = None, None, []
            _judged = "stored"
            _norec = False
        return {"top3": _t3, "hit": _hit, "trioHit": _trio, "subHit": bool(_ra.get("sub_hit")),
                "matched": _matched, "matchedTrio": _matched_t, "liveQuinellas": _live_q,
                "judged": _judged, "noRec": _norec,
                "recommend": _rec, "hitReason": _ra.get("hit_reason"),
                "missReason": _ra.get("miss_reason"),
                "quinellaOdds": _qo}
    except Exception:
        return None


_MULTI_CARD_CACHE = {}   # [수집 누락 긴급수정 2026-07-19] {key: (built_t, rec_t, card)} 카드 15초 캐시
#   대시보드 폴링(30초)마다 수집 경주 전부를 _triple_analyze(무거움: KRA API·전적·전개) 재계산 →
#   개최 많은 날 응답이 수십 초로 늘어나 카드가 늦거나 이전 화면에 머물던 문제. rec.t(새 수집) 변경 시엔 즉시 재계산.


def _multi_card(key, rec):
    """[3번] 카드 요약: analyze(기존 _triple_analyze 재사용·읽기전용) → 유력마TOP3·핵심신호·확신도·마감남은초·색상."""
    # [카드 캐시] 같은 수집본(rec.t 동일)이면 15초간 재분석 생략 → 대시보드 응답 시간 급감(내용 동일)
    _rt = rec.get("t") or 0
    try:
        _ck = _MULTI_CARD_CACHE.get(key)
        if _ck and (time.time() - _ck[0]) < 15 and _ck[1] == _rt:
            return _ck[2]
    except Exception:
        pass
    try:
        an = _triple_analyze(key, rec)
    except Exception as e:
        # [수집분 증발 방지] 분석이 실패해도 '수집 대기'로 오표시하지 않게 최소 폴백 카드 반환(원인 로그 포함).
        import traceback
        traceback.print_exc()
        print("[다중경주] 분석 실패", key, e, "→ 폴백 카드(수집 사실 유지)")
        try:
            _fb = {
                "raceKey": key, "venue": _track_norm(rec.get("venue")), "raceNo": rec.get("raceNo"),
                "sport": _multi_sport_of(rec), "postTime": rec.get("postTime"),
                "secondsLeft": (int(rec["postEpoch"] - time.time()) if rec.get("postEpoch") else None),
                "urgency": "normal", "keyHorses": [], "signals": [], "anomaly": False,
                "midHigh": [], "confidence": None, "quinellaMain": None,
                "afterClose": False, "analyzeError": True,
                "updatedSecondsAgo": int(time.time() - (_rt or time.time())),
            }
            return _fb
        except Exception:
            return None
    now = time.time()
    pe = rec.get("postEpoch")
    left = int(pe - now) if pe else None
    if left is None and not an.get("afterClose") and an.get("minutesBefore") is not None:
        left = int(an["minutesBefore"] * 60)   # [통합] postEpoch 없는 확장수집(경륜/한국)은 분석의 발주전분으로 카운트다운
    urgency = "normal"
    if left is not None:
        if left <= MULTI_URGENT_SEC:
            urgency = "urgent"                 # T-3분 이내 빨강
        elif left <= MULTI_WARN_SEC:
            urgency = "warn"                   # T-10분 이내 주황
    # 핵심 신호(급락/역배열/스마트머니) 요약
    signals = []
    drops = [d for d in (an.get("drops") or []) if (d.get("pct") or 0) <= -30]
    if drops:
        d0 = min(drops, key=lambda d: d.get("pct") or 0)
        signals.append({"type": "급락", "text": "🔴 %s 급락 %d%%" % ("+".join(str(x) for x in d0.get("combo") or []), round(d0.get("pct") or 0))})
    inv = an.get("inverse") or {}
    if inv.get("detected") and (inv.get("invLead") or {}).get("no") is not None:
        signals.append({"type": "역배열", "text": "🔄 %s번 역배열" % inv["invLead"]["no"]})
    smart = [h for h in (an.get("darkHorses") or []) if h.get("smartMoney")]
    if smart:
        signals.append({"type": "스마트머니", "text": "💰 %s번 스마트머니" % smart[0].get("no")})
    conf = an.get("confidence") or {}
    # [3번·중고배당 유력마] 있으면 카드에 💎 배지 + 요약
    _mhf = an.get("midHighFavorites") or []
    mid_high = [{"no": m["no"], "odds": m["odds"], "sigTypes": m.get("sigTypes") or []} for m in _mhf[:3]]
    # [4번·⚡ 이상감지 배지] 급락/역배열/스마트머니 신호 하나라도 있으면 anomaly=True
    anomaly = bool(signals)
    card = {
        "raceKey": key, "venue": _track_norm(rec.get("venue")), "raceNo": rec.get("raceNo"),
        "sport": _multi_sport_of(rec),   # [통합·4번] 종목 그룹(horse|cycle|korea)
        "postTime": rec.get("postTime"), "secondsLeft": left, "urgency": urgency,
        "keyHorses": (an.get("keyHorses") or [])[:3],
        "signals": signals[:3], "anomaly": anomaly,   # [4번] ⚡ 이상감지 배지
        "midHigh": mid_high,   # [3번] 💎 중고배당 유력마(있으면 카드 배지·별도 강조)
        # [확신도 [object Object] 표시 수정] _confidence_engine 의 overall 은 {best,band,bestHorse} 객체다.
        #   과거엔 이 객체를 그대로 카드 confidence 에 넣어 프론트에서 String(객체)="[object Object]"로 표시됐다.
        #   → 객체면 대표 점수(best)를 꺼내 숫자로 전달(레거시 스칼라 overall·level 은 그대로).
        "confidence": _card_conf_value(conf),
        "quinellaMain": next((b.get("combo") for b in (an.get("betRecommend") or []) if b.get("label") == "복승 메인"), None),
        "afterClose": bool(an.get("afterClose")),
        "updatedSecondsAgo": int(now - (rec.get("t") or now)),
    }
    # [카드 적중 표시 (2026-07-19)] 결과가 있으면 ✅적중/❌미적중 배지 데이터 부가(카드 색상은 프론트)
    try:
        _rs = _race_result_summary(key)
        if _rs:
            card["result"] = _rs
    except Exception:
        pass
    try:
        _MULTI_CARD_CACHE[key] = (time.time(), _rt, card)   # [카드 캐시] 성공 카드만 저장
        if len(_MULTI_CARD_CACHE) > 300:                     # 과거 경주 캐시 무한증가 방지
            for _old_k in sorted(_MULTI_CARD_CACHE, key=lambda k: _MULTI_CARD_CACHE[k][0])[:100]:
                _MULTI_CARD_CACHE.pop(_old_k, None)
    except Exception:
        pass
    return card


@app.route("/api/multi/keirin-schedule", methods=["POST"])
def multi_keirin_schedule():
    """[확장 경유 경륜 스케줄] 확장(로그인 세션)이 oddspark 경륜 KaisaiRaceList를 fetch·파싱해 전송 →
    today_schedule.json에 sport=cycle 트랙으로 병합(기존 경마 트랙 보존·멱등). 로그인 벽 우회.
    body: {ymd, tracks:[{joCode, venue, races:[{raceNo, postTime}]}]}."""
    body = request.json or {}
    ymd = (body.get("ymd") or time.strftime("%Y%m%d")).strip()
    tracks = body.get("tracks") or []
    sched = _schedule_load()
    if not isinstance(sched, dict) or sched.get("ymd") != ymd:
        sched = {"ymd": ymd, "updated": time.time(), "tracks": []}
    # 기존 cycle 트랙 제거 후 재삽입(멱등) — 경마(horse) 트랙은 그대로 보존
    sched["tracks"] = [t for t in sched.get("tracks", []) if (t.get("sport") or "horse") != "cycle"]
    added = 0
    for t in tracks:
        races = []
        for r in (t.get("races") or []):
            pt = r.get("postTime")
            try:
                rno = int(r.get("raceNo"))
            except (TypeError, ValueError):
                continue
            races.append({"raceNo": rno, "postTime": pt, "postEpoch": _post_time_epoch(pt, ymd)})
        if not races:
            continue
        sched["tracks"].append({"venue": t.get("venue") or ("경륜%s" % t.get("joCode")),
                                "joCode": str(t.get("joCode") or ""), "sport": "cycle", "races": races})
        added += 1
    sched["updated"] = time.time()
    _schedule_save(sched)
    print("[경륜 스케줄·확장경유] %s: 경륜장 %d곳 병합" % (ymd, added))
    return jsonify({"ok": True, "tracks": added, "ymd": ymd})


@app.route("/api/multi/schedule", methods=["GET", "POST"])
def multi_schedule():
    """[1번] 오늘 개최 스케줄 조회(GET) / 강제 재수집(POST)."""
    if request.method == "POST":
        return jsonify(_multi_schedule_fetch())
    sched = _schedule_load()
    if not sched:                              # 없으면 1회 시도(비어도 단일 모드 안전)
        sched = _multi_schedule_fetch()
    return jsonify(sched)


@app.route("/api/multi/collect", methods=["POST"])
def multi_collect_now():
    """[2번] 지금 발주 임박(T-10분 이내) 경주 배당 즉시 수집(수동 트리거). 실패 격리."""
    sched = _schedule_load() or _multi_schedule_fetch()
    ymd = sched.get("ymd") or time.strftime("%Y%m%d")
    now = time.time()
    collected, skipped = [], 0
    for tr in sched.get("tracks", []):
        for rc in tr.get("races", []):
            pe = rc.get("postEpoch")
            if pe and (pe - now) <= MULTI_COLLECT_LEAD_SEC and (pe - now) > -300:   # 발주 10분전~5분후
                k = _multi_collect_one(tr, rc, ymd)
                if k:
                    collected.append(k)
                else:
                    skipped += 1
    return jsonify({"ok": True, "collected": collected, "skipped": skipped})


@app.route("/api/multi/dashboard", methods=["GET"])
def multi_dashboard():
    """[3번] 다중 경주 대시보드 카드 — 배당 수집된 경주(분석 카드) + 아직 수집 전인 예정 경주(카운트다운) 병합.
      수집 전 경주도 스케줄에서 카운트다운 카드로 표시 → 발주 10분전 이전에도 오늘 전체 경주가 보임."""
    db = _multi_store_load()
    cards = []
    collected_keys = set()
    for key, rec in db.items():
        c = _multi_card(key, rec)
        if c:
            cards.append(c)
            collected_keys.add(key)
    # [통합·1·3번] 확장이 수집한 경주(triple_store)도 읽기 전용으로 포함 → 경륜·한국경마·일본경마 통합.
    #   ⚠ triple_store는 절대 쓰지 않고 읽기만(로그인 필요한 경륜 스케줄 서버fetch 대체). 30분+ 미갱신·마감 후는 제외.
    try:
        tdb = _triple_load()
        for key, rec in tdb.items():
            if key in collected_keys:
                continue                              # multi_race_store 우선(중복 제거)
            if (time.time() - (rec.get("t") or 0)) > STALE_ACTIVE_SEC:
                continue                              # 끝난 경주(30분+ 미갱신) 제외
            _sp = _multi_sport_of(rec)
            if _sp == "boat":                         # 경정은 우선 제외(사용자 요청)
                continue
            _va, _nu = _area_num(key)
            _rec2 = dict(rec)
            _rec2.setdefault("venue", _va)
            _rec2.setdefault("raceNo", _nu)
            c = _multi_card(key, _rec2)
            if c and (c.get("secondsLeft") is None or c["secondsLeft"] > -300):
                cards.append(c)
                collected_keys.add(key)
    except Exception as e:
        print("[다중경주] triple_store 병합 오류(무시):", e)
    # [예정 경주] today_schedule의 발주 전 경주(아직 미수집·마감 안 지남)를 카운트다운 카드로 추가
    now = time.time()
    sched = _schedule_load()
    for tr in sched.get("tracks", []):
        _tr_sport = tr.get("sport") or "horse"     # [종목 표시] 트랙 실제 종목(korea/cycle/horse) — 하드코딩 제거
        for rc in tr.get("races", []):
            pe = rc.get("postEpoch")
            key = _multi_key(tr.get("venue"), rc.get("raceNo")) if rc.get("raceNo") else None
            if not key or key in collected_keys:
                continue
            # [발주시각 없는 종목 표시·한국경마] KRA 는 발주시각 API가 없어 postEpoch=None →
            #   기존엔 `not pe`로 걸러져 한국경마가 아예 안 떴다. 발주시각이 있으면 카운트다운,
            #   없으면 목록 카드(secondsLeft=None)로 표시(일본경마 카운트다운 동작은 그대로 유지).
            left = int(pe - now) if pe else None
            if left is not None and left < -120:    # 발주시각 있는 경주만 마감 2분+ 제외(없으면 목록 유지)
                continue
            urg = "normal"
            if left is not None:
                urg = "urgent" if left <= MULTI_URGENT_SEC else ("warn" if left <= MULTI_WARN_SEC else "normal")
            cards.append({"raceKey": key, "venue": _track_norm(tr.get("venue")), "raceNo": rc.get("raceNo"),
                          "sport": _tr_sport, "postTime": rc.get("postTime"), "secondsLeft": left, "urgency": urg,
                          "keyHorses": [], "signals": [], "anomaly": False, "confidence": None,
                          "quinellaMain": None, "afterClose": False, "scheduled": True})
    cards.sort(key=lambda c: (c.get("secondsLeft") if c.get("secondsLeft") is not None else 9e9))
    # [岐阜·기후 중복 즉시 제거·렌더단계] 저장키가 岐阜(구)·기후(신) 두 벌로 남아 있어도 화면에선 한 장만.
    #   (경마장명 정규화 + 경주번호 + 종목)으로 중복 카드를 병합 — 수집분(secondsLeft 있는 카드) 우선 유지.
    #   ⚠ 기존 카드 데이터는 삭제 없이 '중복 표시'만 접는다(수집 우선·정보 많은 카드 유지).
    try:
        _seen_disp, _deduped = {}, []
        for c in cards:
            _dk = (_track_norm(c.get("venue")), c.get("raceNo"), c.get("sport") or "horse")
            if None in _dk[:2]:
                _deduped.append(c); continue          # 경주 식별 불가 카드는 그대로
            _prev = _seen_disp.get(_dk)
            if _prev is None:
                _seen_disp[_dk] = len(_deduped); _deduped.append(c); continue
            # 이미 같은 경주 카드가 있음 → 더 '충실한'(수집됨·미예정) 카드를 남긴다
            _old = _deduped[_prev]
            _c_rich = (not c.get("scheduled")) and (c.get("secondsLeft") is not None or c.get("keyHorses"))
            _o_rich = (not _old.get("scheduled")) and (_old.get("secondsLeft") is not None or _old.get("keyHorses"))
            if _c_rich and not _o_rich:
                _deduped[_prev] = c
        cards = _deduped
    except Exception as _de:
        print("[대시보드] 岐阜·기후 중복제거 스킵(무시):", _de)
    urgent = [c["raceKey"] for c in cards if c.get("urgency") == "urgent" and not c.get("afterClose")]
    # [5번] 종목별 카운트(토글 UI용)
    by_sport = {}
    for c in cards:
        by_sport[c.get("sport") or "horse"] = by_sport.get(c.get("sport") or "horse", 0) + 1
    return jsonify({"cards": cards, "urgent": urgent, "count": len(cards),
                    "collected": len(collected_keys), "bySport": by_sport})


@app.route("/api/multi/race/<path:key>", methods=["GET"])
def multi_race_detail(key):
    """[4번] 카드 클릭 → 해당 경주 전체 분석(기존 _triple_analyze 재사용). 결과입력은 기존 엔드포인트 사용."""
    db = _multi_store_load()
    rec = db.get(key)
    if not rec:
        rec = _triple_load().get(key)   # [통합] 확장 수집(경륜/한국/일본) 읽기 전용 폴백
    if not rec:
        return jsonify({"error": "해당 경주 배당이 아직 수집되지 않았습니다.", "waiting": True}), 200
    try:
        an = _triple_analyze(key, rec)
    except Exception as e:
        return jsonify({"error": "분석 실패: %s" % e}), 200
    # [카드 적중 표시 (2026-07-19)] 상세에도 결과·적중 대조 데이터 부가(있을 때만·추가 필드)
    try:
        _rs = _race_result_summary(key)
        if _rs:
            an["raceResult"] = _rs
    except Exception:
        pass
    return jsonify(an)


# ══════════════ [자동 예상] 경기 자동 전환·연속 예상(마감5분전 저장·결과 대조) ══════════════
AUTO_PRED_DIR = os.path.join(os.path.dirname(__file__), "data", "auto_prediction")
# ══════════════ [타임별 스냅샷 시스템·신규] data/timeline_snapshot/ + timeline_stats.json ══════════════
#   기존 실시간 분석(_triple_analyze)·auto_prediction·snapshot_compare 는 절대 건드리지 않는다(요청).
#   발주 잔여시간(left=postEpoch-now) 기준으로 T-10/T-7/T-5/T+1/T+3 스냅샷을 각 1회 저장.
#   T-7·T-5 도달 시 카카오 알림 트리거([5]). 결과 입력 시 각 스냅샷 적중·변경마 우승 판정.
TIMELINE_SNAP_DIR = os.path.join(os.path.dirname(__file__), "data", "timeline_snapshot")
TIMELINE_STATS_FILE = os.path.join(os.path.dirname(__file__), "data", "timeline_stats.json")
_timeline_saved = set()                   # (raceKey, phase) 1회 저장 가드

# ══════════════ [카카오톡 알림·신규] T-7/T-5 도달 시 텍스트+링크 전송([5]) ══════════════
#   ⚠ 실제 발송은 카카오 채널/알림톡(사업자 등록·토큰) 필요. 지금은 페이로드 구성 + 전송을 담당하되:
#     - 환경변수 KAKAO_NOTIFY_URL 이 있으면 그 웹훅으로 POST(솔라피·자체 릴레이 등 연동 지점)
#     - 없으면 data/kakao_queue.jsonl 에 적재(나중에 사업자 등록 후 일괄 발송·감사 로그)
#   이미지 전송(T-5 스냅샷 캡처)은 사업자 등록 후 추가 — payload 에 imageHint 만 남긴다.
KAKAO_QUEUE_FILE = os.path.join(os.path.dirname(__file__), "data", "kakao_queue.jsonl")
PUBLIC_BOARD_URL = os.environ.get("PUBLIC_BOARD_URL", "https://web-production-d4723.up.railway.app")


def _kakao_build_message(rk, phase, an, snap):
    """카카오 알림 텍스트 구성. T-7=1차 확정 / T-5=최종 확정('지금 사세요!'). 복승·복병·배당판 링크 포함."""
    main = (snap or {}).get("main") or []
    odds = (snap or {}).get("odds") or {}
    main_txt = "+".join(str(x) for x in main) if main else "-"
    main_odds = ""
    if main and len(main) == 2:
        o = odds.get("%d+%d" % (main[0], main[1]))
        if o:
            main_odds = " (%s배)" % o
    darks = (an.get("darkCombos") or {}).get("darks") or []
    dark_txt = ""
    if darks:
        rep = {}
        for c in (an.get("quinella") or []):
            cb = [int(x) for x in (c.get("combo") or [])]
            if len(cb) == 2 and (c.get("odds") or 0) > 0:
                for x in cb:
                    if rep.get(x) is None or c["odds"] < rep[x]:
                        rep[x] = c["odds"]
        d0 = darks[0]
        dark_txt = "\n🐎 복병: %d번" % d0 + (" (%s배)" % rep[d0] if rep.get(d0) else "")
    url = "%s/?race=%s" % (PUBLIC_BOARD_URL.rstrip("/"), urllib.parse.quote(rk))
    if phase == "T-7":
        head = "[적중왕] 🔒 %s 1차 확정" % rk
        tail = "복승: %s%s ★★★%s\n마감 7분 전" % (main_txt, main_odds, dark_txt)
    else:
        head = "[적중왕] 🔒 %s 최종 확정" % rk
        tail = "복승: %s%s ★★★%s\n지금 사세요!" % (main_txt, main_odds, dark_txt)
    text = "%s\n━━━━━━━━━━━━\n%s\n━━━━━━━━━━━━\n📊 배당판 보기 → %s" % (head, tail, url)
    return {"race": rk, "phase": phase, "text": text, "url": url,
            "imageHint": "T-5 스냅샷 캡처(사업자 등록 후 이미지 API 연동)",
            "at": time.strftime("%Y-%m-%d %H:%M:%S")}


def _kakao_notify_race(rk, phase, an, snap):
    """알림 발송(또는 큐 적재). KAKAO_NOTIFY_URL 있으면 웹훅 POST, 없으면 kakao_queue.jsonl 적재."""
    msg = _kakao_build_message(rk, phase, an, snap)
    url = os.environ.get("KAKAO_NOTIFY_URL", "").strip()
    if url:
        try:
            req = urllib.request.Request(url, data=json.dumps(msg).encode("utf-8"),
                                         headers={"Content-Type": "application/json"})
            urllib.request.urlopen(req, timeout=6)
            msg["sent"] = True
        except Exception as e:
            msg["sent"] = False
            msg["error"] = str(e)[:120]
    else:
        msg["sent"] = False
        msg["queued"] = True
    try:
        os.makedirs(os.path.dirname(KAKAO_QUEUE_FILE), exist_ok=True)
        with open(KAKAO_QUEUE_FILE, "a", encoding="utf-8") as f:
            f.write(json.dumps(msg, ensure_ascii=False) + "\n")
    except Exception as e:
        print("[카카오알림] 큐 적재 실패:", e)
    print("[카카오알림] %s %s → %s" % (rk, phase, "발송" if msg.get("sent") else "큐 적재"))
    return msg


def _timeline_snap_path(rk):
    return os.path.join(TIMELINE_SNAP_DIR, re.sub(r"[^\w가-힣]", "_", rk) + ".json")


def _timeline_extract(an):
    """스냅샷용 요약 추출 — main(복승 메인 조합)·dark_horse(복병 1·2순위)·odds(메인 조합 배당)."""
    cp = an.get("corePicks") or {}
    fq = cp.get("finalQuinellas") or []
    main = []
    odds = {}
    if fq:
        c = fq[0].get("combo") or []
        main = sorted(int(x) for x in c)
        if len(main) == 2:
            odds["%d+%d" % (main[0], main[1])] = fq[0].get("odds")
    dc = an.get("darkCombos") or {}
    dark = dc.get("darks") or [int(d["no"]) for d in (an.get("darkHorses") or [])[:2] if d.get("no") is not None]
    return {"main": main, "dark_horse": dark, "odds": odds}


def _timeline_snap_save(rk, phase, an):
    """지정 phase 스냅샷 저장(1회). T-5는 직전 T-7 대비 변경마 계산. 반환 저장된 snap dict 또는 None."""
    try:
        os.makedirs(TIMELINE_SNAP_DIR, exist_ok=True)
        p = _timeline_snap_path(rk)
        doc = {}
        if os.path.exists(p):
            try:
                doc = json.load(open(p, encoding="utf-8"))
            except Exception:
                doc = {}
        doc.setdefault("race", rk)
        doc.setdefault("date", time.strftime("%Y-%m-%d"))
        doc.setdefault("snapshots", {})
        snap = _timeline_extract(an)
        snap["confirmed"] = phase in ("T-7", "T-5")
        snap["at"] = time.strftime("%H:%M:%S")
        # T-5: T-7 대비 변경 계산
        if phase == "T-5":
            t7 = (doc["snapshots"].get("T-7") or {}).get("main") or []
            changed = sorted(set(snap["main"]) ^ set(t7)) if t7 else []
            snap["changed_from_T7"] = bool(changed)
            snap["changed_horses"] = changed
        # T+3: 마감 후 변경 감지(현재 main vs T-5)
        if phase == "T+3":
            t5 = (doc["snapshots"].get("T-5") or {}).get("main") or []
            snap["post_deadline_change"] = bool(t5 and set(snap["main"]) != set(t5))
        doc["snapshots"][phase] = snap
        doc["updated_at"] = time.strftime("%Y-%m-%d %H:%M:%S")
        json.dump(doc, open(p, "w", encoding="utf-8"), ensure_ascii=False, indent=1)
        return snap
    except Exception as e:
        print("[타임스냅샷] 저장 실패:", e)
        return None


# 잔여시간(초) → phase (윈도우 폭 ~60s, tick 30s라 각 1회 포착). None=해당없음.
_TIMELINE_PHASES = [("T-10", 570, 630), ("T-7", 390, 450), ("T-5", 270, 330),
                    ("T+1", -90, -30), ("T+3", -210, -150)]


def _timeline_phase_of(left):
    for name, lo, hi in _TIMELINE_PHASES:
        if lo < left <= hi:
            return name
    return None


def _timeline_snap_tick(races, now, db):
    """[bg 훅] 각 경주의 잔여시간으로 phase 판정 → 미저장 phase 스냅샷 저장. T-7·T-5는 카카오 알림 트리거."""
    for pe, venue, rno, rk in races:
        left = pe - now
        phase = _timeline_phase_of(left)
        if not phase or (rk, phase) in _timeline_saved:
            continue
        if rk not in (db or {}):
            continue
        try:
            an = _triple_analyze(rk, db.get(rk) or {})
            snap = _timeline_snap_save(rk, phase, an)
            _timeline_saved.add((rk, phase))
            if phase in ("T-7", "T-5") and snap:
                try:
                    _kakao_notify_race(rk, phase, an, snap)
                except Exception as _ke:
                    print("[타임스냅샷] 알림 트리거 오류(무시):", _ke)
        except Exception as e:
            print("[타임스냅샷] tick 오류 %s: %s" % (rk, e))


def _timeline_snap_apply_result(rk, top3):
    """[결과] 각 스냅샷 적중(T7_hit/T5_hit) + 변경마 우승 판정 → 파일 갱신 + 통계 재계산."""
    try:
        p = _timeline_snap_path(rk)
        if not os.path.exists(p):
            return None
        doc = json.load(open(p, encoding="utf-8"))
        t3 = set(int(x) for x in (top3 or []) if x is not None)
        doc["result"] = {"1st": (top3[0] if len(top3) > 0 else None),
                         "2nd": (top3[1] if len(top3) > 1 else None),
                         "3rd": (top3[2] if len(top3) > 2 else None)}
        snaps = doc.get("snapshots") or {}

        def _hit(main):
            m = set(int(x) for x in (main or []))
            return bool(m) and m.issubset(t3)     # 복승 메인 2두가 모두 1~3착이면 적중
        t7 = snaps.get("T-7") or {}
        t5 = snaps.get("T-5") or {}
        analysis = {"T7_hit": _hit(t7.get("main")), "T5_hit": _hit(t5.get("main"))}
        # 변경마 우승: T-5에서 바뀐 말(changed_horses)이 1~3착에 들었나
        chg = t5.get("changed_horses") or []
        if chg:
            analysis["changed_horse_won"] = any(int(x) in t3 for x in chg)
        doc["analysis"] = analysis
        doc["updated_at"] = time.strftime("%Y-%m-%d %H:%M:%S")
        json.dump(doc, open(p, "w", encoding="utf-8"), ensure_ascii=False, indent=1)
        _timeline_stats_recompute()
        return doc
    except Exception as e:
        print("[타임스냅샷] 결과 판정 실패:", e)
        return None


def _timeline_stats_recompute():
    """timeline_snapshot 스캔 → T-7/T-5 적중률·변경 시 적중률·변경마 우승률 → timeline_stats.json."""
    try:
        if not os.path.isdir(TIMELINE_SNAP_DIR):
            return {}
        t7 = [0, 0]; t5 = [0, 0]; changed = [0, 0]; chg_won = [0, 0]
        for fn in os.listdir(TIMELINE_SNAP_DIR):
            if not fn.endswith(".json"):
                continue
            try:
                doc = json.load(open(os.path.join(TIMELINE_SNAP_DIR, fn), encoding="utf-8"))
            except Exception:
                continue
            a = doc.get("analysis")
            if not a:
                continue
            snaps = doc.get("snapshots") or {}
            if (snaps.get("T-7") or {}).get("main"):
                t7[1] += 1; t7[0] += 1 if a.get("T7_hit") else 0
            if (snaps.get("T-5") or {}).get("main"):
                t5[1] += 1; t5[0] += 1 if a.get("T5_hit") else 0
            if (snaps.get("T-5") or {}).get("changed_from_T7"):
                changed[1] += 1; changed[0] += 1 if a.get("T5_hit") else 0
                chg_won[1] += 1; chg_won[0] += 1 if a.get("changed_horse_won") else 0

        def _r(v):
            return {"hit": v[0], "total": v[1], "rate": round(v[0] / v[1] * 100, 1) if v[1] else 0}
        stats = {"T7": _r(t7), "T5": _r(t5), "changedThenHit": _r(changed),
                 "changedHorseWon": _r(chg_won), "updated_at": time.strftime("%Y-%m-%d %H:%M:%S")}
        os.makedirs(os.path.dirname(TIMELINE_STATS_FILE), exist_ok=True)
        json.dump(stats, open(TIMELINE_STATS_FILE, "w", encoding="utf-8"), ensure_ascii=False, indent=1)
        return stats
    except Exception as e:
        print("[타임통계] 재계산 실패:", e)
        return {}


_AUTO_PRED_ENABLED = True                 # 기본 ON(POST /api/auto-prediction/toggle 로 제어)
_auto_pred_saved = set()                  # raceKey별 마감5분전 예상 저장 1회
_auto_pred_scored = set()                 # raceKey별 결과 대조 1회
_auto_pred_status = {"active": False, "current": None, "currentRk": None,
                     "next": None, "nextRk": None, "nextInMin": None,
                     "updatedAt": 0, "savedToday": 0, "day": None}


def _auto_pred_fname(rk):
    """raceKey → YYYY_MM_DD_경주장_경주번호.json (경로조작 방어)."""
    safe = re.sub(r"[^\w가-힣]+", "_", rk or "race").strip("_")
    return "%s_%s.json" % (time.strftime("%Y_%m_%d"), safe)


def _auto_pred_save(rk, an):
    """[마감5분전 최종 예상 저장] 분석(corePicks)에서 추천·유력마·단통 요약을 data/auto_prediction/ 에 저장."""
    try:
        os.makedirs(AUTO_PRED_DIR, exist_ok=True)
        cp = an.get("corePicks") or {}
        doc = {
            "raceKey": rk, "at": time.strftime("%Y-%m-%d %H:%M:%S"), "phase": "마감5분전",
            "quinellas": cp.get("finalQuinellas") or [], "trifectas": cp.get("finalTrifectas") or [],
            "special": cp.get("bmedSpecial") or [], "keyHorses": an.get("keyHorses") or [],
            "dansung": bool(cp.get("dansung")), "minOdds": cp.get("dansungMinOdds"),
            "raceHorseCount": cp.get("raceHorseCount"), "result": None, "compared": False,
        }
        fn = _auto_pred_fname(rk)
        json.dump(doc, open(os.path.join(AUTO_PRED_DIR, fn), "w", encoding="utf-8"), ensure_ascii=False, indent=1)
        print("[자동예상] %s 최종예상 저장(%s)" % (rk, fn))
        # [복병로그] 마감5분전 예측 시점에 복병 rank1~3 기록(결과 대조는 결과 입력 시)
        try:
            _dark_log_record(rk, an)
        except Exception as _de:
            print("[복병로그] 예측 훅 오류(무시):", _de)
        return fn
    except Exception as e:
        print("[자동예상] 저장 실패:", e)
        return None


def _auto_pred_compare(rk):
    """[결과 대조] 실제 착순(results_store, 확장/일괄 수집분)이 있으면 예상과 대조해 파일에 기록.
      ⚠ 서버 단독 oddspark 결과 수집은 로그인 세션 필요 → 기존 결과 입력경로(_apply_result_learning)가 learning 갱신을 담당."""
    try:
        res = _snapshot_result_for(rk)
        if not res or not (res.get("top3") or []):
            return False
        path = os.path.join(AUTO_PRED_DIR, _auto_pred_fname(rk))
        if not os.path.exists(path):
            return False
        doc = json.load(open(path, encoding="utf-8"))
        top3 = [int(x) for x in res["top3"] if x is not None]
        top2, t3 = set(top3[:2]), set(top3)
        _qh = any(len(q.get("combo") or []) == 2 and set(int(x) for x in q["combo"]) <= top2 for q in (doc.get("quinellas") or []))
        _th = any(len(t.get("combo") or []) == 3 and set(int(x) for x in t["combo"]) <= t3 for t in (doc.get("trifectas") or []))
        _sh = any(len(q.get("combo") or []) == 2 and set(int(x) for x in q["combo"]) <= top2 for q in (doc.get("special") or []))
        doc["result"] = {"top3": top3, "finalOdds": res.get("finalOdds")}
        doc["quinellaHit"], doc["trifectaHit"], doc["specialHit"] = _qh, _th, _sh
        doc["compared"] = True
        doc["comparedAt"] = time.strftime("%Y-%m-%d %H:%M:%S")
        json.dump(doc, open(path, "w", encoding="utf-8"), ensure_ascii=False, indent=1)
        print("[자동예상] %s 결과대조 → 복승%s·삼복승%s" % (rk, _qh, _th))
        return True
    except Exception as e:
        print("[자동예상] 대조 실패:", e)
        return False


def _auto_pred_tick(sched, now):
    """[자동 예상·연속 전환] bg 루프에서 매 틱 호출 — ①마감5분전 예상 저장 ②결과 대조(+15분) ③현재/다음 상태 갱신.
      기존 수집 루프(_multi_collect_one)가 이미 배당을 채우므로 여기선 저장·대조·상태만 담당(중복 수집 없음)."""
    if not _AUTO_PRED_ENABLED:
        _auto_pred_status["active"] = False
        return
    try:
        _day = time.strftime("%Y-%m-%d")
        if _auto_pred_status.get("day") != _day:           # 날짜 바뀌면 저장/대조 플래그 초기화
            _auto_pred_saved.clear(); _auto_pred_scored.clear()
            _auto_pred_status["day"] = _day
        races = []
        for tr in sched.get("tracks", []):
            for rc in tr.get("races", []):
                pe = rc.get("postEpoch")
                if pe:
                    races.append((pe, tr.get("venue"), rc.get("raceNo"), _multi_key(tr.get("venue"), rc.get("raceNo"))))
        races.sort(key=lambda x: x[0])
        # ① 마감 5분 전(0<left≤300)·미저장 → 최종 예상 저장(배당 수집돼 있을 때만)
        db = None
        for pe, venue, rno, rk in races:
            left = pe - now
            if 0 < left <= 300 and rk not in _auto_pred_saved:
                if db is None:
                    db = _triple_load()
                if rk in db:
                    try:
                        _auto_pred_save(rk, _triple_analyze(rk, db.get(rk) or {}))
                        _auto_pred_saved.add(rk)
                    except Exception as _se:
                        print("[자동예상] 분석/저장 실패 %s: %s" % (rk, _se))
        # ② 발주 +15분 지난 저장 경주 → 결과 대조(결과 있으면)
        for pe, venue, rno, rk in races:
            if (now - pe) >= 900 and rk in _auto_pred_saved and rk not in _auto_pred_scored:
                if _auto_pred_compare(rk):
                    _auto_pred_scored.add(rk)
        # [타임스냅샷] T-10/T-7/T-5/T+1/T+3 스냅샷 저장 + T-7·T-5 카카오 알림(기존 자동예상과 독립)
        try:
            if db is None:
                db = _triple_load()
            _timeline_snap_tick(races, now, db)
        except Exception as _te:
            print("[타임스냅샷] tick 훅 오류(무시):", _te)
        # ③ 현재(가장 임박)·다음 경주 상태
        upcoming = [r for r in races if r[0] >= now - 120]
        cur = upcoming[0] if upcoming else None
        nxt = upcoming[1] if len(upcoming) > 1 else None
        _auto_pred_status.update({
            "active": bool(upcoming),
            "current": ("%s %d경주" % (cur[1], cur[2])) if cur else None, "currentRk": cur[3] if cur else None,
            "next": ("%s %d경주" % (nxt[1], nxt[2])) if nxt else None, "nextRk": nxt[3] if nxt else None,
            "nextInMin": int((nxt[0] - now) / 60) if nxt else None,
            "updatedAt": now, "savedToday": len(_auto_pred_saved),
        })
    except Exception as e:
        print("[자동예상] tick 오류(무시):", e)


@app.route("/api/auto-prediction/status", methods=["GET"])
def auto_prediction_status():
    """[자동 예상 상태] 현재 예상 중 경주 + 다음 자동 분석 경주(분·오버레이 상단 표시용)."""
    return jsonify(dict(_auto_pred_status, enabled=_AUTO_PRED_ENABLED))


@app.route("/api/auto-prediction/toggle", methods=["POST"])
def auto_prediction_toggle():
    """[자동 예상 ON/OFF] body {enabled:true/false} 없으면 토글."""
    global _AUTO_PRED_ENABLED
    body = request.get_json(silent=True) or {}
    _AUTO_PRED_ENABLED = bool(body["enabled"]) if "enabled" in body else (not _AUTO_PRED_ENABLED)
    return jsonify({"ok": True, "enabled": _AUTO_PRED_ENABLED})


@app.route("/api/auto-prediction/list", methods=["GET"])
def auto_prediction_list():
    """[자동 예상 목록] 저장된 최종 예상 + 결과 대조. 최신순."""
    out = []
    try:
        files = os.listdir(AUTO_PRED_DIR)
    except FileNotFoundError:
        files = []
    for fn in files:
        if not fn.endswith(".json"):
            continue
        try:
            doc = json.load(open(os.path.join(AUTO_PRED_DIR, fn), encoding="utf-8"))
            doc["filename"] = fn
            out.append(doc)
        except Exception:
            pass
    out.sort(key=lambda x: x.get("at") or "", reverse=True)
    return jsonify({"predictions": out[:200], "count": len(out)})


@app.route("/api/auto-prediction/get/<path:filename>", methods=["GET"])
def auto_prediction_get(filename):
    """[자동 예상 1건] 파일명으로 조회(경로조작 방어)."""
    fn = os.path.basename(filename or "")
    path = os.path.join(AUTO_PRED_DIR, fn)
    if not fn.endswith(".json") or not os.path.exists(path):
        return jsonify({"ok": False, "error": "not found"}), 404
    try:
        return jsonify(json.load(open(path, encoding="utf-8")))
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)}), 500


def _multi_bg_loop():
    """[1·2번] 백그라운드: 스케줄 30분 갱신 + 발주 임박 경주 배당 주기 수집(실패 격리·서버 죽지 않음)."""
    last_sched = 0
    last_day = time.strftime("%Y%m%d")
    while True:
        try:
            now = time.time()
            # [날짜 자동 초기화] 자정 넘어 날짜 바뀌면 어제 데이터 정리 + 스케줄 즉시 재수집(새 날짜 경주로 재시작)
            _cur_day = time.strftime("%Y%m%d")
            if _cur_day != last_day:
                print(f"[날짜초기화] 날짜 변경 {last_day}→{_cur_day} → 어제 데이터 자동 정리")
                _startup_date_reset()
                last_day, last_sched = _cur_day, 0
            if now - last_sched >= 1800:       # 30분마다 스케줄 갱신
                # [수집 누락 긴급수정 2026-07-19·비블로킹] 스케줄 갱신은 개최장 많은 날 수십 초~수 분 걸려
                #   (경주별 発走時間 페이지 fetch) 같은 스레드의 배당 수집을 통째로 멈추게 하던 문제 →
                #   별도 스레드로 분리(수집은 계속·갱신은 뒤에서). 기존 갱신 로직 자체는 무변경.
                threading.Thread(target=_multi_schedule_fetch, daemon=True,
                                 name="multi-sched-refresh").start()
                last_sched = now
            sched = _schedule_load()
            ymd = sched.get("ymd") or time.strftime("%Y%m%d")
            # [수집 누락 긴급수정 2026-07-19·병렬+임박 우선] 기존엔 창(발주 10분전~2분후) 안 경주를 '순차'
            #   수집(경주당 fetch 2회·타임아웃 15초) → 경륜 67경주 등 동시 개최가 많으면 한 바퀴가 수 분으로
            #   늘어나 다음 경주가 늦게 뜨거나 통째로 누락되던 문제. → 발주 임박순 정렬 후 병렬(동시 6) 수집.
            #   _multi_collect_one 은 _multi_lock 으로 저장 직렬화돼 병렬 안전(기존 함수 무변경).
            _targets = []
            for tr in sched.get("tracks", []):
                for rc in tr.get("races", []):
                    pe = rc.get("postEpoch")
                    if pe and -120 <= (pe - now) <= MULTI_COLLECT_LEAD_SEC:   # 발주 10분전~2분후
                        _targets.append((pe, tr, rc))
            _targets.sort(key=lambda t: t[0])          # 발주 임박(남은 시간 적은) 경주 먼저
            if len(_targets) == 1:
                _multi_collect_one(_targets[0][1], _targets[0][2], ymd)
            elif _targets:
                try:
                    with ThreadPoolExecutor(max_workers=min(6, len(_targets))) as _mex:
                        _futs = [_mex.submit(_multi_collect_one, _tr2, _rc2, ymd)
                                 for (_pe2, _tr2, _rc2) in _targets]
                        for _f in _futs:
                            try:
                                _f.result(timeout=40)
                            except Exception:
                                pass                    # 개별 경주 실패·지연은 격리(다른 경주 무영향)
                except Exception as _pex:
                    print("[다중경주] 병렬 수집 오류 → 순차 폴백(무시):", _pex)
                    for (_pe2, _tr2, _rc2) in _targets:
                        _multi_collect_one(_tr2, _rc2, ymd)
            # [자동 예상] 수집 직후 마감5분전 예상 저장·결과 대조·현재/다음 상태 갱신(연속 자동 전환)
            _auto_pred_tick(sched, now)
        except Exception as e:
            print("[다중경주] 백그라운드 오류(무시·서버 유지):", e)
        time.sleep(30)


def _start_multi_race_bg():
    """[6번] 다중 경주 백그라운드 시작(실패해도 서버·단일 모드 무영향)."""
    try:
        threading.Thread(target=_multi_bg_loop, daemon=True).start()
        print("[다중경주] 백그라운드 시작(스케줄 30분·수집 30초·실패격리)")
    except Exception as e:
        print("[다중경주] 백그라운드 시작 실패(단일 모드 유지):", e)


def _startup_date_reset():
    """[서버 시작 시 날짜 자동 초기화] 어제(오늘 아닌 날짜) 데이터를 자동 정리 → '어제 경주 잔존' 방지.
      ⚠ 학습 데이터(odds_history·learning·pattern 등)는 절대 건드리지 않음 — 활성 캐시/고정만 정리(기존 기능 무영향)."""
    today = time.strftime("%Y-%m-%d")
    today_ymd = time.strftime("%Y%m%d")

    def _dstr(t):
        return time.strftime("%Y-%m-%d", time.localtime(t or 0))
    # 1) race_pin.json — 어제 고정 경주면 자동 해제(오늘 아닌 고정 초기화)
    try:
        d = json.load(open(RACE_PIN_FILE, encoding="utf-8"))
        pdate = d.get("date") or _dstr(d.get("pinnedAt"))
        if pdate != today:
            _race_pin_clear()
            print(f"[날짜초기화] 고정 경주({pdate}, 어제) → 자동 해제")
    except Exception:
        pass
    # 2) multi_race_store — 오늘 아닌 경주 제거(oddspark 다중 수집 날짜 초기화)
    try:
        mdb = _multi_store_load()
        keep = {k: v for k, v in mdb.items() if _dstr(v.get("t")) == today}
        if len(keep) != len(mdb):
            _multi_store_save(keep)
            print(f"[날짜초기화] 다중경주 저장소: 어제 경주 {len(mdb) - len(keep)}건 제거(새 날짜로 재시작)")
    except Exception:
        pass
    # 3) today_schedule — 어제 날짜면 비움(백그라운드가 오늘 스케줄로 재생성)
    try:
        sched = _schedule_load()
        if sched.get("ymd") and sched["ymd"] != today_ymd:
            _schedule_save({})
            print(f"[날짜초기화] 스케줄({sched['ymd']}, 어제) → 초기화(오늘 재수집 대기)")
    except Exception:
        pass
    # 4) triple_store(단일 경주 활성 캐시) — 어제 경주 제거(오늘 것만 유지). ⚠ odds_history 학습 파일은 보존.
    try:
        tdb = _triple_load()
        keep = {k: v for k, v in tdb.items() if _dstr(v.get("t")) == today}
        if len(keep) != len(tdb):
            _triple_save(keep)
            print(f"[날짜초기화] 단일 배당 활성캐시: 어제 경주 {len(tdb) - len(keep)}건 제거(히스토리 파일 보존)")
    except Exception:
        pass


_bg_boot_started = False


def _boot_background():
    """[24시간 자동수집·백업·학습] 백그라운드 작업 1회 기동(멱등). 로컬(__main__)·gunicorn(모듈로드) 공용.
      ⚠ gunicorn 은 `if __name__=='__main__'` 을 실행하지 않으므로, 이 함수를 모듈 로드 시점에도 호출해야
        Railway 배포에서 다중경주 자동수집·주기백업·학습일지·날짜정리가 정상 기동된다.
      ⚠ gunicorn 은 반드시 --workers 1 로 실행(워커마다 중복 수집·중복 git 백업 방지)."""
    global _bg_boot_started
    if _bg_boot_started:
        return
    _bg_boot_started = True
    try:
        _korea_maybe_resume()
    except Exception as e:
        print("[부팅] 한국 사전분석 재개 실패(무시):", e)
    _start_periodic_backup()             # 6시간 주기 안전 백업(결과 미입력이어도 백업)
    _start_daily_learning_scheduler()    # 매일 22:00 학습 일지 자동 생성·백업
    try:
        _startup_date_reset()            # 어제 고정·수집 데이터 자동 정리(학습 데이터 보존)
    except Exception as e:
        print("[부팅] 날짜 초기화 실패(무시):", e)
    _start_multi_race_bg()               # [핵심] 다중 경주(지방경마·경륜·한국) 24시간 자동수집
    _weather_auto_start()                # [날씨] 경주장별 실시간 날씨·주로 상태 자동수집(30분 캐시)
    _kra_backfill_start()                # [KRA 결과 백필] 20분 주기·당일 미입력 한국경주 결과 자동수집(watch 무관·복기/학습/복병 자동화)
    try:
        _archive_compress_old(7)         # 7일+ 경주 배당 .gz 압축 보관(데이터 삭제 없음)
    except Exception as e:
        print("[부팅] 아카이브 압축 실패(무시):", e)
    print("[부팅] 백그라운드 작업 기동 완료(자동수집·백업·학습·날짜정리)")


# [Railway/gunicorn] gunicorn 은 __main__ 을 건너뛰므로, 여기서 모듈 로드 시점에 백그라운드 기동.
#   (SERVER_SOFTWARE 는 gunicorn 이 자동 설정. 로컬 `python app.py` 에선 미설정 → 아래 __main__ 에서 기동)
if os.environ.get("SERVER_SOFTWARE", "").startswith("gunicorn"):
    _boot_background()


if __name__ == "__main__":
    # [Railway/배포] PORT 환경변수 우선(미설정 시 로컬 8011). PORT 있으면 외부바인드(0.0.0.0)·FLASK_ENV=production 이면 debug OFF.
    _port = int(os.environ.get("PORT", 8011))
    _host = "0.0.0.0" if os.environ.get("PORT") else "127.0.0.1"
    _debug = os.environ.get("FLASK_ENV") != "production"
    print(f"서버 시작: http://{_host}:{_port} (debug={_debug}, 로컬은 자동 리로드 ON)")
    # debug=True: 코드 저장 시 자동 재기동(stale 서버로 인한 405 재발 방지). 로컬 전용(127.0.0.1).
    # threaded=True: 브라우저의 다중 keep-alive 연결을 동시 처리(단일 스레드 멈춤 방지).
    # 재개는 리로더의 실제 작업 프로세스(WERKZEUG_RUN_MAIN)에서만 1회 수행.
    if os.environ.get("WERKZEUG_RUN_MAIN") == "true":
        _race_pin_expire_stale()   # [날짜 초기화] 서버 시작 시 어제 고정 경주 자동 해제 → 오늘로 초기화
        _boot_background()
    app.run(host=_host, port=_port, debug=_debug, threaded=True)
